/* AUTO-GENERATED — Maryland Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["MD"] = {"code":"MD","name":"Maryland","agency":"Maryland MVA","agencyShort":"MVA","handbook":"https://mva.maryland.gov/licenses-ids/commercial-drivers-license-cdl","links":{},"en":[{"q":"On Maryland highways, what is the maximum legal width of a vehicle (excluding mirrors and other safety/energy devices) before an oversize permit is required?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"Maryland Transportation Article § 24-102 sets the maximum vehicle width at 102 inches (8 feet 6 inches); width is measured exclusive of mirrors, marker/turn lamps, and energy-conservation devices. Anything wider needs an SHA oversize permit. Source: Md. Transp. § 24-102; MD SHA Oversize/Overweight Hauling Permit Manual.","handbook":"","hbref":""},{"q":"What is the maximum legal height of a vehicle and its load on Maryland highways without a permit?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"answer":2,"explanation":"Under Maryland Transportation Article § 24-104, the height of a vehicle and its load may not exceed 13 feet 6 inches. The SHA permit manual lists 13'6\" as the legal limit with no special conditions. Source: Md. Transp. § 24-104; MD SHA Hauling Permit Manual (Height section).","handbook":"","hbref":""},{"q":"What is the maximum gross vehicle weight allowed on Maryland's Interstate highways without an overweight permit?","options":["73,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"answer":1,"explanation":"Maryland follows the federal Interstate standard: maximum gross weight is 80,000 pounds (including the load). Source: Md. Transp. § 24-109; 23 CFR 658.17 as applied on Maryland Interstates.","handbook":"","hbref":""},{"q":"On Maryland Interstates, what is the maximum weight allowed on a single axle?","options":["17,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"The single-axle limit on Maryland's Interstate system is 20,000 pounds, matching the federal standard in Maryland Transportation Article § 24-109. Source: Md. Transp. § 24-109; 23 CFR 658.17.","handbook":"","hbref":""},{"q":"On Maryland Interstates, what is the maximum weight allowed on a tandem axle?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"answer":2,"explanation":"The tandem-axle (two-axle group spaced more than 40 but not more than 96 inches apart) limit is 34,000 pounds under Maryland Transportation Article § 24-109, consistent with the federal Interstate standard. Source: Md. Transp. § 24-109; 23 CFR 658.17.","handbook":"","hbref":""},{"q":"Which Maryland agency office issues oversize/overweight hauling permits for travel on state-maintained roads?","options":["The Motor Vehicle Administration (MVA) Driver Licensing Unit","The SHA Office of Traffic and Safety, Motor Carrier Division, Hauling Permits Unit","The Maryland State Police Commercial Vehicle Enforcement Division","The Maryland Transportation Authority Toll Facilities Office"],"answer":1,"explanation":"Oversize/overweight (OS/OW) hauling permits are issued by the Maryland State Highway Administration, Office of Traffic and Safety, Motor Carrier Division – Hauling Permits Unit (Hanover, MD). Source: MD SHA Oversize/Overweight Hauling Permit Manual (Introduction).","handbook":"","hbref":""},{"q":"A load can be reduced no further but still exceeds Maryland's legal limits. Which statute sections establish the legal size and weight limits that trigger the need for a special hauling permit?","options":["Transportation Article, Title 16, Sections 101 and 102","Transportation Article, Title 24, Sections 108 and 109","Transportation Article, Title 21, Sections 1101 and 1102","Transportation Article, Title 11, Sections 301 and 302"],"answer":1,"explanation":"The SHA permit manual states that when a load exceeds the legal limits set in the Maryland Motor Vehicle Law, Title 24, Sections 108 (axle loads) and 109 (gross weight), a Special Hauling Permit must be purchased. Source: MD SHA Hauling Permit Manual; Md. Transp. §§ 24-108, 24-109.","handbook":"","hbref":""},{"q":"On Maryland's National Network and designated trucking routes, what is the maximum length of a semitrailer that does not require a permit?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"On the National Network and designated trucking routes, semitrailers up to 53 feet are allowed without a permit (48 feet applies on many other state highways). Source: Md. Transp. § 24-104.1/24-104.2; J.J. Keller Maryland size/weight summary.","handbook":"","hbref":""},{"q":"Maryland does not enforce a fixed overall length limit on a tractor-semitrailer combination on the National Network, but the weight on any group of axles is still capped by which calculation?","options":["The Federal Bridge Formula (Bridge Gross Weight Table)","The manufacturer's gross axle weight rating only","A flat 1,000 pounds per inch of tire width","The registered tare weight times two"],"answer":0,"explanation":"Maryland applies the Federal Bridge Formula on its Interstate/National Network: the maximum weight on any group of consecutive axles is governed by the bridge formula, up to the 80,000-pound overall cap. Source: Md. Transp. § 24-109; 23 CFR 658.17 Federal Bridge Formula.","handbook":"","hbref":""},{"q":"A combination vehicle exceeds Maryland's legal weight. Up to what gross weight may a routine SHA overweight hauling permit authorize travel, and on what roads?","options":["Up to 100,000 pounds on any state highway","Up to 120,000 pounds on any state road","Up to 150,000 pounds on Interstate routes only","Up to 200,000 pounds on the Capital Beltway only"],"answer":2,"explanation":"The SHA manual provides that combination-vehicle permit loads up to but not exceeding 150,000 pounds are allowed on Interstate routes only (without going to the Office of Bridge Development), provided axle weight/spacing rules are met. Source: MD SHA Hauling Permit Manual (Weight, 'Over 60 Tons').","handbook":"","hbref":""},{"q":"Under the Maryland SHA permit fee schedule, what is the base fee for a hauling permit when the combined load weighs 90,000 pounds (45 tons) or less?","options":["$10.00","$30.00","$50.00","$100.00"],"answer":1,"explanation":"The SHA manual sets a $30.00 base fee for a hauling permit when an over-dimensional/combined load weighs less than 90,000 pounds; loads over 45 tons (90,000 lb) add $5.00 per additional ton. Source: MD SHA Hauling Permit Manual (General Information; Permit Fees).","handbook":"","hbref":""},{"q":"For a permitted load that exceeds 45 tons (90,000 pounds), how much does the Maryland SHA add to the permit fee for each additional ton?","options":["$2.00 per ton","$5.00 per ton","$10.00 per ton","$25.00 per ton"],"answer":1,"explanation":"The manual states that for loads in excess of 45 tons (90,000 lb), an additional $5.00 is charged for each additional ton (e.g., 50 tons = $55.00). Source: MD SHA Hauling Permit Manual (General Information; Permit Fees schedule).","handbook":"","hbref":""},{"q":"Under Maryland's general hours-of-movement rules, when may a permitted oversize/overweight load NOT be moved?","options":["Only between midnight and 6:00 a.m. on weekdays","Any Saturday after 12:00 noon and all day Sunday","Only on the first Monday of each month","Only during posted rush hours in Baltimore"],"answer":1,"explanation":"Per the SHA manual and COMAR Title 11, no permit load may be moved on any Saturday after 12:00 noon, on any Sunday, or during listed holiday periods. Daylight movement (1/2 hour after sunrise to 1/2 hour before sunset) is otherwise the rule. Source: MD SHA Hauling Permit Manual (Hours of Movement); COMAR 11.04.","handbook":"","hbref":""},{"q":"At what width does a permitted load (other than a mobile/modular home) first require a single private escort vehicle in Maryland?","options":["Over 10 feet wide","Over 12 feet wide","Over 13 feet wide","Over 14 feet wide"],"answer":2,"explanation":"The SHA manual requires one private escort for loads over 13 feet wide (loads in the 13'1\"–13'11\" range need 1 private escort), with two private escorts required at 14 feet wide or more. Source: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions).","handbook":"","hbref":""},{"q":"In Maryland, a permitted load 14 feet wide or wider requires how many private escort vehicles?","options":["No escort is required","One private escort","Two private escorts","Four private escorts"],"answer":2,"explanation":"The SHA manual specifies that all loads 14 feet wide or more require two private escorts to move in and through Maryland. Source: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions).","handbook":"","hbref":""},{"q":"Which dimension or weight makes a Maryland permitted load a 'Super Load' on Interstate highways?","options":["Over 90,000 pounds gross or 11 feet wide","Exceeding 150,000 pounds (75 tons) or 27,000 pounds on any axle","Exceeding 80,000 pounds or 12 feet high","Any load requiring a single private escort"],"answer":1,"explanation":"The SHA manual defines Super Loads as, among others, those exceeding 150,000 lb (75 tons) or exceeding 27,000 lb on any axle on Interstate highways (or exceeding 120,000 lb / 60 tons or 27,000 lb per axle on Maryland state highways), or 120 ft long, 16 ft wide, or 16 ft high. Source: MD SHA Hauling Permit Manual (Escorts – General Conditions, Super Loads).","handbook":"","hbref":""},{"q":"On Maryland STATE (non-Interstate) highways, exceeding which gross weight classifies a permitted load as an excessive 'Super Load'?","options":["80,000 pounds (40 tons)","100,000 pounds (50 tons)","120,000 pounds (60 tons)","150,000 pounds (75 tons)"],"answer":2,"explanation":"The SHA manual classifies a load as a Super Load on Maryland state highways when it exceeds 120,000 pounds (60 tons) or exceeds 27,000 pounds on any axle. The 150,000-pound (75-ton) threshold applies to Interstate highways. Source: MD SHA Hauling Permit Manual (Super Loads).","handbook":"","hbref":""},{"q":"Except on Interstate highways, what axle-load tolerance does Maryland law allow a farm vehicle hauling farm products from a field during the listed harvest periods?","options":["A 5% axle-load tolerance","A 10% axle-load tolerance","A 15% axle-load tolerance","No tolerance is allowed at any time"],"answer":2,"explanation":"Maryland Transportation Article § 24-109 allows farm vehicles (off Interstates) a 5% axle tolerance normally, increased to a 15% axle-load tolerance during defined harvest periods (e.g., wheat June 1–Aug 15, corn July 1–Dec 1), with a 5% gross-weight tolerance within 100 miles of the field. Source: Md. Transp. § 24-109 (harvest-time agricultural variance).","handbook":"","hbref":""},{"q":"Except on Interstate highways, a combination hauling forest products from a forest (semitrailer 45 feet or less) is allowed what axle-load tolerance from June 1 through September 30?","options":["5% axle-load tolerance","10% axle-load tolerance","15% axle-load tolerance","20% axle-load tolerance"],"answer":2,"explanation":"Maryland Transportation Article § 24-109 allows a forest-products combination (semitrailer 45 ft or less, loaded off-highway, not on Interstates) a 5% axle tolerance, increased to 15% from June 1 through September 30. Source: Md. Transp. § 24-109 (forest-products variance).","handbook":"","hbref":""},{"q":"Maryland (following federal law) allows a heavy vehicle a small extra weight allowance to offset the weight of which fuel-saving device, without violating the gross/axle/bridge-formula limits?","options":["An automatic tire-inflation system, up to 1,000 extra pounds","An auxiliary power unit / idle-reduction technology, up to 550 extra pounds","A refrigeration unit, up to 2,000 extra pounds","A wide-base single tire, up to 250 extra pounds"],"answer":1,"explanation":"Maryland Transportation Article § 24-109 permits up to an additional 550 pounds total in gross, axle, tandem, or bridge-formula weight to account for an auxiliary power unit or idle-reduction technology unit, consistent with federal law. Source: Md. Transp. § 24-109 (idle-reduction allowance); 23 CFR 658.17.","handbook":"","hbref":""},{"q":"In Maryland, which CDL class is required to operate a combination vehicle with a Gross Combination Weight Rating (GCWR) of 26,001 pounds or more, where the towed unit has a GVWR over 10,000 pounds?","options":["Class A","Class B","Class C","Class D"],"answer":0,"explanation":"Maryland defines a Class A CDL as a combination vehicle with a tractor/power unit and trailer(s) having a GCWR of 26,001+ pounds, with the towed unit GVWR over 10,000 pounds. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151.","handbook":"","hbref":""},{"q":"Under Maryland MVA rules, which CDL class authorizes driving any single vehicle with a GVWR of 26,001 pounds or more (towing a unit not over 10,000 pounds)?","options":["Class A","Class B","Class C","Class M"],"answer":1,"explanation":"A Maryland Class B CDL covers single vehicles with a GVWR of 26,001+ pounds, or such a vehicle towing a unit not exceeding 10,000 pounds GVWR. Examples include straight box trucks and most buses. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions.","handbook":"","hbref":""},{"q":"A Maryland vehicle is rated under 26,001 pounds but is designed to carry 16 or more passengers (including the driver), or carries placarded hazardous materials. Which CDL class applies?","options":["Class A","Class B","Class C","Class E"],"answer":2,"explanation":"Maryland's Class C CDL covers smaller commercial vehicles that do not meet Class A or B weight criteria but are designed to transport 16+ passengers (including the driver) or carry hazardous materials requiring placards. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151.","handbook":"","hbref":""},{"q":"In Maryland, which endorsement code is required to operate a vehicle designed to carry 16 or more passengers, such as a bus?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"answer":1,"explanation":"Maryland requires the P (Passenger) endorsement to operate vehicles that carry 16 or more passengers. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions.","handbook":"","hbref":""},{"q":"To drive a school bus in Maryland, which endorsement combination does the MVA require?","options":["S endorsement only","P endorsement only","Both P (Passenger) and S (School Bus) endorsements","Both S (School Bus) and H (HazMat) endorsements"],"answer":2,"explanation":"Maryland requires both the P (Passenger) and S (School Bus) endorsements to operate a school bus. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions.","handbook":"","hbref":""},{"q":"Which Maryland CDL endorsement is required to operate a vehicle carrying liquids or gases in a tank, such as a fuel or water tanker?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement P"],"answer":1,"explanation":"Maryland uses the N (Tank Vehicle) endorsement for vehicles carrying liquids or gases in tanks, like fuel or water tankers. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions.","handbook":"","hbref":""},{"q":"In Maryland, what does the 'X' endorsement on a CDL combine?","options":["Passenger (P) and School Bus (S)","Tank Vehicle (N) and HazMat (H)","Doubles/Triples (T) and Tank (N)","HazMat (H) and Passenger (P)"],"answer":1,"explanation":"Maryland's X endorsement is a combination of the N (Tank Vehicle) and H (HazMat) endorsements, authorizing transport of hazardous materials in tank vehicles. Source: Maryland MVA, CDL Classifications, Endorsements & Restrictions.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a Maryland CDL restricted to intrastate (Maryland-only) commercial driving?","options":["16 years old","18 years old","21 years old","25 years old"],"answer":1,"explanation":"Maryland allows a CDL at 18 for intrastate (within-Maryland) driving, while interstate driving requires age 21. Source: Maryland MVA, Get or Renew a CDL; Manual DL-151.","handbook":"","hbref":""},{"q":"Per Maryland MVA, what is the minimum age required to drive a commercial vehicle in interstate commerce (across state lines)?","options":["18 years old","19 years old","21 years old","23 years old"],"answer":2,"explanation":"Maryland requires drivers to be at least 21 to operate a CDL vehicle interstate (across state lines), to carry hazardous materials requiring placards, or to transport passengers interstate. Source: Maryland MVA, Get or Renew a CDL.","handbook":"","hbref":""},{"q":"A 19-year-old Maryland CDL holder is legally restricted from doing which of the following?","options":["Driving a straight truck within Maryland","Driving a commercial vehicle across state lines","Holding a Passenger (P) endorsement for intrastate use","Driving a Class B vehicle within Maryland"],"answer":1,"explanation":"A Maryland driver between 18 and 21 cannot drive a commercial vehicle outside Maryland (interstate), cannot drive a vehicle requiring hazmat placards, and cannot operate double/triple trailer rigs. Source: Maryland MVA / Manual DL-151.","handbook":"","hbref":""},{"q":"Under the federal rule applied in Maryland, how long must an applicant hold a Commercial Learner's Permit (CLP) before being allowed to take the CDL skills (road) test?","options":["At least 7 days","At least 10 days","At least 14 days","At least 30 days"],"answer":2,"explanation":"Maryland applies the federal rule requiring a CLP to be held for at least 14 days before the CDL skills (road) test may be taken. Source: Maryland MVA, Get or Renew a CDL; 49 CFR 383.25.","handbook":"","hbref":""},{"q":"Before being issued a Maryland Commercial Learner's Permit (CLP), an applicant must already hold which credential?","options":["A valid Maryland (non-motorcycle) driver's license","A Maryland motorcycle license","A federal TWIC card","An out-of-state CDL"],"answer":0,"explanation":"Maryland requires CLP applicants to already hold a valid Maryland driver's license (not a motorcycle-only license) and to pass the vision and knowledge tests. Source: Maryland MVA / Manual DL-151.","handbook":"","hbref":""},{"q":"Which set of documents does the Maryland MVA require an applicant to present when applying for a CDL?","options":["Only a current driver's license and a photo","Proof of identity, age, Social Security number, and Maryland residency","Only a passport and an employer letter","Proof of identity and a vehicle registration card"],"answer":1,"explanation":"The Maryland MVA requires proof of identity, age, Social Security number, and Maryland residency (lawful presence is established through these identity documents). Source: Maryland MVA, Get or Renew a CDL.","handbook":"","hbref":""},{"q":"Where must Entry-Level Driver Training (ELDT) be completed for a first-time Maryland Class A or B CDL applicant?","options":["Any private driving school of the applicant's choice","A provider listed in the FMCSA Training Provider Registry","Only at a Maryland MVA branch office","A program accredited by the Maryland State Department of Education"],"answer":1,"explanation":"Maryland requires ELDT for first-time Class A/B applicants (and for first-time S, P, and H endorsements) to be completed through a provider listed in the FMCSA Training Provider Registry before the skills test or hazmat knowledge test. Source: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"For which of the following does Maryland require Entry-Level Driver Training (ELDT) before testing?","options":["Renewing an existing Class A CDL","Adding an automatic-transmission restriction","Obtaining a Class A or B CDL for the first time, or adding S, P, or H for the first time","Updating a residential address on the CDL"],"answer":2,"explanation":"Maryland mandates ELDT for first-time Class A or B CDLs and for the first time adding the School Bus (S), Passenger (P), or HazMat (H) endorsements. It is not required for renewals or administrative changes. Source: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380.","handbook":"","hbref":""},{"q":"Which is one of the four medical self-certification categories a Maryland CDL holder must choose from?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Provisional Interstate (PI)","Limited Hazmat (LH)"],"answer":0,"explanation":"Maryland's four self-certification categories are Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A Maryland CDL holder who drives across state lines and must comply with all federal driver-qualification requirements should self-certify as which category?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)"],"answer":2,"explanation":"Non-Excepted Interstate (NI) applies to a CDL holder who drives across state lines and meets all federal qualification requirements, including a valid DOT medical certificate. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"In Maryland, before the HazMat (H) endorsement knowledge test can be taken and the endorsement issued, the applicant must clear what?","options":["A TSA security threat assessment with a fingerprint-based background check","A state vehicle emissions inspection","A drug and alcohol clearinghouse pre-employment query only","A Maryland State Police driving-record audit only"],"answer":0,"explanation":"Maryland requires HazMat applicants to clear a TSA security threat assessment, which includes a fingerprint-based Background Record Check (processed via DPSCS), in addition to passing the hazmat knowledge test. Source: Maryland MVA, CDL HazMat Endorsement; 49 CFR Part 1572.","handbook":"","hbref":""},{"q":"After receiving TSA approval, within what time frame must a Maryland applicant obtain the HazMat endorsement?","options":["Within 30 days","Within 90 days","Within six months","Within two years"],"answer":2,"explanation":"Maryland requires the applicant to obtain the HazMat endorsement within six months of the date on the TSA approval letter. Source: Maryland MVA, CDL HazMat Endorsement.","handbook":"","hbref":""},{"q":"How often must a Maryland CDL holder with a School Bus (S) endorsement typically renew their medical examiner's certificate to keep that endorsement valid?","options":["Every 6 months","Annually (every year)","Every 2 years","Every 5 years"],"answer":1,"explanation":"While most medical examiner's certificates are valid up to two years, Maryland School Bus (S) endorsement holders generally need an annual medical certification to maintain that designation. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"In Maryland, what is the maximum blood/breath alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04","0.08","0.02","0.10"],"answer":0,"explanation":"A CMV driver in Maryland is disqualified for driving with a BAC of 0.04 or greater — half the 0.08 limit for non-commercial drivers. Source: Maryland Transportation Article §16-812(a) and §11-127.1; Maryland CDL Manual; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under Maryland's implied-consent law, what happens if a CDL holder is lawfully asked to take a chemical test for alcohol and refuses?","options":["The CDL is disqualified for at least 1 year (a first refusal is treated like a major offense)","The driver is fined but keeps the CDL","The CDL is suspended for 60 days","Nothing happens until a conviction"],"answer":0,"explanation":"Maryland applies implied consent: refusing a lawfully requested chemical test disqualifies the CDL for 1 year for a first offense, the same as other major offenses. Source: Maryland Transportation Article §16-205.1 and §16-812(b); 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the CDL disqualification period in Maryland for a first major offense (such as DUI, a 0.04+ BAC in a CMV, or test refusal) when NOT transporting placarded hazardous materials?","options":["1 year","60 days","3 years","6 months"],"answer":0,"explanation":"A first major offense disqualifies the CDL for 1 year (3 years if it occurred while transporting placarded HazMat). Source: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"If a Maryland CDL driver commits a first major offense (e.g., DUI or 0.04+ BAC) while transporting hazardous materials that require placarding, how long is the disqualification?","options":["3 years","1 year","5 years","Lifetime"],"answer":0,"explanation":"The standard 1-year first-offense disqualification is increased to 3 years when the driver was transporting placarded hazardous materials at the time. Source: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"What is the CDL disqualification in Maryland for a SECOND major offense (a second DUI, 0.04+ BAC, refusal, etc.) committed in a separate incident?","options":["Lifetime disqualification","5 years","3 years","2 years"],"answer":0,"explanation":"A second major offense results in lifetime CDL disqualification, though reinstatement may be possible after 10 years in qualifying cases. Source: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Using a CMV to commit a felony involving the manufacturing, distributing, or dispensing of a controlled substance results in what Maryland CDL penalty?","options":["Lifetime disqualification with no 10-year reinstatement","1-year disqualification","3-year disqualification","Lifetime disqualification, but eligible for reinstatement after 10 years"],"answer":0,"explanation":"A felony involving manufacturing, distributing, or dispensing a controlled substance using a CMV is a lifetime disqualification that is NOT eligible for the 10-year reinstatement. Source: 49 CFR 383.51 Table 1; Maryland Transportation Article §16-812.","handbook":"","hbref":""},{"q":"How many serious traffic violations within a 3-year period trigger a 60-day CDL disqualification in Maryland?","options":["2 serious violations","3 serious violations","4 serious violations","1 serious violation"],"answer":0,"explanation":"Two serious traffic violations within 3 years (in any combination, in a CMV) result in a 60-day disqualification. Source: Maryland CDL Manual; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Three serious traffic violations within a 3-year period result in what CDL disqualification period in Maryland?","options":["120 days","60 days","180 days","1 year"],"answer":0,"explanation":"Three serious traffic violations within 3 years disqualify the CDL for 120 days; this is in addition to any prior 60-day disqualification. Source: Maryland CDL Manual; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"How many miles per hour over the posted limit must a speeding offense be to count as a 'serious traffic violation' for CDL purposes in Maryland?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"answer":0,"explanation":"Speeding 15 mph or more above the posted speed limit is a serious traffic violation that counts toward the 2-in-3-years (60 day) and 3-in-3-years (120 day) disqualifications. Source: Maryland CDL Manual; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Which of the following is classified as a 'serious traffic violation' for a Maryland CDL holder?","options":["Reckless driving","Parking in a fire lane","A burned-out taillight","An expired registration sticker"],"answer":0,"explanation":"Serious traffic violations include reckless driving, speeding 15+ mph over, improper/erratic lane changes, following too closely, texting, and handheld phone use. Routine equipment/parking issues are not serious violations. Source: Maryland CDL Manual; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"In Maryland, driving a CMV while texting in violation of the law is treated as which type of offense for CDL disqualification?","options":["A serious traffic violation","A major offense","An out-of-service violation","A railroad-crossing violation"],"answer":0,"explanation":"Texting while driving a CMV is a serious traffic violation that counts toward the 60-day (2-in-3-years) and 120-day (3-in-3-years) disqualifications. Maryland bans texting under a primary-enforcement law. Source: Maryland Transportation Article §21-1124.1; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"Under Maryland law, an adult driver of a CMV using a hand-held mobile phone while the vehicle is in motion commits what kind of CDL offense?","options":["A serious traffic violation","A minor non-reportable offense","A major offense with a 1-year disqualification","An out-of-service order violation"],"answer":0,"explanation":"Using a hand-held phone while driving a CMV is a serious traffic violation counting toward the 60/120-day disqualification thresholds. Maryland's hand-held ban is a primary offense. Source: Maryland Transportation Article §21-1124.2; 49 CFR 383.51 Table 2.","handbook":"","hbref":""},{"q":"What is the minimum CDL disqualification in Maryland for a FIRST railroad-highway grade crossing violation?","options":["Not less than 60 days","Not less than 30 days","Not less than 120 days","Not less than 1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation disqualifies the CDL for not less than 60 days. Source: Maryland CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A SECOND railroad-highway grade crossing violation within a 3-year period results in what minimum CDL disqualification in Maryland?","options":["Not less than 120 days","Not less than 60 days","Not less than 1 year","Not less than 180 days"],"answer":0,"explanation":"A second railroad-crossing violation within 3 years disqualifies the CDL for not less than 120 days. Source: Maryland CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"A THIRD railroad-highway grade crossing violation within a 3-year period results in what minimum CDL disqualification in Maryland?","options":["Not less than 1 year","Not less than 120 days","Not less than 180 days","Lifetime"],"answer":0,"explanation":"A third (or subsequent) railroad-crossing violation within 3 years disqualifies the CDL for not less than 1 year. Source: Maryland CDL Manual; 49 CFR 383.51 Table 3.","handbook":"","hbref":""},{"q":"What is the CDL disqualification range in Maryland for a FIRST conviction of violating an out-of-service order while driving a NON-HazMat CMV?","options":["180 days up to 1 year","60 to 120 days","1 to 3 years","30 to 90 days"],"answer":0,"explanation":"A first out-of-service order violation (non-HazMat, fewer than 16 passengers) disqualifies the CDL for not less than 180 days and not more than 1 year. Source: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A SECOND out-of-service order violation within any 10-year period (non-HazMat) results in what CDL disqualification range in Maryland?","options":["2 to 5 years","180 days to 1 year","1 to 3 years","Lifetime"],"answer":0,"explanation":"A second out-of-service order violation within 10 years disqualifies the CDL for not less than 2 years and not more than 5 years. Source: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"A FIRST out-of-service order violation while transporting placarded hazardous materials or while operating a vehicle designed for 16 or more passengers carries what CDL disqualification range in Maryland?","options":["180 days up to 2 years","180 days up to 1 year","2 to 5 years","3 to 5 years"],"answer":0,"explanation":"A first out-of-service order violation involving placarded HazMat or a 16+ passenger vehicle disqualifies the CDL for not less than 180 days and not more than 2 years. Source: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4.","handbook":"","hbref":""},{"q":"When may the Maryland MVA begin a CDL disqualification related to a high-BAC commercial stop?","options":["Upon a citation/administrative per se action for a high BAC in a CMV, even before conviction","Only after a criminal conviction in court","Only after a second offense","Only if the driver causes a crash"],"answer":0,"explanation":"Maryland may disqualify a CDL based on a citation or administrative per se order for a high BAC while driving a commercial vehicle, even before any court conviction. Source: MDOT MVA CDL Disqualification & Reinstatement page; Maryland Transportation Article §16-205.1, §16-812.","handbook":"","hbref":""},{"q":"After a lifetime CDL disqualification, a Maryland driver may generally apply for reinstatement after how many years, provided eligibility requirements are met?","options":["10 years","5 years","3 years","Never — lifetime is permanent in all cases"],"answer":0,"explanation":"A lifetime CDL disqualification may be reduced to a minimum of 10 years if the driver meets reinstatement requirements — except for offenses like drug-trafficking or human-trafficking by CMV, which allow no reinstatement. Source: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1.","handbook":"","hbref":""},{"q":"Under Maryland's Move Over law, when a CDL driver approaches a stopped emergency vehicle, tow truck, or service vehicle displaying warning lights, what is the FIRST action the law requires?","options":["Move into a lane not immediately adjacent to the stopped vehicle, if it is safe and legal to do so","Come to a complete stop until directed to proceed by an officer","Sound the horn continuously while passing the stopped vehicle","Reduce speed to exactly 20 mph below the posted limit and hold the lane"],"answer":0,"explanation":"Maryland Transportation Article 21-405.1 (Move Over law) requires a driver to make a lane change into a lane not immediately adjacent to the stopped vehicle when it is safe and legal. Only if a lane change is unsafe or impossible must the driver instead slow to a reasonable and prudent speed. Source: Md. Code, Transportation 21-405.1; Maryland MVA/MSP guidance.","handbook":"","hbref":""},{"q":"If a Maryland CDL driver cannot safely change lanes when passing a stopped emergency or service vehicle with its lights on, what must the driver do instead?","options":["Slow to a speed that is reasonable and prudent for the existing conditions","Stop completely on the shoulder until the scene is cleared","Maintain the posted speed limit and pass without changing speed","Pull onto the median and wait for traffic to clear the lane"],"answer":0,"explanation":"Under Md. Transportation 21-405.1, if moving over is unsafe or not possible, the driver must slow to a reasonable and prudent speed safe for conditions. Maryland law does not set a single fixed number; it requires a reasonable speed for conditions. Source: Md. Code, Transportation 21-405.1.","handbook":"","hbref":""},{"q":"As of an October 1, 2022 expansion, Maryland's Move Over law applies to which of the following stopped on the roadside?","options":["Any vehicle displaying hazard lights, warning cones, or road flares, including ordinary passenger cars","Only marked police and fire vehicles using flashing lights","Only tow trucks and highway maintenance vehicles","Only commercial motor vehicles over 26,001 pounds"],"answer":0,"explanation":"Effective October 1, 2022, Maryland broadened 21-405.1 so the Move Over duty applies to ANY stopped vehicle displaying hazard lights, road flares, or warning cones, not just emergency or service vehicles. Source: Md. Code, Transportation 21-405.1 (2022 amendment); Maryland MVA.","handbook":"","hbref":""},{"q":"When a Maryland school bus is stopped with its red lights flashing and stop arm extended on a two-lane undivided road, what must a CDL driver approaching from EITHER direction do?","options":["Stop and remain stopped until the lights stop flashing and the bus moves or signals to go","Slow to 15 mph and pass on the left with caution","Stop only if traveling in the same direction as the bus","Proceed if no children are visible near the bus"],"answer":0,"explanation":"On an undivided two-way roadway in Maryland, traffic in BOTH directions must stop for a school bus with flashing red lights and extended stop arm, and stay stopped until the signals are off. Source: Md. Code, Transportation 21-706; Maryland MVA/MSP.","handbook":"","hbref":""},{"q":"Under Maryland's divided-highway exception, when are drivers traveling in the OPPOSITE direction from a stopped school bus NOT required to stop?","options":["When the directions of travel are separated by a physical median or barrier such as grass, dirt, or a concrete divider","When the road has four or more lanes, regardless of any median","When a double yellow center line separates the directions of travel","When the bus is more than 100 feet away in the opposite lanes"],"answer":0,"explanation":"Maryland exempts opposite-direction traffic from stopping ONLY when a physical median, barrier, or unpaved strip separates the roadways. Painted lines do NOT create a divided highway, so a double yellow line alone does not trigger the exception. Source: Md. Code, Transportation 21-706; Maryland MVA guidance.","handbook":"","hbref":""},{"q":"On a Maryland divided highway with a physical median, who must still stop when a school bus on the opposite side flashes its red lights?","options":["Drivers traveling in the same direction as the bus, behind it","All drivers on both roadways must stop","No drivers are required to stop on any divided highway","Only drivers in the lane immediately next to the median"],"answer":0,"explanation":"Even on a divided highway, traffic following the bus in the SAME direction must stop. Only opposing traffic separated by the physical median is excused. Source: Md. Code, Transportation 21-706.","handbook":"","hbref":""},{"q":"What is the absolute maximum speed limit that may be posted on any highway in Maryland, including interstate highways and expressways?","options":["70 mph","65 mph","75 mph","55 mph"],"answer":0,"explanation":"Maryland law caps the maximum speed limit at 70 mph, which may be posted only on certain interstate highways and expressways; no Maryland highway may post more than 70 mph. Source: Md. Code, Transportation 21-801.1; MDOT SHA.","handbook":"","hbref":""},{"q":"How does Maryland set the maximum speed limit for trucks and other commercial motor vehicles compared with passenger cars on the same highway?","options":["Trucks follow the same posted maximum as other vehicles; Maryland has no separate lower statewide truck speed limit","Trucks are limited to 55 mph statewide regardless of the posted limit","Trucks are limited to 10 mph below the posted limit on all highways","Trucks are limited to 65 mph while cars may run 70 mph on every interstate"],"answer":0,"explanation":"Unlike some states, Maryland does NOT set a separate, lower statewide speed limit for trucks. Commercial vehicles obey the same posted limits as other traffic (up to the 70 mph cap). Source: Md. Code, Transportation 21-801.1; MDOT SHA speed-limit guidance.","handbook":"","hbref":""},{"q":"Which commercial vehicles must STOP before crossing railroad tracks at grade under the rules Maryland applies to CDL drivers?","options":["Buses carrying passengers and vehicles carrying placarded hazardous materials","All commercial motor vehicles over 10,000 pounds","Only vehicles pulling double or triple trailers","Only empty tank vehicles that previously hauled flammables"],"answer":0,"explanation":"Maryland follows the federal rule (49 CFR 392.10) adopted in its CDL manual: buses carrying passengers and placarded hazmat vehicles must stop at grade crossings. Most other trucks are not required to stop unless signs or signals direct it. Source: Maryland CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"When a placarded hazmat truck or passenger bus is required to stop at a Maryland railroad crossing, within what distance of the nearest rail must it stop?","options":["No closer than 15 feet and no farther than 50 feet from the nearest rail","No closer than 5 feet and no farther than 25 feet from the nearest rail","No closer than 25 feet and no farther than 75 feet from the nearest rail","No closer than 10 feet and no farther than 100 feet from the nearest rail"],"answer":0,"explanation":"Required-to-stop CMVs must halt within 50 feet of, but not closer than 15 feet to, the nearest rail, then look and listen before proceeding. Source: Maryland CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"After stopping at a railroad crossing, a Maryland bus or placarded hazmat driver may proceed only after doing what?","options":["Looking and listening in both directions for an approaching train and confirming the crossing can be cleared without stopping","Shifting gears at least once while crossing the tracks to maintain momentum","Waiting a mandatory 30 seconds regardless of whether a train is coming","Sounding the horn three times before entering the crossing"],"answer":0,"explanation":"After stopping within the 15-to-50-foot zone, the driver must look and listen both ways for a train and must not start across unless there is room to clear the tracks completely without stopping. Drivers should not shift gears while on the tracks. Source: Maryland CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"When a Maryland CDL driver must stop a truck on the traveled portion or shoulder of a highway, within how many minutes must warning devices (reflective triangles) be placed?","options":["Within 10 minutes of stopping","Within 5 minutes of stopping","Within 15 minutes of stopping","Within 30 minutes of stopping"],"answer":0,"explanation":"A driver of a stopped CMV must place warning devices within 10 minutes. This federal standard is taught in the Maryland CDL Manual and applies in Maryland. Source: Maryland CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a two-lane, two-way road, where should a Maryland CDL driver place the three required warning triangles for a stopped truck?","options":["About 10 feet behind the vehicle on the traffic side, about 100 feet behind, and about 100 feet ahead of the vehicle","All three triangles 200 feet behind the vehicle in a row","About 50 feet, 150 feet, and 250 feet behind the vehicle only","One on the hood and two on the roof to maximize visibility"],"answer":0,"explanation":"On a two-way road, place one triangle about 10 feet behind on the traffic side, one about 100 feet to the rear, and one about 100 feet to the front, so traffic from both directions is warned. Source: Maryland CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a one-way or divided highway, how should a Maryland CDL driver space the three warning triangles behind a stopped truck?","options":["At about 10 feet, 100 feet, and 200 feet toward the approaching traffic","At about 10 feet, 50 feet, and 100 feet toward the approaching traffic","At about 25 feet, 75 feet, and 150 feet toward the approaching traffic","At about 50 feet, 100 feet, and 500 feet toward the approaching traffic"],"answer":0,"explanation":"On a one-way or divided highway, the three triangles go toward approaching traffic at about 10, 100, and 200 feet from the vehicle. Source: Maryland CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Maryland's keep-right statute requires a slow vehicle to use the right-hand lane. A vehicle traveling how far below the maximum speed limit must keep right (except to pass or turn left)?","options":["10 mph or more below the applicable maximum speed limit","5 mph or more below the applicable maximum speed limit","15 mph or more below the applicable maximum speed limit","20 mph or more below the applicable maximum speed limit"],"answer":0,"explanation":"Md. Transportation 21-301 requires any vehicle going 10 mph or more below the maximum limit (or slower than normal traffic when conditions require) to keep to the right-hand lane, except when overtaking or preparing for a left turn. Source: Md. Code, Transportation 21-301.","handbook":"","hbref":""},{"q":"On a Maryland roadway with two or more lanes in the same direction, what governs which lane a truck, truck tractor, trailer, or bus must use?","options":["The directions of any traffic-control device that requires the vehicle to be driven in a certain lane","The driver's preference, since lane signs do not apply to commercial vehicles","A fixed rule that all trucks must use only the far-left lane","Whichever lane has the fewest passenger vehicles at the time"],"answer":0,"explanation":"Maryland law (Transportation 21-301 and related lane-use rules) requires trucks, truck tractors, trailers, and buses to obey traffic-control devices designating specific lanes for them. Source: Md. Code, Transportation 21-301; 21-309.","handbook":"","hbref":""},{"q":"Why are commercial trucks generally prohibited from the Baltimore-Washington Parkway (the National Park Service section of MD 295)?","options":["It is a federal parkway that bans commercial vehicles; trucks must use I-95 or other truck routes unless they hold a special permit","The pavement is too narrow for any vehicle wider than a passenger car","It is a toll road that does not accept commercial transponders","It permits trucks only between midnight and 5 a.m."],"answer":0,"explanation":"The NPS-administered Baltimore-Washington Parkway prohibits commercial vehicles; trucks are signed off and must use I-95 or other designated truck routes. RVs and buses are generally allowed, but commercial trucks are not without a permit. Source: National Park Service parkway regulations; Maryland truck-route guidance.","handbook":"","hbref":""},{"q":"Which classes of cargo are prohibited from the Fort McHenry Tunnel (I-95) and Baltimore Harbor Tunnel (I-895) in Maryland?","options":["Explosives, bulk gasoline and flammable liquids, and bottled propane above the allowed limits, among other hazardous materials","Refrigerated food loads and live animals","Any load weighing more than 40,000 pounds gross","All loads carried in double or triple trailers, regardless of contents"],"answer":0,"explanation":"The MDTA bans explosives, bulk gasoline/flammable liquids, certain radioactive materials, and bottled propane over the allowed limit (more than 10 lb per container) from the Fort McHenry and Baltimore Harbor Tunnels. Source: MDTA forbidden-hazardous-materials list; mdta.maryland.gov.","handbook":"","hbref":""},{"q":"A Maryland CDL driver hauling placarded hazmat that is banned from the Baltimore tunnels should take which route through the Baltimore area?","options":["The western section of I-695 (the outer Beltway) around the harbor crossings","Straight through the Fort McHenry Tunnel on I-95 during off-peak hours","The Baltimore Harbor Tunnel on I-895 with hazard lights on","Any city street through downtown Baltimore that avoids tolls"],"answer":0,"explanation":"Hazmat loads barred from the tunnels must detour around the harbor using the western portion of I-695. This routing matters even more since the Key Bridge (the southeast I-695 crossing) collapsed in 2024. Source: MDTA tunnel-restriction/permit guidance; mdta.maryland.gov.","handbook":"","hbref":""},{"q":"On the steep mountain grades of I-68 in western Maryland (near Sideling Hill and Big Savage Mountain), what safety feature is provided for trucks that lose braking on a long downgrade?","options":["Runaway truck ramps (escape ramps) that use an upgrade and arrester material to stop the vehicle","Mandatory tunnels that force trucks to slow before descending","Reversible toll lanes that open only for disabled trucks","Heated pavement strips that increase tire traction on the grade"],"answer":0,"explanation":"I-68 through western Maryland has steep, long grades; runaway truck ramps (gravel/sand arrester escape ramps on an upgrade) are provided so trucks with failed or overheated brakes can stop safely. Drivers should descend in a low gear and use proper braking technique. Source: MDOT SHA; Maryland CDL Manual mountain-driving section.","handbook":"","hbref":""},{"q":"Which Maryland agency issues Commercial Driver's Licenses (CDLs)?","options":["The MDOT Motor Vehicle Administration (MVA)","The Maryland State Police Commercial Vehicle Division","The Federal Motor Carrier Safety Administration (FMCSA)","The Maryland Department of Labor"],"answer":0,"explanation":"CDLs in Maryland are issued by the MDOT Motor Vehicle Administration (MVA). The FMCSA sets federal CDL standards but does not issue the license itself. Source: Maryland MVA, Commercial Driver's License pages.","handbook":"","hbref":""},{"q":"Before scheduling the CDL skills (road) test in Maryland, how long must you have held your Commercial Learner's Permit (CLP)?","options":["At least 14 days","At least 7 days","At least 30 days","At least 60 days"],"answer":0,"explanation":"Maryland follows the federal rule: a CLP holder is not eligible to take the CDL skills test until at least 14 days after the CLP is issued. Source: Maryland MVA, Get or Renew a CDL.","handbook":"","hbref":""},{"q":"What training must be completed before a Maryland applicant can take the CDL skills test for a first Class A or Class B license?","options":["Entry-Level Driver Training (ELDT)","A state-approved defensive driving course","An FMCSA hazardous materials seminar","A 40-hour MVA classroom orientation"],"answer":0,"explanation":"Maryland will not allow you to take the skills test until you complete federally required Entry-Level Driver Training (ELDT), required for a first Class A or B CDL and for first P, S, or H endorsements. Source: Maryland MVA / FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"The Maryland CDL skills test has three parts that must be passed. What are they?","options":["Pre-trip vehicle inspection, basic vehicle control skills, and on-road driving","Written knowledge, vision screening, and on-road driving","Air-brake test, backing test, and night driving","Pre-trip inspection, hazardous materials handling, and on-road driving"],"answer":0,"explanation":"Maryland's CDL skills test consists of the pre-trip vehicle inspection, basic vehicle control skills, and the on-road driving test, and all three must be completed successfully. Source: Maryland MVA, CDL Skills Test.","handbook":"","hbref":""},{"q":"Under Maryland's CDL self-certification, how many categories of commercial driving operation can an applicant declare?","options":["Four","Two","Three","Five"],"answer":0,"explanation":"Maryland CDL holders self-certify into one of four categories: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), and Excepted Intrastate (EA). Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"A Maryland driver certifies as 'Non-Excepted Interstate (NI).' What does this mean?","options":["They drive across state lines and must meet all federal medical qualification requirements","They drive only within Maryland and are exempt from federal medical rules","They drive across state lines only for specific excepted activities","They drive only within Maryland using an approved MVA medical waiver"],"answer":0,"explanation":"Non-Excepted Interstate (NI) means the driver operates a CMV across state lines and complies with all federal qualification (including medical) requirements. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"How does a Maryland CDL holder's DOT Medical Examiner's Certificate normally reach the MVA?","options":["The medical examiner submits it electronically to FMCSA's National Registry and the MVA receives it automatically","The driver must mail the paper certificate to MVA headquarters within 10 days","The driver's employer faxes it to the MVA on the driver's behalf","The certificate is uploaded only when the driver renews the CDL in person"],"answer":0,"explanation":"The certified medical examiner sends the certificate information electronically to the FMCSA National Registry, and the MVA receives the medical certification automatically; the driver does not need to mail or submit it. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"What happens to a Maryland driver's commercial privileges if their DOT medical certification lapses?","options":["Their CDL is downgraded and they are no longer qualified to operate a CMV","Nothing changes for 90 days as long as they keep driving intrastate","Their full driver's license, including the base class, is suspended immediately","The MVA issues an automatic temporary medical waiver"],"answer":0,"explanation":"If medical certification lapses, the driver is no longer legally qualified to operate a CMV and the commercial driving privileges are downgraded. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which set of documents must a Maryland CDL applicant provide at the MVA?","options":["Proof of identity, age, Social Security number, and Maryland residency","Only a valid passport and a utility bill","Proof of identity and a notarized employer letter only","A birth certificate and proof of vehicle insurance only"],"answer":0,"explanation":"Maryland CDL applicants must present proof of identity, age, Social Security number, and Maryland residency. Source: Maryland MVA, Get or Renew a CDL.","handbook":"","hbref":""},{"q":"Self-certification of driving type is required in Maryland in all of the following situations EXCEPT which?","options":["Each time you renew your annual vehicle registration","When you get a new CDL","When you renew or upgrade your CDL","When you switch between interstate and intrastate driving"],"answer":0,"explanation":"Self-certification is required when getting, renewing, transferring, or upgrading a CDL, changing medical status, or switching between interstate and intrastate driving — not for routine vehicle registration. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which category describes a Maryland CDL holder who drives a CMV only within Maryland and holds an approved MVA CDL Medical Waiver?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"answer":0,"explanation":"Non-Excepted Intrastate (NA) applies to a driver qualified to operate only within Maryland who has an approved MVA CDL Medical Waiver. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"What is the first knowledge test every Maryland CDL applicant must pass, regardless of endorsements?","options":["The General Knowledge test","The Hazardous Materials test","The Air Brakes test","The Combination Vehicles test"],"answer":0,"explanation":"All Maryland CDL applicants must first pass the CDL General Knowledge test; endorsement-specific tests (P, S, N, H, T) are taken in addition as needed. Source: Maryland MVA / CDL Manual (DL-151).","handbook":"","hbref":""},{"q":"Where does a Maryland applicant take the CDL knowledge (written) tests?","options":["Electronically at MVA offices throughout Maryland","Only by mail-in paper exam to MVA headquarters","At any FMCSA federal testing center","Online from home through any approved third-party website"],"answer":0,"explanation":"The CDL knowledge tests are administered electronically at MVA offices across Maryland. Source: Maryland MVA, Knowledge Tests / Prepare for a Driver's License Test.","handbook":"","hbref":""},{"q":"What is the typical renewal cycle (term length) for a standard Maryland driver's license and CDL?","options":["8 years","4 years","5 years","10 years"],"answer":0,"explanation":"Maryland driver's licenses, including CDLs, are typically issued/renewed for an 8-year term. Source: Maryland MVA, Renew a License or ID.","handbook":"","hbref":""},{"q":"On the Maryland CDL skills test, in what order are the three components generally conducted?","options":["Pre-trip inspection, then basic control skills, then on-road driving","On-road driving, then pre-trip inspection, then basic control skills","Basic control skills, then on-road driving, then pre-trip inspection","On-road driving, then basic control skills, then pre-trip inspection"],"answer":0,"explanation":"Maryland conducts the skills test in sequence: pre-trip vehicle inspection first, then basic vehicle control skills, then the on-road driving test. Source: Maryland MVA, CDL Skills Test.","handbook":"","hbref":""},{"q":"If a Maryland CDL holder lets their medical certification lapse and more than one year passes, what must they do to regain the CDL?","options":["Retake all CDL knowledge and skills tests","Simply submit a new medical certificate with no testing","Pay a reinstatement fee but take no tests","Wait out a mandatory 90-day suspension only"],"answer":0,"explanation":"If a CDL is downgraded for a lapsed medical certificate and more than one year passes, the driver must retake all CDL knowledge and skills tests to get the CDL back. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which category fits a Maryland CDL holder who crosses state lines only to transport school children, sick or injured persons, or corpses?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"Excepted Interstate (EI) covers drivers who operate across state lines only for specific excepted activities such as transporting school children or staff, sick or injured persons, or corpses. Source: Maryland MVA, CDL Medical Certification Requirements.","handbook":"","hbref":""},{"q":"Which scenario does NOT, by itself, trigger the federal ELDT requirement before a Maryland skills test?","options":["Renewing an existing Class A CDL with the same endorsements","Applying for a first Class A CDL","Upgrading from a Class B to a Class A CDL","Obtaining a first Passenger (P) or School Bus (S) endorsement"],"answer":0,"explanation":"ELDT is required for a first Class A or B CDL, for upgrading Class B to Class A, and for a first P, S, or H endorsement — but a straightforward renewal of an existing CDL does not itself trigger ELDT. Source: Maryland MVA / FMCSA ELDT rule.","handbook":"","hbref":""},{"q":"How is the Maryland CDL skills (road) test appointment typically scheduled?","options":["By making an appointment through the applicant's myMVA account","By walking in to any MVA branch without an appointment","By calling FMCSA's national scheduling line","Automatically the same day the CLP is issued"],"answer":0,"explanation":"Applicants schedule the CDL skills test by making an appointment through their myMVA account; the test is administered by the MVA after the CLP hold and ELDT are satisfied. Source: Maryland MVA, CDL Skills Test.","handbook":"","hbref":""}],"ru":{"0":{"q":"На автодорогах Мэриленда какова максимальная допустимая ширина транспортного средства (без учёта зеркал и других устройств безопасности/энергосбережения), при превышении которой требуется разрешение на негабарит?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","120 дюймов (10 футов)"],"explanation":"Maryland Transportation Article § 24-102 устанавливает максимальную ширину транспортного средства в 102 дюйма (8 футов 6 дюймов); ширина измеряется без учёта зеркал, габаритных/указательных фонарей и устройств энергосбережения. Всё, что шире, требует разрешения SHA на негабарит. Источник: Md. Transp. § 24-102; MD SHA Oversize/Overweight Hauling Permit Manual."},"1":{"q":"Какова максимальная допустимая высота транспортного средства с грузом на автодорогах Мэриленда без разрешения?","options":["12 футов 6 дюймов","13 футов","13 футов 6 дюймов","14 футов"],"explanation":"Согласно Maryland Transportation Article § 24-104, высота транспортного средства с грузом не может превышать 13 футов 6 дюймов. В руководстве SHA по разрешениям 13'6\" указано как законный предел без особых условий. Источник: Md. Transp. § 24-104; MD SHA Hauling Permit Manual (раздел Height)."},"2":{"q":"Каков максимальный полный вес транспортного средства, разрешённый на межштатных автомагистралях (Interstate) Мэриленда без разрешения на перевес?","options":["73 000 фунтов","80 000 фунтов","90 000 фунтов","100 000 фунтов"],"explanation":"Мэриленд следует федеральному стандарту для межштатных автомагистралей: максимальный полный вес составляет 80 000 фунтов (включая груз). Источник: Md. Transp. § 24-109; 23 CFR 658.17 в применении к межштатным автомагистралям Мэриленда."},"3":{"q":"На межштатных автомагистралях Мэриленда каков максимальный вес, допустимый на одиночную ось?","options":["17 000 фунтов","20 000 фунтов","22 400 фунтов","34 000 фунтов"],"explanation":"Предел нагрузки на одиночную ось в системе межштатных автомагистралей Мэриленда составляет 20 000 фунтов, что соответствует федеральному стандарту в Maryland Transportation Article § 24-109. Источник: Md. Transp. § 24-109; 23 CFR 658.17."},"4":{"q":"На межштатных автомагистралях Мэриленда каков максимальный вес, допустимый на сдвоенную ось (тандем)?","options":["20 000 фунтов","32 000 фунтов","34 000 фунтов","40 000 фунтов"],"explanation":"Предел нагрузки на сдвоенную ось (группа из двух осей с расстоянием более 40, но не более 96 дюймов) составляет 34 000 фунтов согласно Maryland Transportation Article § 24-109, что соответствует федеральному стандарту для межштатных автомагистралей. Источник: Md. Transp. § 24-109; 23 CFR 658.17."},"5":{"q":"Какое управление Мэриленда выдаёт разрешения на перевозку негабаритных/тяжеловесных грузов для движения по дорогам, обслуживаемым штатом?","options":["Подразделение лицензирования водителей Управления транспортных средств (MVA)","Управление дорожного движения и безопасности SHA, отдел автоперевозчиков, подразделение разрешений на перевозки (SHA Office of Traffic and Safety, Motor Carrier Division, Hauling Permits Unit)","Отдел контроля коммерческого транспорта полиции штата Мэриленд","Отдел платных объектов Транспортного управления Мэриленда"],"explanation":"Разрешения на перевозку негабаритных/тяжеловесных грузов (OS/OW) выдаёт Maryland State Highway Administration, Office of Traffic and Safety, Motor Carrier Division – Hauling Permits Unit (Ганновер, штат Мэриленд). Источник: MD SHA Oversize/Overweight Hauling Permit Manual (Introduction)."},"6":{"q":"Груз уже невозможно уменьшить, но он по-прежнему превышает законные пределы Мэриленда. Какие разделы закона устанавливают законные пределы размеров и веса, при превышении которых требуется специальное разрешение на перевозку?","options":["Transportation Article, Title 16, Sections 101 and 102","Transportation Article, Title 24, Sections 108 and 109","Transportation Article, Title 21, Sections 1101 and 1102","Transportation Article, Title 11, Sections 301 and 302"],"explanation":"В руководстве SHA по разрешениям указано, что когда груз превышает законные пределы, установленные в Maryland Motor Vehicle Law, Title 24, Sections 108 (нагрузки на оси) и 109 (полный вес), необходимо приобрести специальное разрешение на перевозку. Источник: MD SHA Hauling Permit Manual; Md. Transp. §§ 24-108, 24-109."},"7":{"q":"На национальной сети дорог Мэриленда (National Network) и обозначенных грузовых маршрутах какова максимальная длина полуприцепа, не требующая разрешения?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"На национальной сети дорог (National Network) и обозначенных грузовых маршрутах полуприцепы длиной до 53 футов допускаются без разрешения (48 футов применяется на многих других дорогах штата). Источник: Md. Transp. § 24-104.1/24-104.2; J.J. Keller Maryland size/weight summary."},"8":{"q":"Мэриленд не устанавливает фиксированного предела общей длины сцепки тягача с полуприцепом в национальной сети (National Network), но вес на любую группу осей всё равно ограничен каким расчётом?","options":["Федеральная мостовая формула (Bridge Gross Weight Table)","Только заводской рейтинг полной нагрузки на ось (GAWR)","Фиксированно 1 000 фунтов на дюйм ширины шины","Зарегистрированный вес тары, умноженный на два"],"explanation":"Мэриленд применяет федеральную мостовую формулу на своих межштатных автомагистралях/в национальной сети: максимальный вес на любую группу последовательных осей определяется мостовой формулой, вплоть до общего предела в 80 000 фунтов. Источник: Md. Transp. § 24-109; 23 CFR 658.17 Federal Bridge Formula."},"9":{"q":"Сцепка превышает законный вес в Мэриленде. До какого полного веса обычное разрешение SHA на тяжеловесную перевозку может разрешить движение и по каким дорогам?","options":["До 100 000 фунтов по любой дороге штата","До 120 000 фунтов по любой дороге штата","До 150 000 фунтов только по межштатным маршрутам (Interstate)","До 200 000 фунтов только по Capital Beltway"],"explanation":"Руководство SHA предусматривает, что грузы по разрешению для сцепок весом до 150 000 фунтов включительно допускаются только на межштатных маршрутах (Interstate) (без обращения в Office of Bridge Development), при условии соблюдения правил по весу/расстоянию между осями. Источник: MD SHA Hauling Permit Manual (Weight, 'Over 60 Tons')."},"10":{"q":"Согласно тарифной сетке сборов SHA Мэриленда, какова базовая плата за разрешение на перевозку, когда совокупный вес груза составляет 90 000 фунтов (45 тонн) или менее?","options":["$10.00","$30.00","$50.00","$100.00"],"explanation":"Руководство SHA устанавливает базовую плату в $30.00 за разрешение на перевозку, когда негабаритный/совокупный груз весит менее 90 000 фунтов; за грузы свыше 45 тонн (90 000 фунтов) добавляется $5.00 за каждую дополнительную тонну. Источник: MD SHA Hauling Permit Manual (General Information; Permit Fees)."},"11":{"q":"Для груза по разрешению, превышающего 45 тонн (90 000 фунтов), сколько SHA Мэриленда добавляет к плате за разрешение за каждую дополнительную тонну?","options":["$2.00 за тонну","$5.00 за тонну","$10.00 за тонну","$25.00 за тонну"],"explanation":"В руководстве указано, что для грузов свыше 45 тонн (90 000 фунтов) взимается дополнительно $5.00 за каждую дополнительную тонну (например, 50 тонн = $55.00). Источник: MD SHA Hauling Permit Manual (General Information; тарифная сетка Permit Fees)."},"12":{"q":"Согласно общим правилам Мэриленда о часах движения, когда НЕЛЬЗЯ перемещать негабаритный/тяжеловесный груз по разрешению?","options":["Только с полуночи до 6:00 в будние дни","В любую субботу после 12:00 (полудня) и весь воскресный день","Только в первый понедельник каждого месяца","Только в обозначенные часы пик в Балтиморе"],"explanation":"Согласно руководству SHA и COMAR Title 11, ни один груз по разрешению не может перемещаться в любую субботу после 12:00 (полудня), в любое воскресенье или в перечисленные праздничные периоды. В остальных случаях действует правило движения при дневном свете (с получаса после восхода до получаса до заката). Источник: MD SHA Hauling Permit Manual (Hours of Movement); COMAR 11.04."},"13":{"q":"При какой ширине груз по разрешению (кроме передвижного/модульного дома) впервые требует одной частной машины сопровождения в Мэриленде?","options":["Шире 10 футов","Шире 12 футов","Шире 13 футов","Шире 14 футов"],"explanation":"Руководство SHA требует одну частную машину сопровождения для грузов шире 13 футов (грузы в диапазоне 13'1\"–13'11\" требуют 1 частное сопровождение), при этом две частные машины сопровождения требуются при ширине 14 футов или более. Источник: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)."},"14":{"q":"В Мэриленде груз по разрешению шириной 14 футов или более требует сколько частных машин сопровождения?","options":["Сопровождение не требуется","Одна частная машина сопровождения","Две частные машины сопровождения","Четыре частные машины сопровождения"],"explanation":"Руководство SHA указывает, что все грузы шириной 14 футов или более требуют двух частных машин сопровождения для движения по Мэриленду и через него. Источник: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)."},"15":{"q":"Какой габарит или вес делает груз по разрешению в Мэриленде «сверхтяжёлым грузом» (Super Load) на межштатных автомагистралях?","options":["Свыше 90 000 фунтов полного веса или 11 футов ширины","Превышение 150 000 фунтов (75 тонн) или 27 000 фунтов на любую ось","Превышение 80 000 фунтов или 12 футов высоты","Любой груз, требующий одной частной машины сопровождения"],"explanation":"Руководство SHA определяет «сверхтяжёлые грузы» (Super Loads) в числе прочего как превышающие 150 000 фунтов (75 тонн) или превышающие 27 000 фунтов на любую ось на межштатных автомагистралях (либо превышающие 120 000 фунтов / 60 тонн или 27 000 фунтов на ось на дорогах штата Мэриленд), либо длиной 120 футов, шириной 16 футов или высотой 16 футов. Источник: MD SHA Hauling Permit Manual (Escorts – General Conditions, Super Loads)."},"16":{"q":"На дорогах штата Мэриленд (не межштатных), при превышении какого полного веса груз по разрешению классифицируется как чрезмерный «сверхтяжёлый груз» (Super Load)?","options":["80 000 фунтов (40 тонн)","100 000 фунтов (50 тонн)","120 000 фунтов (60 тонн)","150 000 фунтов (75 тонн)"],"explanation":"Руководство SHA классифицирует груз как «сверхтяжёлый груз» (Super Load) на дорогах штата Мэриленд, когда он превышает 120 000 фунтов (60 тонн) или превышает 27 000 фунтов на любую ось. Порог в 150 000 фунтов (75 тонн) применяется к межштатным автомагистралям. Источник: MD SHA Hauling Permit Manual (Super Loads)."},"17":{"q":"За исключением межштатных автомагистралей, какой допуск по нагрузке на ось закон Мэриленда разрешает сельскохозяйственному транспортному средству, перевозящему сельхозпродукцию с поля в перечисленные периоды сбора урожая?","options":["Допуск по нагрузке на ось 5%","Допуск по нагрузке на ось 10%","Допуск по нагрузке на ось 15%","Допуск не разрешён ни в какое время"],"explanation":"Maryland Transportation Article § 24-109 обычно разрешает сельскохозяйственным транспортным средствам (вне межштатных автомагистралей) допуск по оси 5%, увеличиваемый до 15% по нагрузке на ось в установленные периоды сбора урожая (например, пшеница с 1 июня по 15 августа, кукуруза с 1 июля по 1 декабря), с допуском по полному весу 5% в пределах 100 миль от поля. Источник: Md. Transp. § 24-109 (сельскохозяйственная льгота на период сбора урожая)."},"18":{"q":"За исключением межштатных автомагистралей, сцепке, перевозящей лесную продукцию из леса (полуприцеп длиной 45 футов или менее), какой допуск по нагрузке на ось разрешается с 1 июня по 30 сентября?","options":["Допуск по нагрузке на ось 5%","Допуск по нагрузке на ось 10%","Допуск по нагрузке на ось 15%","Допуск по нагрузке на ось 20%"],"explanation":"Maryland Transportation Article § 24-109 разрешает сцепке для перевозки лесной продукции (полуприцеп 45 футов или менее, загруженной вне дорог, не на межштатных автомагистралях) допуск по оси 5%, увеличиваемый до 15% с 1 июня по 30 сентября. Источник: Md. Transp. § 24-109 (льгота для лесной продукции)."},"19":{"q":"Мэриленд (следуя федеральному закону) разрешает тяжёлому транспортному средству небольшую дополнительную весовую надбавку для компенсации веса какого устройства экономии топлива без нарушения пределов полного веса/нагрузки на ось/мостовой формулы?","options":["Система автоматической подкачки шин, до 1 000 дополнительных фунтов","Вспомогательная силовая установка / технология снижения холостого хода, до 550 дополнительных фунтов","Холодильная установка, до 2 000 дополнительных фунтов","Широкопрофильная одиночная шина, до 250 дополнительных фунтов"],"explanation":"Maryland Transportation Article § 24-109 разрешает в общей сложности до 550 дополнительных фунтов в полном весе, на оси, тандеме или по мостовой формуле для учёта вспомогательной силовой установки или технологии снижения холостого хода, в соответствии с федеральным законом. Источник: Md. Transp. § 24-109 (надбавка за снижение холостого хода); 23 CFR 658.17."},"20":{"q":"В Мэриленде какой класс CDL требуется для управления сцепкой с полным весом автопоезда (GCWR) 26 001 фунт или более, где буксируемая единица имеет GVWR свыше 10 000 фунтов?","options":["Класс A","Класс B","Класс C","Класс D"],"explanation":"Мэриленд определяет CDL класса A как сцепку с тягачом/силовой установкой и прицепом(ами) с GCWR 26 001+ фунтов, где буксируемая единица имеет GVWR свыше 10 000 фунтов. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"21":{"q":"Согласно правилам Maryland MVA, какой класс CDL даёт право управлять любым одиночным транспортным средством с GVWR 26 001 фунт или более (буксирующим единицу не более 10 000 фунтов)?","options":["Класс A","Класс B","Класс C","Класс M"],"explanation":"CDL класса B в Мэриленде охватывает одиночные транспортные средства с GVWR 26 001+ фунтов или такое транспортное средство, буксирующее единицу с GVWR не более 10 000 фунтов. Примеры включают цельные фургоны и большинство автобусов. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"22":{"q":"Транспортное средство в Мэриленде имеет рейтинг менее 26 001 фунта, но рассчитано на перевозку 16 или более пассажиров (включая водителя) либо перевозит опасные материалы, требующие табличек. Какой класс CDL применяется?","options":["Класс A","Класс B","Класс C","Класс E"],"explanation":"CDL класса C в Мэриленде охватывает меньшие коммерческие транспортные средства, которые не соответствуют весовым критериям класса A или B, но рассчитаны на перевозку 16+ пассажиров (включая водителя) либо перевозят опасные материалы, требующие табличек. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"23":{"q":"В Мэриленде какой код подтверждения (endorsement) требуется для управления транспортным средством, рассчитанным на перевозку 16 или более пассажиров, например автобусом?","options":["Подтверждение N","Подтверждение P","Подтверждение T","Подтверждение H"],"explanation":"Мэриленд требует подтверждения P (Passenger) для управления транспортными средствами, перевозящими 16 или более пассажиров. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"24":{"q":"Чтобы управлять школьным автобусом в Мэриленде, какую комбинацию подтверждений требует MVA?","options":["Только подтверждение S","Только подтверждение P","Оба подтверждения — P (Passenger) и S (School Bus)","Оба подтверждения — S (School Bus) и H (HazMat)"],"explanation":"Мэриленд требует оба подтверждения — P (Passenger) и S (School Bus) — для управления школьным автобусом. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"25":{"q":"Какое подтверждение CDL в Мэриленде требуется для управления транспортным средством, перевозящим жидкости или газы в цистерне, например топливным или водяным автоцистерном?","options":["Подтверждение H","Подтверждение N","Подтверждение T","Подтверждение P"],"explanation":"Мэриленд использует подтверждение N (Tank Vehicle) для транспортных средств, перевозящих жидкости или газы в цистернах, таких как топливные или водяные автоцистерны. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"26":{"q":"В Мэриленде что объединяет подтверждение «X» в CDL?","options":["Passenger (P) и School Bus (S)","Tank Vehicle (N) и HazMat (H)","Doubles/Triples (T) и Tank (N)","HazMat (H) и Passenger (P)"],"explanation":"Подтверждение X в Мэриленде представляет собой комбинацию подтверждений N (Tank Vehicle) и H (HazMat), дающую право на перевозку опасных материалов в автоцистернах. Источник: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"27":{"q":"Каков минимальный возраст для получения CDL в Мэриленде с ограничением только на внутриштатное (только в пределах Мэриленда) коммерческое вождение?","options":["16 лет","18 лет","21 год","25 лет"],"explanation":"Мэриленд разрешает CDL с 18 лет для внутриштатного (в пределах Мэриленда) вождения, тогда как для межштатного вождения требуется возраст 21 год. Источник: Maryland MVA, Get or Renew a CDL; Manual DL-151."},"28":{"q":"Согласно Maryland MVA, каков минимальный возраст, необходимый для управления коммерческим транспортным средством в межштатных перевозках (через границы штатов)?","options":["18 лет","19 лет","21 год","23 года"],"explanation":"Мэриленд требует, чтобы водителям было не менее 21 года для управления транспортным средством с CDL в межштатном сообщении (через границы штатов), для перевозки опасных материалов, требующих табличек, или для межштатной перевозки пассажиров. Источник: Maryland MVA, Get or Renew a CDL."},"29":{"q":"19-летнему владельцу CDL в Мэриленде по закону запрещено делать что из перечисленного?","options":["Управлять цельным грузовиком в пределах Мэриленда","Управлять коммерческим транспортным средством через границы штатов","Иметь подтверждение Passenger (P) для внутриштатного использования","Управлять транспортным средством класса B в пределах Мэриленда"],"explanation":"Водитель в Мэриленде в возрасте от 18 до 21 года не может управлять коммерческим транспортным средством за пределами Мэриленда (межштатно), не может управлять транспортным средством, требующим табличек HazMat, и не может управлять сцепками с двойными/тройными прицепами. Источник: Maryland MVA / Manual DL-151."},"30":{"q":"Согласно федеральному правилу, применяемому в Мэриленде, как долго заявитель должен владеть учебным коммерческим разрешением (CLP), прежде чем ему будет позволено сдавать практический экзамен CDL (на дороге)?","options":["Не менее 7 дней","Не менее 10 дней","Не менее 14 дней","Не менее 30 дней"],"explanation":"Мэриленд применяет федеральное правило, требующее владеть CLP не менее 14 дней, прежде чем можно будет сдавать практический экзамен CDL (на дороге). Источник: Maryland MVA, Get or Renew a CDL; 49 CFR 383.25."},"31":{"q":"Прежде чем получить учебное коммерческое разрешение (CLP) в Мэриленде, заявитель должен уже иметь какой документ?","options":["Действительные водительские права Мэриленда (не мотоциклетные)","Мотоциклетные права Мэриленда","Федеральную карту TWIC","CDL другого штата"],"explanation":"Мэриленд требует, чтобы заявители на CLP уже имели действительные водительские права Мэриленда (не только мотоциклетные) и прошли тесты на зрение и знания. Источник: Maryland MVA / Manual DL-151."},"32":{"q":"Какой набор документов Maryland MVA требует предъявить заявителю при подаче заявления на CDL?","options":["Только действующие водительские права и фотографию","Подтверждение личности, возраста, номера социального страхования (Social Security number) и проживания в Мэриленде","Только паспорт и письмо от работодателя","Подтверждение личности и карту регистрации транспортного средства"],"explanation":"Maryland MVA требует подтверждение личности, возраста, номера социального страхования (Social Security number) и проживания в Мэриленде (законность пребывания устанавливается через эти документы, удостоверяющие личность). Источник: Maryland MVA, Get or Renew a CDL."},"33":{"q":"Где должно быть пройдено обучение водителей начального уровня (ELDT) для впервые подающего заявление на CDL класса A или B в Мэриленде?","options":["В любой частной автошколе по выбору заявителя","У провайдера, включённого в FMCSA Training Provider Registry","Только в отделении Maryland MVA","По программе, аккредитованной Maryland State Department of Education"],"explanation":"Мэриленд требует, чтобы ELDT для впервые подающих заявление на класс A/B (а также для впервые получаемых подтверждений S, P и H) проходилось у провайдера, включённого в FMCSA Training Provider Registry, до практического экзамена или теста знаний по HazMat. Источник: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"34":{"q":"Для чего из перечисленного Мэриленд требует обучение водителей начального уровня (ELDT) перед тестированием?","options":["Продление существующего CDL класса A","Добавление ограничения по автоматической трансмиссии","Получение CDL класса A или B впервые либо добавление S, P или H впервые","Обновление адреса проживания в CDL"],"explanation":"Мэриленд требует ELDT для впервые получаемых CDL класса A или B и для впервые добавляемых подтверждений School Bus (S), Passenger (P) или HazMat (H). Оно не требуется для продлений или административных изменений. Источник: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"35":{"q":"Какая из перечисленных является одной из четырёх категорий медицинской самосертификации, из которых должен выбрать владелец CDL в Мэриленде?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Provisional Interstate (PI)","Limited Hazmat (LH)"],"explanation":"Четыре категории самосертификации в Мэриленде — это Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: Maryland MVA, CDL Medical Certification Requirements."},"36":{"q":"Владелец CDL в Мэриленде, который ездит через границы штатов и должен соблюдать все федеральные требования к квалификации водителя, должен самосертифицироваться по какой категории?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI) применяется к владельцу CDL, который ездит через границы штатов и соответствует всем федеральным квалификационным требованиям, включая действующий медицинский сертификат DOT. Источник: Maryland MVA, CDL Medical Certification Requirements."},"37":{"q":"В Мэриленде, прежде чем можно будет сдать тест знаний на подтверждение HazMat (H) и выдать это подтверждение, заявитель должен пройти что?","options":["Оценку угрозы безопасности TSA с проверкой биографии на основе отпечатков пальцев","Государственную проверку выбросов транспортного средства","Только предварительный запрос в реестр по наркотикам и алкоголю (clearinghouse)","Только аудит водительской истории полицией штата Мэриленд"],"explanation":"Мэриленд требует, чтобы заявители на HazMat прошли оценку угрозы безопасности TSA, которая включает проверку биографии на основе отпечатков пальцев (Background Record Check, обрабатываемую через DPSCS), в дополнение к сдаче теста знаний по HazMat. Источник: Maryland MVA, CDL HazMat Endorsement; 49 CFR Part 1572."},"38":{"q":"После получения одобрения TSA, в течение какого срока заявитель в Мэриленде должен получить подтверждение HazMat?","options":["В течение 30 дней","В течение 90 дней","В течение шести месяцев","В течение двух лет"],"explanation":"Мэриленд требует, чтобы заявитель получил подтверждение HazMat в течение шести месяцев с даты, указанной в письме об одобрении TSA. Источник: Maryland MVA, CDL HazMat Endorsement."},"39":{"q":"Как часто владелец CDL в Мэриленде с подтверждением School Bus (S) обычно должен обновлять свой сертификат медицинского эксперта, чтобы это подтверждение оставалось действительным?","options":["Каждые 6 месяцев","Ежегодно (каждый год)","Каждые 2 года","Каждые 5 лет"],"explanation":"Хотя большинство сертификатов медицинского эксперта действительны до двух лет, владельцам подтверждения School Bus (S) в Мэриленде, как правило, требуется ежегодная медицинская сертификация для сохранения этого статуса. Источник: Maryland MVA, CDL Medical Certification Requirements."},"40":{"q":"В Мэриленде какова максимальная концентрация алкоголя в крови/выдыхаемом воздухе (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"Водитель CMV в Мэриленде дисквалифицируется за вождение с BAC 0.04 или выше — это половина предела 0.08 для некоммерческих водителей. Источник: Maryland Transportation Article §16-812(a) и §11-127.1; Maryland CDL Manual; 49 CFR 383.51 Table 1."},"41":{"q":"Согласно закону Мэриленда о подразумеваемом согласии, что происходит, если владельцу CDL законно предлагают пройти химический тест на алкоголь, а он отказывается?","options":["CDL дисквалифицируется не менее чем на 1 год (первый отказ приравнивается к тяжкому правонарушению)","Водителя штрафуют, но он сохраняет CDL","CDL приостанавливается на 60 дней","Ничего не происходит до осуждения"],"explanation":"Мэриленд применяет принцип подразумеваемого согласия: отказ от законно запрошенного химического теста дисквалифицирует CDL на 1 год за первое нарушение, так же как и другие тяжкие правонарушения. Источник: Maryland Transportation Article §16-205.1 и §16-812(b); 49 CFR 383.51 Table 1."},"42":{"q":"Каков срок дисквалификации CDL в Мэриленде за первое тяжкое правонарушение (например, DUI, BAC 0.04+ в CMV или отказ от теста), когда НЕ осуществляется перевозка опасных материалов, требующих табличек?","options":["1 год","60 дней","3 года","6 месяцев"],"explanation":"Первое тяжкое правонарушение дисквалифицирует CDL на 1 год (3 года, если оно произошло во время перевозки HazMat с табличками). Источник: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"43":{"q":"Если водитель CDL в Мэриленде совершает первое тяжкое правонарушение (например, DUI или BAC 0.04+) во время перевозки опасных материалов, требующих табличек, как долго длится дисквалификация?","options":["3 года","1 год","5 лет","Пожизненно"],"explanation":"Стандартная годичная дисквалификация за первое нарушение увеличивается до 3 лет, когда водитель в этот момент перевозил опасные материалы с табличками. Источник: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"44":{"q":"Какова дисквалификация CDL в Мэриленде за ВТОРОЕ тяжкое правонарушение (второй DUI, BAC 0.04+, отказ и т. д.), совершённое в отдельном эпизоде?","options":["Пожизненная дисквалификация","5 лет","3 года","2 года"],"explanation":"Второе тяжкое правонарушение приводит к пожизненной дисквалификации CDL, хотя восстановление может быть возможно по прошествии 10 лет в соответствующих случаях. Источник: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"45":{"q":"Использование CMV для совершения тяжкого преступления (felony), связанного с производством, распространением или сбытом контролируемого вещества, влечёт за собой какое наказание для CDL в Мэриленде?","options":["Пожизненную дисквалификацию без права восстановления через 10 лет","Дисквалификацию на 1 год","Дисквалификацию на 3 года","Пожизненную дисквалификацию, но с правом восстановления через 10 лет"],"explanation":"Тяжкое преступление (felony), связанное с производством, распространением или сбытом контролируемого вещества с использованием CMV, влечёт пожизненную дисквалификацию, которая НЕ подлежит восстановлению через 10 лет. Источник: 49 CFR 383.51 Table 1; Maryland Transportation Article §16-812."},"46":{"q":"Сколько серьёзных нарушений ПДД в течение 3-летнего периода влекут 60-дневную дисквалификацию CDL в Мэриленде?","options":["2 серьёзных нарушения","3 серьёзных нарушения","4 серьёзных нарушения","1 серьёзное нарушение"],"explanation":"Два серьёзных нарушения ПДД в течение 3 лет (в любом сочетании, в CMV) влекут 60-дневную дисквалификацию. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"47":{"q":"Три серьёзных нарушения ПДД в течение 3-летнего периода влекут какой срок дисквалификации CDL в Мэриленде?","options":["120 дней","60 дней","180 дней","1 год"],"explanation":"Три серьёзных нарушения ПДД в течение 3 лет дисквалифицируют CDL на 120 дней; это дополнительно к любой предыдущей 60-дневной дисквалификации. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"На сколько миль в час выше установленного ограничения должно быть превышение скорости, чтобы оно считалось «серьёзным нарушением ПДД» для целей CDL в Мэриленде?","options":["15 mph или более выше ограничения","10 mph или более выше ограничения","20 mph или более выше ограничения","25 mph или более выше ограничения"],"explanation":"Превышение скорости на 15 mph или более выше установленного ограничения является серьёзным нарушением ПДД, которое засчитывается в дисквалификации 2-за-3-года (60 дней) и 3-за-3-года (120 дней). Источник: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"49":{"q":"Что из перечисленного классифицируется как «серьёзное нарушение ПДД» для владельца CDL в Мэриленде?","options":["Безрассудное вождение (reckless driving)","Парковка в пожарном проезде","Перегоревший задний фонарь","Просроченная регистрационная наклейка"],"explanation":"Серьёзные нарушения ПДД включают безрассудное вождение, превышение скорости на 15+ mph, неправильную/беспорядочную смену полос, слишком близкое следование, отправку текстовых сообщений и использование телефона в руке. Обычные неисправности оборудования/проблемы с парковкой не являются серьёзными нарушениями. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"50":{"q":"В Мэриленде вождение CMV с отправкой текстовых сообщений в нарушение закона рассматривается как какой тип правонарушения для дисквалификации CDL?","options":["Серьёзное нарушение ПДД","Тяжкое правонарушение","Нарушение предписания о выводе из эксплуатации (out-of-service)","Нарушение на железнодорожном переезде"],"explanation":"Отправка текстовых сообщений во время вождения CMV является серьёзным нарушением ПДД, которое засчитывается в дисквалификации на 60 дней (2-за-3-года) и 120 дней (3-за-3-года). Мэриленд запрещает отправку текстовых сообщений по закону первичного контроля (primary-enforcement). Источник: Maryland Transportation Article §21-1124.1; 49 CFR 383.51 Table 2."},"51":{"q":"Согласно закону Мэриленда, взрослый водитель CMV, использующий ручной мобильный телефон во время движения транспортного средства, совершает какой вид правонарушения для CDL?","options":["Серьёзное нарушение ПДД","Незначительное несообщаемое правонарушение","Тяжкое правонарушение с дисквалификацией на 1 год","Нарушение предписания о выводе из эксплуатации (out-of-service)"],"explanation":"Использование ручного телефона во время вождения CMV является серьёзным нарушением ПДД, засчитываемым к порогам дисквалификации в 60/120 дней. Запрет Мэриленда на использование телефона в руке является правонарушением первичного контроля. Источник: Maryland Transportation Article §21-1124.2; 49 CFR 383.51 Table 2."},"52":{"q":"Какова минимальная дисквалификация CDL в Мэриленде за ПЕРВОЕ нарушение на железнодорожном переезде?","options":["Не менее 60 дней","Не менее 30 дней","Не менее 120 дней","Не менее 1 года"],"explanation":"Первое нарушение на железнодорожном переезде дисквалифицирует CDL не менее чем на 60 дней. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"53":{"q":"ВТОРОЕ нарушение на железнодорожном переезде в течение 3-летнего периода влечёт какую минимальную дисквалификацию CDL в Мэриленде?","options":["Не менее 120 дней","Не менее 60 дней","Не менее 1 года","Не менее 180 дней"],"explanation":"Второе нарушение на железнодорожном переезде в течение 3 лет дисквалифицирует CDL не менее чем на 120 дней. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"54":{"q":"ТРЕТЬЕ нарушение на железнодорожном переезде в течение 3-летнего периода влечёт какую минимальную дисквалификацию CDL в Мэриленде?","options":["Не менее 1 года","Не менее 120 дней","Не менее 180 дней","Пожизненно"],"explanation":"Третье (или последующее) нарушение на железнодорожном переезде в течение 3 лет дисквалифицирует CDL не менее чем на 1 год. Источник: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"Каков диапазон дисквалификации CDL в Мэриленде за ПЕРВОЕ осуждение за нарушение предписания о выводе из эксплуатации (out-of-service) при вождении CMV без HazMat?","options":["От 180 дней до 1 года","От 60 до 120 дней","От 1 до 3 лет","От 30 до 90 дней"],"explanation":"Первое нарушение предписания о выводе из эксплуатации (без HazMat, менее 16 пассажиров) дисквалифицирует CDL не менее чем на 180 дней и не более чем на 1 год. Источник: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"56":{"q":"ВТОРОЕ нарушение предписания о выводе из эксплуатации в течение любого 10-летнего периода (без HazMat) влечёт какой диапазон дисквалификации CDL в Мэриленде?","options":["От 2 до 5 лет","От 180 дней до 1 года","От 1 до 3 лет","Пожизненно"],"explanation":"Второе нарушение предписания о выводе из эксплуатации в течение 10 лет дисквалифицирует CDL не менее чем на 2 года и не более чем на 5 лет. Источник: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"57":{"q":"ПЕРВОЕ нарушение предписания о выводе из эксплуатации во время перевозки опасных материалов с табличками либо при управлении транспортным средством, рассчитанным на 16 или более пассажиров, влечёт какой диапазон дисквалификации CDL в Мэриленде?","options":["От 180 дней до 2 лет","От 180 дней до 1 года","От 2 до 5 лет","От 3 до 5 лет"],"explanation":"Первое нарушение предписания о выводе из эксплуатации, связанное с HazMat с табличками или транспортным средством на 16+ пассажиров, дисквалифицирует CDL не менее чем на 180 дней и не более чем на 2 года. Источник: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"58":{"q":"Когда Maryland MVA может начать дисквалификацию CDL, связанную с остановкой коммерческого транспорта при высоком BAC?","options":["По факту выписки штрафа/административного действия per se за высокий BAC в CMV, даже до осуждения","Только после уголовного осуждения в суде","Только после второго правонарушения","Только если водитель стал причиной ДТП"],"explanation":"Мэриленд может дисквалифицировать CDL на основании штрафа или административного предписания per se за высокий BAC во время вождения коммерческого транспортного средства, даже до какого-либо осуждения в суде. Источник: MDOT MVA CDL Disqualification & Reinstatement page; Maryland Transportation Article §16-205.1, §16-812."},"59":{"q":"После пожизненной дисквалификации CDL водитель в Мэриленде, как правило, может подать заявление на восстановление по прошествии скольких лет при условии соблюдения требований к праву на восстановление?","options":["10 лет","5 лет","3 года","Никогда — пожизненная дисквалификация постоянна во всех случаях"],"explanation":"Пожизненная дисквалификация CDL может быть сокращена минимум до 10 лет, если водитель соответствует требованиям к восстановлению, — за исключением таких правонарушений, как наркоторговля или торговля людьми с использованием CMV, которые не допускают восстановления. Источник: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"60":{"q":"Согласно закону Мэриленда «Move Over» («Уступи дорогу»), когда водитель с CDL приближается к остановившемуся аварийному автомобилю, эвакуатору или служебной машине с включёнными проблесковыми маячками, какое ПЕРВОЕ действие требует закон?","options":["Перестроиться в полосу, не примыкающую непосредственно к остановившемуся автомобилю, если это безопасно и разрешено законом","Полностью остановиться, пока сотрудник не даст указание продолжать движение","Непрерывно сигналить во время проезда мимо остановившегося автомобиля","Снизить скорость ровно на 20 mph ниже установленного ограничения и оставаться в своей полосе"],"explanation":"Статья 21-405.1 Транспортного кодекса Мэриленда (закон «Move Over») требует, чтобы водитель перестроился в полосу, не примыкающую непосредственно к остановившемуся автомобилю, когда это безопасно и разрешено законом. Только если перестроение небезопасно или невозможно, водитель обязан вместо этого снизить скорость до разумной и осмотрительной. Источник: Md. Code, Transportation 21-405.1; рекомендации Maryland MVA/MSP."},"61":{"q":"Если водитель с CDL в Мэриленде не может безопасно перестроиться при проезде мимо остановившегося аварийного или служебного автомобиля с включёнными маячками, что он должен сделать вместо этого?","options":["Снизить скорость до разумной и осмотрительной с учётом существующих условий","Полностью остановиться на обочине, пока место происшествия не будет освобождено","Сохранять установленное ограничение скорости и проехать, не меняя скорости","Выехать на разделительную полосу и подождать, пока движение в полосе не освободится"],"explanation":"Согласно Md. Transportation 21-405.1, если перестроение небезопасно или невозможно, водитель обязан снизить скорость до разумной и осмотрительной, безопасной для существующих условий. Закон Мэриленда не устанавливает единого фиксированного значения; он требует разумной скорости с учётом условий. Источник: Md. Code, Transportation 21-405.1."},"62":{"q":"В результате расширения, вступившего в силу 1 октября 2022 года, закон Мэриленда «Move Over» применяется к каким из следующих транспортных средств, остановившихся на обочине?","options":["К любому транспортному средству с включённой аварийной сигнализацией, предупреждающими конусами или дорожными сигнальными огнями, включая обычные легковые автомобили","Только к обозначенным полицейским и пожарным автомобилям с включёнными проблесковыми маячками","Только к эвакуаторам и автомобилям дорожного обслуживания","Только к коммерческим транспортным средствам массой свыше 26 001 фунта"],"explanation":"С 1 октября 2022 года Мэриленд расширил статью 21-405.1, и теперь обязанность «Move Over» применяется к ЛЮБОМУ остановившемуся транспортному средству с включённой аварийной сигнализацией, дорожными сигнальными огнями или предупреждающими конусами, а не только к аварийным или служебным автомобилям. Источник: Md. Code, Transportation 21-405.1 (поправка 2022 года); Maryland MVA."},"63":{"q":"Когда школьный автобус в Мэриленде остановился с мигающими красными огнями и выдвинутым знаком «Стоп» на двухполосной дороге без разделительной полосы, что должен сделать водитель с CDL, приближающийся с ЛЮБОГО направления?","options":["Остановиться и оставаться на месте, пока огни не перестанут мигать и автобус не тронется или не подаст сигнал к движению","Снизить скорость до 15 mph и осторожно проехать слева","Останавливаться только при движении в том же направлении, что и автобус","Продолжать движение, если рядом с автобусом не видно детей"],"explanation":"На дороге без разделительной полосы с двусторонним движением в Мэриленде транспорт в ОБОИХ направлениях должен остановиться перед школьным автобусом с мигающими красными огнями и выдвинутым знаком «Стоп» и оставаться на месте, пока сигналы не выключатся. Источник: Md. Code, Transportation 21-706; Maryland MVA/MSP."},"64":{"q":"Согласно исключению Мэриленда для разделённых автомагистралей, когда водители, движущиеся в ПРОТИВОПОЛОЖНОМ направлении от остановившегося школьного автобуса, НЕ обязаны останавливаться?","options":["Когда направления движения разделены физической разделительной полосой или барьером, таким как трава, грунт или бетонный разделитель","Когда дорога имеет четыре или более полос, независимо от наличия разделительной полосы","Когда направления движения разделены двойной жёлтой осевой линией","Когда автобус находится на расстоянии более 100 футов в полосах противоположного направления"],"explanation":"Мэриленд освобождает встречный транспорт от обязанности останавливаться ТОЛЬКО когда дороги разделены физической разделительной полосой, барьером или неасфальтированной полосой. Нанесённые линии НЕ создают разделённую автомагистраль, поэтому одна лишь двойная жёлтая линия не активирует исключение. Источник: Md. Code, Transportation 21-706; рекомендации Maryland MVA."},"65":{"q":"На разделённой автомагистрали в Мэриленде с физической разделительной полосой, кто всё равно должен остановиться, когда школьный автобус на противоположной стороне включает мигающие красные огни?","options":["Водители, движущиеся в том же направлении, что и автобус, позади него","Все водители на обеих проезжих частях должны остановиться","Никто из водителей не обязан останавливаться ни на одной разделённой автомагистрали","Только водители в полосе, непосредственно примыкающей к разделительной полосе"],"explanation":"Даже на разделённой автомагистрали транспорт, следующий за автобусом в ТОМ ЖЕ направлении, должен остановиться. Освобождается только встречный транспорт, отделённый физической разделительной полосой. Источник: Md. Code, Transportation 21-706."},"66":{"q":"Какое максимальное ограничение скорости может быть установлено на любой автомагистрали в Мэриленде, включая межштатные автомагистрали и скоростные шоссе?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"Закон Мэриленда ограничивает максимальную скорость значением 70 mph, которое может быть установлено только на определённых межштатных автомагистралях и скоростных шоссе; ни на одной автомагистрали Мэриленда не может быть установлено более 70 mph. Источник: Md. Code, Transportation 21-801.1; MDOT SHA."},"67":{"q":"Как Мэриленд устанавливает максимальное ограничение скорости для грузовиков и других коммерческих транспортных средств по сравнению с легковыми автомобилями на той же автомагистрали?","options":["Грузовики подчиняются тому же установленному максимуму, что и другие транспортные средства; в Мэриленде нет отдельного более низкого общештатного ограничения скорости для грузовиков","Грузовики ограничены 55 mph по всему штату независимо от установленного ограничения","Грузовики ограничены 10 mph ниже установленного ограничения на всех автомагистралях","Грузовики ограничены 65 mph, тогда как легковые автомобили могут двигаться 70 mph на каждой межштатной автомагистрали"],"explanation":"В отличие от некоторых штатов, Мэриленд НЕ устанавливает отдельного, более низкого общештатного ограничения скорости для грузовиков. Коммерческие транспортные средства подчиняются тем же установленным ограничениям, что и остальной транспорт (вплоть до предела в 70 mph). Источник: Md. Code, Transportation 21-801.1; рекомендации MDOT SHA по ограничениям скорости."},"68":{"q":"Какие коммерческие транспортные средства должны ОСТАНОВИТЬСЯ перед пересечением железнодорожных путей на одном уровне согласно правилам, которые Мэриленд применяет к водителям с CDL?","options":["Автобусы, перевозящие пассажиров, и транспортные средства, перевозящие опасные материалы с табличками","Все коммерческие транспортные средства массой свыше 10 000 фунтов","Только транспортные средства, тянущие сдвоенные или строенные прицепы","Только пустые цистерны, ранее перевозившие горючие вещества"],"explanation":"Мэриленд следует федеральному правилу (49 CFR 392.10), принятому в его руководстве CDL: автобусы, перевозящие пассажиров, и транспортные средства с табличками HazMat должны останавливаться на переездах в одном уровне. Большинство других грузовиков не обязаны останавливаться, если это не предписано знаками или сигналами. Источник: Maryland CDL Manual; 49 CFR 392.10."},"69":{"q":"Когда грузовик с табличками HazMat или пассажирский автобус обязан остановиться на железнодорожном переезде в Мэриленде, в пределах какого расстояния от ближайшего рельса он должен остановиться?","options":["Не ближе 15 футов и не дальше 50 футов от ближайшего рельса","Не ближе 5 футов и не дальше 25 футов от ближайшего рельса","Не ближе 25 футов и не дальше 75 футов от ближайшего рельса","Не ближе 10 футов и не дальше 100 футов от ближайшего рельса"],"explanation":"Коммерческие транспортные средства, обязанные останавливаться, должны остановиться в пределах 50 футов, но не ближе 15 футов к ближайшему рельсу, затем посмотреть и прислушаться, прежде чем продолжить движение. Источник: Maryland CDL Manual; 49 CFR 392.10."},"70":{"q":"После остановки на железнодорожном переезде водитель автобуса или транспорта с табличками HazMat в Мэриленде может продолжить движение только после чего?","options":["Посмотрев и прислушавшись в обоих направлениях в поисках приближающегося поезда и убедившись, что переезд можно пересечь без остановки","Переключив передачу хотя бы один раз при пересечении путей для сохранения инерции движения","Подождав обязательные 30 секунд независимо от того, приближается ли поезд","Подав звуковой сигнал три раза перед въездом на переезд"],"explanation":"После остановки в зоне от 15 до 50 футов водитель должен посмотреть и прислушаться в обе стороны в поисках поезда и не должен начинать пересечение, если нет возможности полностью освободить пути без остановки. Водителям не следует переключать передачи, находясь на путях. Источник: Maryland CDL Manual; 49 CFR 392.10."},"71":{"q":"Когда водитель с CDL в Мэриленде вынужден остановить грузовик на проезжей части или обочине автомагистрали, в течение скольких минут должны быть установлены предупреждающие устройства (светоотражающие треугольники)?","options":["В течение 10 минут после остановки","В течение 5 минут после остановки","В течение 15 минут после остановки","В течение 30 минут после остановки"],"explanation":"Водитель остановившегося коммерческого транспортного средства должен установить предупреждающие устройства в течение 10 минут. Этот федеральный стандарт изложен в Maryland CDL Manual и применяется в Мэриленде. Источник: Maryland CDL Manual; 49 CFR 392.22."},"72":{"q":"На двухполосной дороге с двусторонним движением, где водитель с CDL в Мэриленде должен разместить три обязательных предупреждающих треугольника для остановившегося грузовика?","options":["Примерно в 10 футах позади автомобиля со стороны движения, примерно в 100 футах позади и примерно в 100 футах впереди автомобиля","Все три треугольника в 200 футах позади автомобиля в ряд","Примерно в 50 футах, 150 футах и 250 футах только позади автомобиля","Один на капоте и два на крыше для максимальной видимости"],"explanation":"На дороге с двусторонним движением разместите один треугольник примерно в 10 футах позади со стороны движения, один примерно в 100 футах сзади и один примерно в 100 футах спереди, чтобы транспорт с обоих направлений был предупреждён. Источник: Maryland CDL Manual; 49 CFR 392.22."},"73":{"q":"На дороге с односторонним движением или разделённой автомагистрали, как водитель с CDL в Мэриленде должен расположить три предупреждающих треугольника позади остановившегося грузовика?","options":["Примерно в 10 футах, 100 футах и 200 футах в сторону приближающегося транспорта","Примерно в 10 футах, 50 футах и 100 футах в сторону приближающегося транспорта","Примерно в 25 футах, 75 футах и 150 футах в сторону приближающегося транспорта","Примерно в 50 футах, 100 футах и 500 футах в сторону приближающегося транспорта"],"explanation":"На дороге с односторонним движением или разделённой автомагистрали три треугольника размещаются в сторону приближающегося транспорта примерно в 10, 100 и 200 футах от автомобиля. Источник: Maryland CDL Manual; 49 CFR 392.22."},"74":{"q":"Закон Мэриленда о движении по правой стороне требует, чтобы медленное транспортное средство использовало правую полосу. Транспортное средство, движущееся на сколько ниже максимального ограничения скорости, должно держаться правее (кроме случаев обгона или поворота налево)?","options":["На 10 mph или более ниже применимого максимального ограничения скорости","На 5 mph или более ниже применимого максимального ограничения скорости","На 15 mph или более ниже применимого максимального ограничения скорости","На 20 mph или более ниже применимого максимального ограничения скорости"],"explanation":"Md. Transportation 21-301 требует, чтобы любое транспортное средство, движущееся на 10 mph или более ниже максимального ограничения (или медленнее обычного транспортного потока, когда того требуют условия), держалось правой полосы, кроме случаев обгона или подготовки к повороту налево. Источник: Md. Code, Transportation 21-301."},"75":{"q":"На дороге Мэриленда с двумя или более полосами в одном направлении, что определяет, какую полосу должен использовать грузовик, седельный тягач, прицеп или автобус?","options":["Указания любого средства регулирования дорожного движения, требующего, чтобы транспортное средство двигалось по определённой полосе","Предпочтение водителя, поскольку знаки полос не применяются к коммерческим транспортным средствам","Фиксированное правило, согласно которому все грузовики должны использовать только крайнюю левую полосу","Та полоса, в которой в данный момент меньше всего легковых автомобилей"],"explanation":"Закон Мэриленда (Transportation 21-301 и связанные правила использования полос) требует, чтобы грузовики, седельные тягачи, прицепы и автобусы подчинялись средствам регулирования дорожного движения, обозначающим для них определённые полосы. Источник: Md. Code, Transportation 21-301; 21-309."},"76":{"q":"Почему коммерческим грузовикам, как правило, запрещено движение по Балтимор-Вашингтон-Паркуэй (участок MD 295, находящийся в ведении Службы национальных парков)?","options":["Это федеральный паркуэй, на котором запрещены коммерческие транспортные средства; грузовики должны использовать I-95 или другие маршруты для грузовиков, если у них нет специального разрешения","Покрытие слишком узкое для любого транспортного средства шире легкового автомобиля","Это платная дорога, которая не принимает коммерческие транспондеры","По нему разрешено движение грузовиков только с полуночи до 5 утра"],"explanation":"Балтимор-Вашингтон-Паркуэй, находящийся в ведении NPS, запрещает движение коммерческих транспортных средств; для грузовиков установлены запрещающие знаки, и они должны использовать I-95 или другие назначенные маршруты для грузовиков. Жилым автофургонам и автобусам движение, как правило, разрешено, но коммерческим грузовикам — нет без разрешения. Источник: правила паркуэев Службы национальных парков; рекомендации Мэриленда по маршрутам для грузовиков."},"77":{"q":"Какие классы грузов запрещены к провозу через туннель Форт-Макгенри (I-95) и Балтиморский гаванский туннель (I-895) в Мэриленде?","options":["Взрывчатые вещества, бензин наливом и легковоспламеняющиеся жидкости, а также пропан в баллонах сверх разрешённых пределов, среди прочих опасных материалов","Рефрижераторные грузы с продуктами и живые животные","Любой груз массой брутто более 40 000 фунтов","Все грузы, перевозимые в сдвоенных или строенных прицепах, независимо от содержимого"],"explanation":"MDTA запрещает провоз взрывчатых веществ, бензина/легковоспламеняющихся жидкостей наливом, определённых радиоактивных материалов и пропана в баллонах сверх разрешённого предела (более 10 фунтов на контейнер) через туннели Форт-Макгенри и Балтиморский гаванский. Источник: список запрещённых опасных материалов MDTA; mdta.maryland.gov."},"78":{"q":"Водитель с CDL в Мэриленде, перевозящий HazMat с табличками, провоз которого запрещён через балтиморские туннели, каким маршрутом должен следовать через район Балтимора?","options":["Западный участок I-695 (внешняя кольцевая дорога) в обход гаванских переправ","Прямо через туннель Форт-Макгенри по I-95 в часы низкой загрузки","Через Балтиморский гаванский туннель по I-895 с включённой аварийной сигнализацией","По любой городской улице через центр Балтимора, избегая платных участков"],"explanation":"Грузы HazMat, которым запрещён проезд через туннели, должны объезжать гавань по западному участку I-695. Этот маршрут стал ещё важнее после того, как мост Ки-Бридж (юго-восточная переправа I-695) обрушился в 2024 году. Источник: рекомендации MDTA по ограничениям/разрешениям в туннелях; mdta.maryland.gov."},"79":{"q":"На крутых горных уклонах I-68 в западном Мэриленде (около Сайдлинг-Хилл и Биг-Сэвидж-Маунтин) какое средство безопасности предусмотрено для грузовиков, потерявших тормоза на длинном спуске?","options":["Аварийные съезды для грузовиков (улавливающие тупики), которые используют подъём и тормозящий материал для остановки транспортного средства","Обязательные туннели, заставляющие грузовики снижать скорость перед спуском","Реверсивные платные полосы, которые открываются только для неисправных грузовиков","Подогреваемые полосы покрытия, повышающие сцепление шин на уклоне"],"explanation":"I-68 через западный Мэриленд имеет крутые длинные уклоны; аварийные съезды для грузовиков (улавливающие тупики из гравия/песка на подъёме) предусмотрены, чтобы грузовики с отказавшими или перегретыми тормозами могли безопасно остановиться. Водителям следует спускаться на пониженной передаче и использовать правильную технику торможения. Источник: MDOT SHA; раздел Maryland CDL Manual о вождении в горах."},"80":{"q":"Какое ведомство Мэриленда выдаёт коммерческие водительские удостоверения (CDL)?","options":["Администрация транспортных средств MDOT (MVA)","Отдел коммерческого транспорта полиции штата Мэриленд","Федеральное управление по безопасности автомобильных перевозчиков (FMCSA)","Департамент труда Мэриленда"],"explanation":"CDL в Мэриленде выдаются Администрацией транспортных средств MDOT (MVA). FMCSA устанавливает федеральные стандарты CDL, но не выдаёт само удостоверение. Источник: Maryland MVA, страницы Commercial Driver's License."},"81":{"q":"Прежде чем записаться на экзамен по навыкам вождения (дорожный) для CDL в Мэриленде, как долго вы должны были владеть своим коммерческим ученическим разрешением (CLP)?","options":["Не менее 14 days","Не менее 7 days","Не менее 30 days","Не менее 60 days"],"explanation":"Мэриленд следует федеральному правилу: владелец CLP не имеет права сдавать экзамен по навыкам CDL ранее, чем через 14 days после выдачи CLP. Источник: Maryland MVA, Get or Renew a CDL."},"82":{"q":"Какое обучение должно быть пройдено, прежде чем заявитель в Мэриленде сможет сдать экзамен по навыкам CDL для первого удостоверения класса A или класса B?","options":["Обучение водителей начального уровня (ELDT)","Утверждённый штатом курс безопасного вождения","Семинар FMCSA по опасным материалам","40-часовой ознакомительный курс MVA в классе"],"explanation":"Мэриленд не допустит вас к экзамену по навыкам, пока вы не пройдёте обязательное по федеральным нормам обучение водителей начального уровня (ELDT), требуемое для первого CDL класса A или B и для первых endorsements P, S или H. Источник: Maryland MVA / правило ELDT FMCSA."},"83":{"q":"Экзамен по навыкам CDL в Мэриленде состоит из трёх частей, которые должны быть сданы. Какие это части?","options":["Предрейсовый осмотр транспортного средства, базовые навыки управления транспортным средством и вождение на дороге","Письменный тест на знания, проверка зрения и вождение на дороге","Тест на пневматические тормоза, тест на движение задним ходом и ночное вождение","Предрейсовый осмотр, обращение с опасными материалами и вождение на дороге"],"explanation":"Экзамен по навыкам CDL в Мэриленде состоит из предрейсового осмотра транспортного средства, базовых навыков управления транспортным средством и дорожного экзамена по вождению, и все три части должны быть успешно завершены. Источник: Maryland MVA, CDL Skills Test."},"84":{"q":"Согласно самосертификации CDL в Мэриленде, сколько категорий коммерческой эксплуатации транспортных средств может заявить заявитель?","options":["Четыре","Две","Три","Пять"],"explanation":"Владельцы CDL в Мэриленде самостоятельно сертифицируются в одной из четырёх категорий: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: Maryland MVA, CDL Medical Certification Requirements."},"85":{"q":"Водитель в Мэриленде сертифицируется как «Non-Excepted Interstate (NI)». Что это означает?","options":["Он ездит через границы штатов и должен соответствовать всем федеральным требованиям медицинской квалификации","Он ездит только в пределах Мэриленда и освобождён от федеральных медицинских правил","Он ездит через границы штатов только для определённых исключённых видов деятельности","Он ездит только в пределах Мэриленда, используя утверждённое MVA медицинское освобождение"],"explanation":"Non-Excepted Interstate (NI) означает, что водитель эксплуатирует CMV через границы штатов и соблюдает все федеральные квалификационные требования (включая медицинские). Источник: Maryland MVA, CDL Medical Certification Requirements."},"86":{"q":"Как медицинская справка DOT (DOT Medical Examiner's Certificate) владельца CDL в Мэриленде обычно попадает в MVA?","options":["Медицинский эксперт подаёт её в электронном виде в Национальный реестр FMCSA, и MVA получает её автоматически","Водитель должен отправить бумажную справку в штаб-квартиру MVA по почте в течение 10 дней","Работодатель водителя отправляет её в MVA по факсу от имени водителя","Справка загружается только при личном продлении CDL водителем"],"explanation":"Сертифицированный медицинский эксперт направляет информацию о справке в электронном виде в Национальный реестр FMCSA, и MVA получает медицинскую сертификацию автоматически; водителю не нужно отправлять или подавать её. Источник: Maryland MVA, CDL Medical Certification Requirements."},"87":{"q":"Что происходит с коммерческими правами водителя в Мэриленде, если его медицинская сертификация DOT истекает?","options":["Его CDL понижается, и он больше не имеет права управлять CMV","В течение 90 дней ничего не меняется, пока он продолжает ездить в пределах штата","Его полное водительское удостоверение, включая базовый класс, немедленно приостанавливается","MVA выдаёт автоматическое временное медицинское освобождение"],"explanation":"Если медицинская сертификация истекает, водитель более не имеет законного права управлять CMV, и коммерческие права на вождение понижаются. Источник: Maryland MVA, CDL Medical Certification Requirements."},"88":{"q":"Какой набор документов должен предоставить заявитель на CDL в Мэриленде в MVA?","options":["Подтверждение личности, возраста, номера социального страхования и проживания в Мэриленде","Только действующий паспорт и счёт за коммунальные услуги","Только подтверждение личности и нотариально заверенное письмо от работодателя","Только свидетельство о рождении и подтверждение страховки транспортного средства"],"explanation":"Заявители на CDL в Мэриленде должны предъявить подтверждение личности, возраста, номера социального страхования и проживания в Мэриленде. Источник: Maryland MVA, Get or Renew a CDL."},"89":{"q":"Самосертификация типа вождения требуется в Мэриленде во всех следующих ситуациях, КРОМЕ какой?","options":["Каждый раз при продлении ежегодной регистрации транспортного средства","При получении нового CDL","При продлении или повышении класса CDL","При переключении между междуштатным и внутриштатным вождением"],"explanation":"Самосертификация требуется при получении, продлении, переоформлении или повышении класса CDL, при изменении медицинского статуса или при переключении между междуштатным и внутриштатным вождением — но не для обычной регистрации транспортного средства. Источник: Maryland MVA, CDL Medical Certification Requirements."},"90":{"q":"Какая категория описывает владельца CDL в Мэриленде, который управляет CMV только в пределах Мэриленда и имеет утверждённое MVA медицинское освобождение CDL (CDL Medical Waiver)?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA) применяется к водителю, имеющему квалификацию для эксплуатации только в пределах Мэриленда и обладающему утверждённым MVA медицинским освобождением CDL. Источник: Maryland MVA, CDL Medical Certification Requirements."},"91":{"q":"Какой тест на знания первым должен сдать каждый заявитель на CDL в Мэриленде, независимо от endorsements?","options":["Тест на общие знания (General Knowledge)","Тест на опасные материалы (Hazardous Materials)","Тест на пневматические тормоза (Air Brakes)","Тест на составные транспортные средства (Combination Vehicles)"],"explanation":"Все заявители на CDL в Мэриленде должны сначала сдать тест на общие знания CDL; тесты по конкретным endorsements (P, S, N, H, T) сдаются дополнительно по мере необходимости. Источник: Maryland MVA / CDL Manual (DL-151)."},"92":{"q":"Где заявитель в Мэриленде сдаёт тесты на знания CDL (письменные)?","options":["В электронном виде в офисах MVA по всему Мэриленду","Только по почте бумажным экзаменом в штаб-квартиру MVA","В любом федеральном тестовом центре FMCSA","Онлайн из дома через любой утверждённый сторонний веб-сайт"],"explanation":"Тесты на знания CDL проводятся в электронном виде в офисах MVA по всему Мэриленду. Источник: Maryland MVA, Knowledge Tests / Prepare for a Driver's License Test."},"93":{"q":"Каков типичный цикл продления (срок действия) стандартного водительского удостоверения и CDL в Мэриленде?","options":["8 лет","4 года","5 лет","10 лет"],"explanation":"Водительские удостоверения в Мэриленде, включая CDL, обычно выдаются/продлеваются на срок 8 лет. Источник: Maryland MVA, Renew a License or ID."},"94":{"q":"На экзамене по навыкам CDL в Мэриленде в каком порядке обычно проводятся три компонента?","options":["Предрейсовый осмотр, затем базовые навыки управления, затем вождение на дороге","Вождение на дороге, затем предрейсовый осмотр, затем базовые навыки управления","Базовые навыки управления, затем вождение на дороге, затем предрейсовый осмотр","Вождение на дороге, затем базовые навыки управления, затем предрейсовый осмотр"],"explanation":"Мэриленд проводит экзамен по навыкам в следующей последовательности: сначала предрейсовый осмотр транспортного средства, затем базовые навыки управления транспортным средством, затем дорожный экзамен по вождению. Источник: Maryland MVA, CDL Skills Test."},"95":{"q":"Если владелец CDL в Мэриленде допустил истечение медицинской сертификации и прошло более одного года, что он должен сделать, чтобы восстановить CDL?","options":["Пересдать все тесты на знания и навыки CDL","Просто подать новую медицинскую справку без тестирования","Оплатить сбор за восстановление, но не сдавать тесты","Только выждать обязательную 90-дневную приостановку"],"explanation":"Если CDL понижен из-за истёкшей медицинской справки и прошло более одного года, водитель должен пересдать все тесты на знания и навыки CDL, чтобы вернуть CDL. Источник: Maryland MVA, CDL Medical Certification Requirements."},"96":{"q":"Какая категория подходит для владельца CDL в Мэриленде, который пересекает границы штатов только для перевозки школьников, больных или травмированных лиц либо тел умерших?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Excepted Interstate (EI) охватывает водителей, которые эксплуатируют транспорт через границы штатов только для определённых исключённых видов деятельности, таких как перевозка школьников или персонала, больных или травмированных лиц либо тел умерших. Источник: Maryland MVA, CDL Medical Certification Requirements."},"97":{"q":"Какой сценарий сам по себе НЕ активирует федеральное требование ELDT перед экзаменом по навыкам в Мэриленде?","options":["Продление существующего CDL класса A с теми же endorsements","Подача заявления на первый CDL класса A","Повышение с класса B до класса A CDL","Получение первого endorsement на перевозку пассажиров (P) или школьного автобуса (S)"],"explanation":"ELDT требуется для первого CDL класса A или B, для повышения с класса B до класса A и для первого endorsement P, S или H — но обычное продление существующего CDL само по себе не активирует ELDT. Источник: Maryland MVA / правило ELDT FMCSA."},"98":{"q":"Как обычно назначается запись на экзамен по навыкам (дорожный) для CDL в Мэриленде?","options":["Путём записи через аккаунт myMVA заявителя","Путём прихода в любое отделение MVA без записи","Путём звонка на национальную линию записи FMCSA","Автоматически в тот же день, когда выдан CLP"],"explanation":"Заявители записываются на экзамен по навыкам CDL через свой аккаунт myMVA; экзамен проводится MVA после соблюдения срока ожидания CLP и прохождения ELDT. Источник: Maryland MVA, CDL Skills Test."}},"tr":{"0":{"q":"Maryland karayollarında, fazla boyut izni (oversize permit) gerekmeden önce bir aracın yasal azami genişliği (aynalar ve diğer güvenlik/enerji cihazları hariç) nedir?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Maryland Transportation Article § 24-102, azami araç genişliğini 102 inches (8 feet 6 inches) olarak belirler; genişlik aynalar, işaret/sinyal lambaları ve enerji koruma cihazları hariç ölçülür. Bundan daha geniş olan herhangi bir şey için bir SHA fazla boyut izni gereklidir. Kaynak: Md. Transp. § 24-102; MD SHA Oversize/Overweight Hauling Permit Manual."},"1":{"q":"Maryland karayollarında bir aracın ve yükünün izin gerektirmeden ulaşabileceği yasal azami yükseklik nedir?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"Maryland Transportation Article § 24-104 uyarınca, bir aracın ve yükünün yüksekliği 13 feet 6 inches değerini aşamaz. SHA izin kılavuzu, herhangi bir özel koşul olmaksızın yasal sınır olarak 13'6\" değerini listeler. Kaynak: Md. Transp. § 24-104; MD SHA Hauling Permit Manual (Height section)."},"2":{"q":"Maryland'in Eyaletlerarası (Interstate) otoyollarında, fazla ağırlık izni olmadan izin verilen azami brüt araç ağırlığı nedir?","options":["73,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"explanation":"Maryland, federal Eyaletlerarası standardını izler: azami brüt ağırlık (yük dahil) 80,000 pounds'tur. Kaynak: Md. Transp. § 24-109; Maryland Eyaletlerarası yollarında uygulandığı şekliyle 23 CFR 658.17."},"3":{"q":"Maryland Eyaletlerarası (Interstate) yollarında, tek bir aksta izin verilen azami ağırlık nedir?","options":["17,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"Maryland'in Eyaletlerarası sistemindeki tek aks sınırı, Maryland Transportation Article § 24-109'daki federal standarda uygun olarak 20,000 pounds'tur. Kaynak: Md. Transp. § 24-109; 23 CFR 658.17."},"4":{"q":"Maryland Eyaletlerarası (Interstate) yollarında, bir tandem aksta izin verilen azami ağırlık nedir?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"Tandem aks (birbirinden 40 inch'ten fazla ancak 96 inch'ten fazla olmamak üzere aralıklı iki akslı grup) sınırı, federal Eyaletlerarası standardıyla tutarlı olarak Maryland Transportation Article § 24-109 uyarınca 34,000 pounds'tur. Kaynak: Md. Transp. § 24-109; 23 CFR 658.17."},"5":{"q":"Eyalet tarafından bakımı yapılan yollarda seyahat için fazla boyut/fazla ağırlık taşıma izinlerini hangi Maryland kurum ofisi düzenler?","options":["Motor Vehicle Administration (MVA) Sürücü Belgelendirme Birimi","SHA Office of Traffic and Safety, Motor Carrier Division, Hauling Permits Unit","Maryland State Police Ticari Araç Denetim Bölümü","Maryland Transportation Authority Ücretli Geçiş Tesisleri Ofisi"],"explanation":"Fazla boyut/fazla ağırlık (OS/OW) taşıma izinleri, Maryland State Highway Administration, Office of Traffic and Safety, Motor Carrier Division – Hauling Permits Unit (Hanover, MD) tarafından düzenlenir. Kaynak: MD SHA Oversize/Overweight Hauling Permit Manual (Introduction)."},"6":{"q":"Bir yük daha fazla azaltılamaz ancak yine de Maryland'in yasal sınırlarını aşmaktadır. Özel taşıma izni ihtiyacını tetikleyen yasal boyut ve ağırlık sınırlarını hangi yasa bölümleri belirler?","options":["Transportation Article, Title 16, Sections 101 and 102","Transportation Article, Title 24, Sections 108 and 109","Transportation Article, Title 21, Sections 1101 and 1102","Transportation Article, Title 11, Sections 301 and 302"],"explanation":"SHA izin kılavuzu, bir yük Maryland Motor Vehicle Law'da belirlenen yasal sınırları aştığında, Title 24, Sections 108 (aks yükleri) ve 109 (brüt ağırlık) uyarınca bir Özel Taşıma İzni satın alınması gerektiğini belirtir. Kaynak: MD SHA Hauling Permit Manual; Md. Transp. §§ 24-108, 24-109."},"7":{"q":"Maryland'in National Network ve belirlenmiş kamyon güzergahlarında, izin gerektirmeyen bir yarı römorkun (semitrailer) azami uzunluğu nedir?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"National Network ve belirlenmiş kamyon güzergahlarında, 53 feet'e kadar yarı römorklara izin olmadan izin verilir (48 feet birçok diğer eyalet karayolunda geçerlidir). Kaynak: Md. Transp. § 24-104.1/24-104.2; J.J. Keller Maryland boyut/ağırlık özeti."},"8":{"q":"Maryland, National Network üzerinde bir çekici-yarı römork kombinasyonunun toplam uzunluğuna sabit bir sınır uygulamaz, ancak herhangi bir aks grubundaki ağırlık yine de hangi hesaplama ile sınırlandırılır?","options":["Federal Köprü Formülü (Bridge Gross Weight Table)","Yalnızca üreticinin brüt aks ağırlık derecesi","Lastik genişliğinin her inç'i için sabit 1,000 pounds","Tescilli boş ağırlığın iki katı"],"explanation":"Maryland, Eyaletlerarası/National Network üzerinde Federal Köprü Formülü'nü uygular: birbirini izleyen herhangi bir aks grubundaki azami ağırlık, genel 80,000-pound üst sınırına kadar köprü formülü ile düzenlenir. Kaynak: Md. Transp. § 24-109; 23 CFR 658.17 Federal Bridge Formula."},"9":{"q":"Bir kombinasyon araç Maryland'in yasal ağırlığını aşmaktadır. Rutin bir SHA fazla ağırlık taşıma izni, hangi brüt ağırlığa kadar ve hangi yollarda seyahate izin verebilir?","options":["Herhangi bir eyalet karayolunda 100,000 pounds'a kadar","Herhangi bir eyalet yolunda 120,000 pounds'a kadar","Yalnızca Eyaletlerarası güzergahlarda 150,000 pounds'a kadar","Yalnızca Capital Beltway üzerinde 200,000 pounds'a kadar"],"explanation":"SHA kılavuzu, aks ağırlığı/aralık kuralları karşılandığı takdirde, kombinasyon araç izin yüklerinin 150,000 pounds'a kadar (ancak aşmayacak şekilde) yalnızca Eyaletlerarası güzergahlarda (Office of Bridge Development'a başvurmadan) izin verildiğini belirtir. Kaynak: MD SHA Hauling Permit Manual (Weight, 'Over 60 Tons')."},"10":{"q":"Maryland SHA ücret cetveline göre, birleşik yük 90,000 pounds (45 tons) veya daha az ağırlığında olduğunda taşıma izni için temel ücret nedir?","options":["$10.00","$30.00","$50.00","$100.00"],"explanation":"SHA kılavuzu, fazla boyutlu/birleşik bir yük 90,000 pounds'tan az ağırlıkta olduğunda taşıma izni için $30.00 temel ücret belirler; 45 tons (90,000 lb) üzerindeki yükler her ek ton için $5.00 ekler. Kaynak: MD SHA Hauling Permit Manual (General Information; Permit Fees)."},"11":{"q":"45 tons'u (90,000 pounds) aşan izinli bir yük için, Maryland SHA her ek ton için izin ücretine ne kadar ekler?","options":["$2.00 per ton","$5.00 per ton","$10.00 per ton","$25.00 per ton"],"explanation":"Kılavuz, 45 tons'u (90,000 lb) aşan yükler için her ek ton başına ek $5.00 ücret alındığını belirtir (örneğin, 50 tons = $55.00). Kaynak: MD SHA Hauling Permit Manual (General Information; Permit Fees schedule)."},"12":{"q":"Maryland'in genel hareket saatleri kurallarına göre, izinli bir fazla boyut/fazla ağırlık yükü NE ZAMAN hareket ettirilemez?","options":["Yalnızca hafta içi gece yarısı ile sabah 6:00 a.m. arasında","Herhangi bir Cumartesi öğlen 12:00 noon'dan sonra ve tüm gün Pazar","Yalnızca her ayın ilk Pazartesi günü","Yalnızca Baltimore'da ilan edilen yoğun saatler boyunca"],"explanation":"SHA kılavuzu ve COMAR Title 11 uyarınca, herhangi bir izin yükü, herhangi bir Cumartesi öğlen 12:00 noon'dan sonra, herhangi bir Pazar günü veya listelenen tatil dönemlerinde hareket ettirilemez. Aksi takdirde gündüz hareketi (gün doğumundan 1/2 saat sonrasından gün batımından 1/2 saat öncesine kadar) kuraldır. Kaynak: MD SHA Hauling Permit Manual (Hours of Movement); COMAR 11.04."},"13":{"q":"Maryland'de izinli bir yük (mobil/modüler ev dışında) hangi genişlikte ilk olarak tek bir özel refakat aracı (private escort) gerektirir?","options":["10 feet'ten geniş","12 feet'ten geniş","13 feet'ten geniş","14 feet'ten geniş"],"explanation":"SHA kılavuzu, 13 feet'ten geniş yükler için bir özel refakat aracı gerektirir (13'1\"–13'11\" aralığındaki yükler 1 özel refakat aracı gerektirir), 14 feet veya daha geniş olduğunda iki özel refakat aracı gereklidir. Kaynak: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)."},"14":{"q":"Maryland'de, 14 feet veya daha geniş olan izinli bir yük kaç özel refakat aracı (private escort) gerektirir?","options":["Refakat aracı gerekmez","Bir özel refakat aracı","İki özel refakat aracı","Dört özel refakat aracı"],"explanation":"SHA kılavuzu, 14 feet veya daha geniş tüm yüklerin Maryland'e ve Maryland içinden hareket etmek için iki özel refakat aracı gerektirdiğini belirtir. Kaynak: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)."},"15":{"q":"Hangi boyut veya ağırlık, Maryland'de izinli bir yükü Eyaletlerarası (Interstate) otoyollarda 'Süper Yük' (Super Load) yapar?","options":["90,000 pounds brüt veya 11 feet genişliğin üzerinde","150,000 pounds'u (75 tons) veya herhangi bir akstaki 27,000 pounds'u aşan","80,000 pounds'u veya 12 feet yüksekliği aşan","Tek bir özel refakat aracı gerektiren herhangi bir yük"],"explanation":"SHA kılavuzu Süper Yükleri, diğerlerinin yanı sıra, Eyaletlerarası otoyollarda 150,000 lb'yi (75 tons) veya herhangi bir akstaki 27,000 lb'yi aşan (ya da Maryland eyalet karayollarında 120,000 lb / 60 tons veya aks başına 27,000 lb'yi aşan) ya da 120 ft uzunluğunda, 16 ft genişliğinde veya 16 ft yüksekliğinde olanlar olarak tanımlar. Kaynak: MD SHA Hauling Permit Manual (Escorts – General Conditions, Super Loads)."},"16":{"q":"Maryland EYALET (Eyaletlerarası olmayan) karayollarında, hangi brüt ağırlığın aşılması izinli bir yükü aşırı bir 'Süper Yük' (Super Load) olarak sınıflandırır?","options":["80,000 pounds (40 tons)","100,000 pounds (50 tons)","120,000 pounds (60 tons)","150,000 pounds (75 tons)"],"explanation":"SHA kılavuzu, bir yükü Maryland eyalet karayollarında 120,000 pounds'u (60 tons) aştığında veya herhangi bir akstaki 27,000 pounds'u aştığında Süper Yük olarak sınıflandırır. 150,000-pound (75-ton) eşiği Eyaletlerarası otoyollar için geçerlidir. Kaynak: MD SHA Hauling Permit Manual (Super Loads)."},"17":{"q":"Eyaletlerarası (Interstate) otoyollar hariç, Maryland yasası, listelenen hasat dönemlerinde bir tarladan tarım ürünleri taşıyan bir çiftlik aracına hangi aks yükü toleransını tanır?","options":["%5 aks yükü toleransı","%10 aks yükü toleransı","%15 aks yükü toleransı","Hiçbir zaman tolerans tanınmaz"],"explanation":"Maryland Transportation Article § 24-109, çiftlik araçlarına (Eyaletlerarası dışında) normalde %5 aks toleransı tanır, bu tolerans tanımlı hasat dönemlerinde (örneğin buğday için 1 Haziran–15 Ağustos, mısır için 1 Temmuz–1 Aralık) %15 aks yükü toleransına yükseltilir; tarladan 100 mil mesafe içinde %5 brüt ağırlık toleransı ile birlikte. Kaynak: Md. Transp. § 24-109 (hasat zamanı tarımsal istisna)."},"18":{"q":"Eyaletlerarası (Interstate) otoyollar hariç, bir ormandan orman ürünleri taşıyan bir kombinasyon araç (yarı römork 45 feet veya daha az), 1 Haziran'dan 30 Eylül'e kadar hangi aks yükü toleransına izinlidir?","options":["%5 aks yükü toleransı","%10 aks yükü toleransı","%15 aks yükü toleransı","%20 aks yükü toleransı"],"explanation":"Maryland Transportation Article § 24-109, bir orman ürünleri kombinasyonuna (yarı römork 45 ft veya daha az, karayolu dışında yüklenmiş, Eyaletlerarası yollarda değil) %5 aks toleransı tanır, bu tolerans 1 Haziran'dan 30 Eylül'e kadar %15'e yükseltilir. Kaynak: Md. Transp. § 24-109 (orman ürünleri istisnası)."},"19":{"q":"Maryland (federal yasayı izleyerek), brüt/aks/köprü formülü sınırlarını ihlal etmeden ağır bir araca hangi yakıt tasarrufu cihazının ağırlığını telafi etmek için küçük bir ek ağırlık ödeneği tanır?","options":["Otomatik lastik şişirme sistemi, 1,000 pounds'a kadar ek","Yardımcı güç ünitesi / rölanti azaltma teknolojisi, 550 pounds'a kadar ek","Soğutma ünitesi, 2,000 pounds'a kadar ek","Geniş tabanlı tek lastik, 250 pounds'a kadar ek"],"explanation":"Maryland Transportation Article § 24-109, federal yasayla tutarlı olarak, bir yardımcı güç ünitesi veya rölanti azaltma teknolojisi ünitesini hesaba katmak üzere brüt, aks, tandem veya köprü formülü ağırlığında toplam 550 pounds'a kadar ek ağırlığa izin verir. Kaynak: Md. Transp. § 24-109 (rölanti azaltma ödeneği); 23 CFR 658.17."},"20":{"q":"Maryland'de, 26,001 pounds veya daha fazla Brüt Kombinasyon Ağırlık Derecesine (GCWR) sahip, çekilen ünitenin GVWR'si 10,000 pounds'un üzerinde olan bir kombinasyon aracı kullanmak için hangi CDL sınıfı gereklidir?","options":["Class A","Class B","Class C","Class D"],"explanation":"Maryland, Class A CDL'yi, çekilen ünitenin GVWR'si 10,000 pounds'un üzerinde olmak üzere, 26,001+ pounds GCWR'ye sahip bir çekici/güç ünitesi ve römork(lar)dan oluşan bir kombinasyon aracı olarak tanımlar. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"21":{"q":"Maryland MVA kurallarına göre, 26,001 pounds veya daha fazla GVWR'ye sahip herhangi bir tek aracı (10,000 pounds'u aşmayan bir ünite çekerek) kullanmaya hangi CDL sınıfı yetki verir?","options":["Class A","Class B","Class C","Class M"],"explanation":"Maryland Class B CDL, 26,001+ pounds GVWR'ye sahip tek araçları veya 10,000 pounds GVWR'yi aşmayan bir ünite çeken böyle bir aracı kapsar. Örnekler arasında düz kasalı kamyonlar ve çoğu otobüs bulunur. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"22":{"q":"Bir Maryland aracı 26,001 pounds'un altında derecelendirilmiştir ancak 16 veya daha fazla yolcu (sürücü dahil) taşımak için tasarlanmıştır ya da plakart gerektiren tehlikeli maddeler taşır. Hangi CDL sınıfı geçerlidir?","options":["Class A","Class B","Class C","Class E"],"explanation":"Maryland'in Class C CDL'si, Class A veya B ağırlık kriterlerini karşılamayan ancak 16+ yolcu (sürücü dahil) taşımak için tasarlanmış ya da plakart gerektiren tehlikeli maddeler taşıyan daha küçük ticari araçları kapsar. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"23":{"q":"Maryland'de, otobüs gibi 16 veya daha fazla yolcu taşımak için tasarlanmış bir aracı kullanmak için hangi onay (endorsement) kodu gereklidir?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"explanation":"Maryland, 16 veya daha fazla yolcu taşıyan araçları kullanmak için P (Passenger) onayını gerektirir. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"24":{"q":"Maryland'de okul otobüsü kullanmak için, MVA hangi onay (endorsement) kombinasyonunu gerektirir?","options":["Yalnızca S onayı","Yalnızca P onayı","Hem P (Passenger) hem de S (School Bus) onayları","Hem S (School Bus) hem de H (HazMat) onayları"],"explanation":"Maryland, bir okul otobüsü kullanmak için hem P (Passenger) hem de S (School Bus) onaylarını gerektirir. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"25":{"q":"Yakıt veya su tankeri gibi bir tankta sıvı veya gaz taşıyan bir aracı kullanmak için hangi Maryland CDL onayı (endorsement) gereklidir?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement P"],"explanation":"Maryland, yakıt veya su tankerleri gibi tanklarda sıvı veya gaz taşıyan araçlar için N (Tank Vehicle) onayını kullanır. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"26":{"q":"Maryland'de, bir CDL üzerindeki 'X' onayı (endorsement) neyi birleştirir?","options":["Passenger (P) ve School Bus (S)","Tank Vehicle (N) ve HazMat (H)","Doubles/Triples (T) ve Tank (N)","HazMat (H) ve Passenger (P)"],"explanation":"Maryland'in X onayı, N (Tank Vehicle) ve H (HazMat) onaylarının bir kombinasyonu olup, tank araçlarında tehlikeli madde taşınmasına yetki verir. Kaynak: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"27":{"q":"Eyalet içi (yalnızca Maryland) ticari sürüş ile sınırlı bir Maryland CDL'si almak için asgari yaş nedir?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"Maryland, eyalet içi (Maryland içi) sürüş için 18 yaşında CDL'ye izin verirken, eyaletlerarası sürüş 21 yaşını gerektirir. Kaynak: Maryland MVA, Get or Renew a CDL; Manual DL-151."},"28":{"q":"Maryland MVA'ya göre, eyaletlerarası ticarette (eyalet sınırları boyunca) ticari bir aracı kullanmak için gereken asgari yaş nedir?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"Maryland, bir CDL aracını eyaletlerarası (eyalet sınırları boyunca) kullanmak, plakart gerektiren tehlikeli maddeler taşımak veya yolcuları eyaletlerarası taşımak için sürücülerin en az 21 yaşında olmasını gerektirir. Kaynak: Maryland MVA, Get or Renew a CDL."},"29":{"q":"19 yaşındaki bir Maryland CDL sahibinin aşağıdakilerden hangisini yapması yasal olarak kısıtlanmıştır?","options":["Maryland içinde düz bir kamyon kullanmak","Eyalet sınırları boyunca ticari bir araç kullanmak","Eyalet içi kullanım için bir Passenger (P) onayına sahip olmak","Maryland içinde bir Class B aracı kullanmak"],"explanation":"18 ile 21 yaş arasındaki bir Maryland sürücüsü, Maryland dışında (eyaletlerarası) ticari bir araç kullanamaz, hazmat plakartı gerektiren bir araç kullanamaz ve çiftli/üçlü römork takımlarını kullanamaz. Kaynak: Maryland MVA / Manual DL-151."},"30":{"q":"Maryland'de uygulanan federal kural uyarınca, bir başvuru sahibinin CDL beceri (yol) sınavına girmesine izin verilmeden önce bir Commercial Learner's Permit (CLP) belgesini ne kadar süre elinde bulundurması gerekir?","options":["En az 7 days","En az 10 days","En az 14 days","En az 30 days"],"explanation":"Maryland, CDL beceri (yol) sınavı verilebilmesinden önce bir CLP'nin en az 14 days süreyle elde bulundurulmasını gerektiren federal kuralı uygular. Kaynak: Maryland MVA, Get or Renew a CDL; 49 CFR 383.25."},"31":{"q":"Bir Maryland Commercial Learner's Permit (CLP) belgesi verilmeden önce, bir başvuru sahibinin halihazırda hangi belgeye sahip olması gerekir?","options":["Geçerli bir Maryland (motosiklet dışı) sürücü belgesi","Bir Maryland motosiklet ehliyeti","Bir federal TWIC kartı","Bir eyalet dışı CDL"],"explanation":"Maryland, CLP başvuru sahiplerinin halihazırda geçerli bir Maryland sürücü belgesine (yalnızca motosiklet ehliyeti değil) sahip olmasını ve görme ve bilgi sınavlarını geçmesini gerektirir. Kaynak: Maryland MVA / Manual DL-151."},"32":{"q":"Maryland MVA, bir CDL için başvururken başvuru sahibinin hangi belge setini sunmasını gerektirir?","options":["Yalnızca geçerli bir sürücü belgesi ve bir fotoğraf","Kimlik, yaş, Sosyal Güvenlik numarası ve Maryland ikametgahı kanıtı","Yalnızca bir pasaport ve bir işveren mektubu","Kimlik kanıtı ve bir araç tescil kartı"],"explanation":"Maryland MVA, kimlik, yaş, Sosyal Güvenlik numarası ve Maryland ikametgahı kanıtı gerektirir (yasal varlık bu kimlik belgeleri aracılığıyla tespit edilir). Kaynak: Maryland MVA, Get or Renew a CDL."},"33":{"q":"İlk kez Maryland Class A veya B CDL başvuru sahibi için Entry-Level Driver Training (ELDT) nerede tamamlanmalıdır?","options":["Başvuru sahibinin seçtiği herhangi bir özel sürücü kursu","FMCSA Training Provider Registry'de listelenen bir sağlayıcı","Yalnızca bir Maryland MVA şube ofisinde","Maryland State Department of Education tarafından akredite edilmiş bir program"],"explanation":"Maryland, ilk kez Class A/B başvuru sahipleri için (ve ilk kez S, P ve H onayları için) ELDT'nin, beceri sınavı veya hazmat bilgi sınavından önce FMCSA Training Provider Registry'de listelenen bir sağlayıcı aracılığıyla tamamlanmasını gerektirir. Kaynak: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"34":{"q":"Maryland, aşağıdakilerden hangisi için sınavdan önce Entry-Level Driver Training (ELDT) gerektirir?","options":["Mevcut bir Class A CDL'nin yenilenmesi","Otomatik vites kısıtlamasının eklenmesi","İlk kez bir Class A veya B CDL almak ya da ilk kez S, P veya H eklemek","CDL üzerindeki bir ikametgah adresinin güncellenmesi"],"explanation":"Maryland, ilk kez Class A veya B CDL'leri için ve ilk kez School Bus (S), Passenger (P) veya HazMat (H) onaylarını ekleme için ELDT'yi zorunlu kılar. Yenilemeler veya idari değişiklikler için gerekli değildir. Kaynak: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"35":{"q":"Bir Maryland CDL sahibinin seçmesi gereken dört tıbbi öz-beyan (self-certification) kategorisinden biri hangisidir?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Provisional Interstate (PI)","Limited Hazmat (LH)"],"explanation":"Maryland'in dört öz-beyan kategorisi şunlardır: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"36":{"q":"Eyalet sınırları boyunca araç kullanan ve tüm federal sürücü-yeterlilik gerekliliklerine uyması gereken bir Maryland CDL sahibi, hangi kategori olarak öz-beyanda bulunmalıdır?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI), eyalet sınırları boyunca araç kullanan ve geçerli bir DOT tıbbi sertifikası dahil tüm federal yeterlilik gerekliliklerini karşılayan bir CDL sahibi için geçerlidir. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"37":{"q":"Maryland'de, HazMat (H) onay bilgi sınavına girilmeden ve onay verilmeden önce, başvuru sahibi neyi geçmek zorundadır?","options":["Parmak izine dayalı bir geçmiş kontrolü içeren bir TSA güvenlik tehdidi değerlendirmesi","Bir eyalet araç emisyon muayenesi","Yalnızca bir uyuşturucu ve alkol veri tabanı (clearinghouse) işe alım öncesi sorgusu","Yalnızca bir Maryland State Police sürüş kaydı denetimi"],"explanation":"Maryland, hazmat bilgi sınavını geçmenin yanı sıra, HazMat başvuru sahiplerinin parmak izine dayalı bir Background Record Check (DPSCS aracılığıyla işlenen) içeren bir TSA güvenlik tehdidi değerlendirmesini geçmesini gerektirir. Kaynak: Maryland MVA, CDL HazMat Endorsement; 49 CFR Part 1572."},"38":{"q":"TSA onayını aldıktan sonra, bir Maryland başvuru sahibi HazMat onayını hangi süre içinde almalıdır?","options":["30 days içinde","90 days içinde","Altı ay içinde","İki yıl içinde"],"explanation":"Maryland, başvuru sahibinin HazMat onayını TSA onay mektubundaki tarihten itibaren altı ay içinde almasını gerektirir. Kaynak: Maryland MVA, CDL HazMat Endorsement."},"39":{"q":"School Bus (S) onayına sahip bir Maryland CDL sahibinin, bu onayı geçerli tutmak için tıbbi muayene sertifikasını tipik olarak ne sıklıkla yenilemesi gerekir?","options":["Her 6 ayda bir","Yıllık (her yıl)","Her 2 yılda bir","Her 5 yılda bir"],"explanation":"Çoğu tıbbi muayene sertifikası iki yıla kadar geçerli olsa da, Maryland School Bus (S) onay sahiplerinin bu statüyü korumak için genellikle yıllık bir tıbbi sertifikasyona ihtiyacı vardır. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"40":{"q":"Maryland'de, bir kişinin yasal olarak ticari motorlu araç (CMV) kullanabileceği azami kan/nefes alkol konsantrasyonu (BAC) nedir?","options":["0.04","0.08","0.02","0.10"],"explanation":"Maryland'de bir CMV sürücüsü, 0.04 veya daha yüksek bir BAC ile araç kullanmaktan ehliyeti diskalifiye edilir — ticari olmayan sürücüler için olan 0.08 sınırının yarısı. Kaynak: Maryland Transportation Article §16-812(a) ve §11-127.1; Maryland CDL Manual; 49 CFR 383.51 Table 1."},"41":{"q":"Maryland'in zımni rıza (implied-consent) yasası uyarınca, bir CDL sahibinden alkol için bir kimyasal testi yapması yasal olarak istenir ve reddederse ne olur?","options":["CDL en az 1 yıl boyunca diskalifiye edilir (ilk ret, büyük bir suç gibi muamele görür)","Sürücü para cezasına çarptırılır ancak CDL'sini korur","CDL 60 gün süreyle askıya alınır","Mahkumiyete kadar hiçbir şey olmaz"],"explanation":"Maryland zımni rıza uygular: yasal olarak istenen bir kimyasal testi reddetmek, diğer büyük suçlarla aynı şekilde, ilk suç için CDL'yi 1 yıl diskalifiye eder. Kaynak: Maryland Transportation Article §16-205.1 ve §16-812(b); 49 CFR 383.51 Table 1."},"42":{"q":"Plakartlı tehlikeli madde taşımazken işlenen ilk büyük suç (örneğin DUI, bir CMV'de 0.04+ BAC veya test reddi) için Maryland'de CDL diskalifiye süresi nedir?","options":["1 yıl","60 gün","3 yıl","6 ay"],"explanation":"İlk büyük suç, CDL'yi 1 yıl diskalifiye eder (plakartlı HazMat taşınırken meydana gelmişse 3 yıl). Kaynak: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"43":{"q":"Bir Maryland CDL sürücüsü, plakart gerektiren tehlikeli maddeler taşırken ilk büyük suçu (örneğin DUI veya 0.04+ BAC) işlerse, diskalifiye süresi ne kadardır?","options":["3 yıl","1 yıl","5 yıl","Ömür boyu"],"explanation":"Standart 1 yıllık ilk suç diskalifiyesi, sürücü o sırada plakartlı tehlikeli maddeler taşıyorsa 3 yıla çıkarılır. Kaynak: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"44":{"q":"Ayrı bir olayda işlenen İKİNCİ bir büyük suç (ikinci bir DUI, 0.04+ BAC, ret vb.) için Maryland'de CDL diskalifiyesi nedir?","options":["Ömür boyu diskalifiye","5 yıl","3 yıl","2 yıl"],"explanation":"İkinci bir büyük suç, ömür boyu CDL diskalifiyesi ile sonuçlanır, ancak uygun durumlarda 10 yıldan sonra yeniden ehliyet verilmesi mümkün olabilir. Kaynak: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"45":{"q":"Bir kontrollü maddenin üretimi, dağıtımı veya temini içeren bir suçu işlemek için bir CMV kullanmak, hangi Maryland CDL cezasıyla sonuçlanır?","options":["10 yıllık yeniden ehliyet hakkı olmaksızın ömür boyu diskalifiye","1 yıllık diskalifiye","3 yıllık diskalifiye","Ömür boyu diskalifiye, ancak 10 yıldan sonra yeniden ehliyet hakkına uygun"],"explanation":"Bir CMV kullanarak bir kontrollü maddenin üretimi, dağıtımı veya temini içeren bir suç, 10 yıllık yeniden ehliyet hakkına UYGUN OLMAYAN ömür boyu bir diskalifiyedir. Kaynak: 49 CFR 383.51 Table 1; Maryland Transportation Article §16-812."},"46":{"q":"3 yıllık bir süre içinde kaç ciddi trafik ihlali, Maryland'de 60 günlük bir CDL diskalifiyesini tetikler?","options":["2 ciddi ihlal","3 ciddi ihlal","4 ciddi ihlal","1 ciddi ihlal"],"explanation":"3 yıl içinde iki ciddi trafik ihlali (bir CMV'de, herhangi bir kombinasyonda) 60 günlük bir diskalifiye ile sonuçlanır. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"47":{"q":"3 yıllık bir süre içinde üç ciddi trafik ihlali, Maryland'de hangi CDL diskalifiye süresiyle sonuçlanır?","options":["120 gün","60 gün","180 gün","1 yıl"],"explanation":"3 yıl içinde üç ciddi trafik ihlali, CDL'yi 120 gün diskalifiye eder; bu, daha önceki herhangi bir 60 günlük diskalifiyeye ek olarak uygulanır. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"Maryland'de CDL açısından bir 'ciddi trafik ihlali' sayılması için bir hız aşımı suçunun belirlenen sınırın saatte kaç mil üzerinde olması gerekir?","options":["Sınırın 15 mph veya daha fazla üzerinde","Sınırın 10 mph veya daha fazla üzerinde","Sınırın 20 mph veya daha fazla üzerinde","Sınırın 25 mph veya daha fazla üzerinde"],"explanation":"Belirlenen hız sınırının 15 mph veya daha fazla üzerinde hız yapmak, 3 yılda 2 (60 gün) ve 3 yılda 3 (120 gün) diskalifiyelere doğru sayılan bir ciddi trafik ihlalidir. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"49":{"q":"Aşağıdakilerden hangisi bir Maryland CDL sahibi için 'ciddi trafik ihlali' olarak sınıflandırılır?","options":["Tehlikeli sürüş (reckless driving)","Yangın şeridine park etmek","Yanmış bir arka stop lambası","Süresi dolmuş bir tescil etiketi"],"explanation":"Ciddi trafik ihlalleri arasında tehlikeli sürüş, 15+ mph hız aşımı, uygunsuz/düzensiz şerit değişiklikleri, çok yakın takip, mesajlaşma ve elde tutulan telefon kullanımı yer alır. Rutin ekipman/park sorunları ciddi ihlal değildir. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"50":{"q":"Maryland'de, yasaya aykırı olarak mesajlaşırken bir CMV kullanmak, CDL diskalifiyesi açısından hangi tür suç olarak değerlendirilir?","options":["Bir ciddi trafik ihlali","Bir büyük suç","Bir hizmet dışı (out-of-service) ihlali","Bir demiryolu geçidi ihlali"],"explanation":"Bir CMV kullanırken mesajlaşmak, 60 günlük (3 yılda 2) ve 120 günlük (3 yılda 3) diskalifiyelere doğru sayılan bir ciddi trafik ihlalidir. Maryland, birincil uygulama (primary-enforcement) yasası kapsamında mesajlaşmayı yasaklar. Kaynak: Maryland Transportation Article §21-1124.1; 49 CFR 383.51 Table 2."},"51":{"q":"Maryland yasası uyarınca, bir CMV'nin yetişkin bir sürücüsünün araç hareket halindeyken elde tutulan bir cep telefonu kullanması ne tür bir CDL suçu oluşturur?","options":["Bir ciddi trafik ihlali","Küçük, raporlanamayan bir suç","1 yıllık diskalifiyeli bir büyük suç","Bir hizmet dışı (out-of-service) emri ihlali"],"explanation":"Bir CMV kullanırken elde tutulan bir telefon kullanmak, 60/120 günlük diskalifiye eşiklerine doğru sayılan bir ciddi trafik ihlalidir. Maryland'in elde tutulan telefon yasağı birincil bir suçtur. Kaynak: Maryland Transportation Article §21-1124.2; 49 CFR 383.51 Table 2."},"52":{"q":"İLK demiryolu-karayolu hemzemin geçit ihlali için Maryland'de asgari CDL diskalifiyesi nedir?","options":["60 günden az olmamak üzere","30 günden az olmamak üzere","120 günden az olmamak üzere","1 yıldan az olmamak üzere"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, CDL'yi 60 günden az olmamak üzere diskalifiye eder. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"53":{"q":"3 yıllık bir süre içinde İKİNCİ bir demiryolu-karayolu hemzemin geçit ihlali, Maryland'de hangi asgari CDL diskalifiyesiyle sonuçlanır?","options":["120 günden az olmamak üzere","60 günden az olmamak üzere","1 yıldan az olmamak üzere","180 günden az olmamak üzere"],"explanation":"3 yıl içinde ikinci bir demiryolu geçidi ihlali, CDL'yi 120 günden az olmamak üzere diskalifiye eder. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"54":{"q":"3 yıllık bir süre içinde ÜÇÜNCÜ bir demiryolu-karayolu hemzemin geçit ihlali, Maryland'de hangi asgari CDL diskalifiyesiyle sonuçlanır?","options":["1 yıldan az olmamak üzere","120 günden az olmamak üzere","180 günden az olmamak üzere","Ömür boyu"],"explanation":"3 yıl içinde üçüncü (veya sonraki) bir demiryolu geçidi ihlali, CDL'yi 1 yıldan az olmamak üzere diskalifiye eder. Kaynak: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"Bir HazMat OLMAYAN CMV kullanırken bir hizmet dışı (out-of-service) emrini ihlal etmenin İLK mahkumiyeti için Maryland'de CDL diskalifiye aralığı nedir?","options":["180 günden 1 yıla kadar","60 ila 120 gün","1 ila 3 yıl","30 ila 90 gün"],"explanation":"İlk hizmet dışı emri ihlali (HazMat olmayan, 16'dan az yolcu), CDL'yi 180 günden az ve 1 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"56":{"q":"Herhangi bir 10 yıllık süre içinde İKİNCİ bir hizmet dışı (out-of-service) emri ihlali (HazMat olmayan), Maryland'de hangi CDL diskalifiye aralığıyla sonuçlanır?","options":["2 ila 5 yıl","180 günden 1 yıla","1 ila 3 yıl","Ömür boyu"],"explanation":"10 yıl içinde ikinci bir hizmet dışı emri ihlali, CDL'yi 2 yıldan az ve 5 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"57":{"q":"Plakartlı tehlikeli maddeler taşırken veya 16 ya da daha fazla yolcu için tasarlanmış bir araç kullanırken işlenen İLK bir hizmet dışı (out-of-service) emri ihlali, Maryland'de hangi CDL diskalifiye aralığını taşır?","options":["180 günden 2 yıla kadar","180 günden 1 yıla kadar","2 ila 5 yıl","3 ila 5 yıl"],"explanation":"Plakartlı HazMat veya 16+ yolculu bir araç içeren ilk bir hizmet dışı emri ihlali, CDL'yi 180 günden az ve 2 yıldan fazla olmamak üzere diskalifiye eder. Kaynak: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"58":{"q":"Maryland MVA, yüksek BAC'li bir ticari durdurma ile ilgili bir CDL diskalifiyesini ne zaman başlatabilir?","options":["Bir CMV'de yüksek BAC için bir ceza/idari per se işlemi üzerine, mahkumiyetten önce bile","Yalnızca mahkemede cezai bir mahkumiyetten sonra","Yalnızca ikinci bir suçtan sonra","Yalnızca sürücü bir kazaya neden olursa"],"explanation":"Maryland, ticari bir araç kullanırken yüksek bir BAC için bir cezaya veya idari per se emrine dayanarak, herhangi bir mahkeme mahkumiyetinden önce bile bir CDL'yi diskalifiye edebilir. Kaynak: MDOT MVA CDL Disqualification & Reinstatement page; Maryland Transportation Article §16-205.1, §16-812."},"59":{"q":"Ömür boyu bir CDL diskalifiyesinden sonra, bir Maryland sürücüsü, uygunluk gereklilikleri karşılandığı takdirde, genel olarak kaç yıl sonra yeniden ehliyet için başvurabilir?","options":["10 yıl","5 yıl","3 yıl","Asla — ömür boyu her durumda kalıcıdır"],"explanation":"Sürücü, yeniden ehliyet gerekliliklerini karşılarsa ömür boyu bir CDL diskalifiyesi asgari 10 yıla indirilebilir — CMV ile uyuşturucu kaçakçılığı veya insan kaçakçılığı gibi yeniden ehliyete izin vermeyen suçlar hariç. Kaynak: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"60":{"q":"Maryland'in Çekil Kenara (Move Over) yasası uyarınca, bir CDL sürücüsü uyarı ışıkları yanan duran bir acil durum aracına, çekiciye veya servis aracına yaklaştığında yasa İLK olarak hangi eylemi gerektirir?","options":["Güvenli ve yasal ise, duran araca hemen bitişik olmayan bir şeride geçmek","Bir görevli ilerlemesini söyleyene kadar tamamen durmak","Duran aracı geçerken sürekli korna çalmak","Hızı tam olarak belirtilen sınırın 20 mph altına düşürmek ve şeridi korumak"],"explanation":"Maryland Transportation Article 21-405.1 (Çekil Kenara yasası), güvenli ve yasal olduğunda sürücünün duran araca hemen bitişik olmayan bir şeride geçmesini gerektirir. Yalnızca şerit değiştirmek güvensiz veya imkansız ise sürücü bunun yerine makul ve ihtiyatlı bir hıza düşmek zorundadır. Kaynak: Md. Code, Transportation 21-405.1; Maryland MVA/MSP rehberliği."},"61":{"q":"Bir Maryland CDL sürücüsü, ışıkları yanan duran bir acil durum veya servis aracını geçerken güvenli bir şekilde şerit değiştiremiyorsa, bunun yerine ne yapmalıdır?","options":["Mevcut koşullar için makul ve ihtiyatlı olan bir hıza düşmek","Olay yeri temizlenene kadar banketin üzerinde tamamen durmak","Belirtilen hız sınırını korumak ve hızı değiştirmeden geçmek","Refüje çekmek ve trafiğin şeridi boşaltmasını beklemek"],"explanation":"Md. Transportation 21-405.1 uyarınca, kenara çekilmek güvensiz veya mümkün değilse, sürücü koşullar için güvenli olan makul ve ihtiyatlı bir hıza düşmek zorundadır. Maryland yasası tek bir sabit sayı belirlemez; koşullar için makul bir hız gerektirir. Kaynak: Md. Code, Transportation 21-405.1."},"62":{"q":"1 Ekim 2022 tarihli bir genişletme itibariyle, Maryland'in Çekil Kenara yasası yol kenarında duran aşağıdakilerden hangisine uygulanır?","options":["Sıradan binek otomobiller dahil olmak üzere, dörtlü flaşör, uyarı konileri veya yol fişekleri gösteren herhangi bir araç","Yalnızca yanıp sönen ışıklar kullanan işaretli polis ve itfaiye araçları","Yalnızca çekiciler ve karayolu bakım araçları","Yalnızca 26,001 pound üzerindeki ticari motorlu araçlar"],"explanation":"1 Ekim 2022'den itibaren geçerli olmak üzere, Maryland 21-405.1'i genişletti; böylece Çekil Kenara görevi yalnızca acil durum veya servis araçlarına değil, dörtlü flaşör, yol fişeği veya uyarı konileri gösteren HERHANGİ bir duran araca uygulanır. Kaynak: Md. Code, Transportation 21-405.1 (2022 değişikliği); Maryland MVA."},"63":{"q":"İki şeritli bölünmemiş bir yolda bir Maryland okul otobüsü kırmızı ışıkları yanıp sönerek ve dur kolu açık olarak durduğunda, HER İKİ yönden yaklaşan bir CDL sürücüsü ne yapmalıdır?","options":["Durmak ve ışıkların yanıp sönmesi kesilene ve otobüs hareket edene veya gitme işareti verene kadar durmuş halde kalmak","15 mph hıza düşmek ve dikkatle soldan geçmek","Yalnızca otobüsle aynı yönde gidiyorsa durmak","Otobüsün yakınında görünür çocuk yoksa ilerlemek"],"explanation":"Maryland'de bölünmemiş çift yönlü bir yolda, HER İKİ yöndeki trafik, kırmızı ışıkları yanıp sönen ve dur kolu açık olan bir okul otobüsü için durmalı ve işaretler kapanana kadar durmuş halde kalmalıdır. Kaynak: Md. Code, Transportation 21-706; Maryland MVA/MSP."},"64":{"q":"Maryland'in bölünmüş karayolu istisnası uyarınca, duran bir okul otobüsünün TERS yönünde seyahat eden sürücülerin durmaları NE ZAMAN gerekmez?","options":["Seyahat yönleri çimen, toprak veya beton ayırıcı gibi fiziksel bir refüj veya bariyerle ayrıldığında","Herhangi bir refüjden bağımsız olarak yol dört veya daha fazla şeride sahip olduğunda","Seyahat yönlerini çift sarı orta çizgi ayırdığında","Otobüs ters yöndeki şeritlerde 100 fitten daha uzakta olduğunda"],"explanation":"Maryland, ters yöndeki trafiği durmaktan YALNIZCA fiziksel bir refüj, bariyer veya asfaltsız şerit yolları ayırdığında muaf tutar. Boyalı çizgiler bölünmüş bir karayolu OLUŞTURMAZ, bu yüzden tek başına çift sarı çizgi istisnayı tetiklemez. Kaynak: Md. Code, Transportation 21-706; Maryland MVA rehberliği."},"65":{"q":"Fiziksel refüjü olan bir Maryland bölünmüş karayolunda, karşı taraftaki bir okul otobüsü kırmızı ışıklarını yanıp söndürdüğünde kimler yine de durmalıdır?","options":["Otobüsle aynı yönde, onun arkasında seyahat eden sürücüler","Her iki yoldaki tüm sürücüler durmalıdır","Hiçbir bölünmüş karayolunda hiçbir sürücünün durması gerekmez","Yalnızca refüjün hemen yanındaki şeritteki sürücüler"],"explanation":"Bölünmüş bir karayolunda bile, otobüsü AYNI yönde takip eden trafik durmalıdır. Yalnızca fiziksel refüjle ayrılmış karşı yöndeki trafik muaftır. Kaynak: Md. Code, Transportation 21-706."},"66":{"q":"Eyaletler arası karayolları ve ekspres yollar dahil olmak üzere Maryland'deki herhangi bir karayolunda belirlenebilecek mutlak maksimum hız sınırı nedir?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"Maryland yasası maksimum hız sınırını 70 mph ile sınırlar; bu yalnızca belirli eyaletler arası karayolları ve ekspres yollarda belirlenebilir; hiçbir Maryland karayolu 70 mph'den fazlasını belirleyemez. Kaynak: Md. Code, Transportation 21-801.1; MDOT SHA."},"67":{"q":"Maryland, aynı karayolundaki binek otomobillere kıyasla kamyonlar ve diğer ticari motorlu araçlar için maksimum hız sınırını nasıl belirler?","options":["Kamyonlar diğer araçlarla aynı belirtilen maksimumu izler; Maryland'in eyalet genelinde ayrı bir daha düşük kamyon hız sınırı yoktur","Belirtilen sınırdan bağımsız olarak kamyonlar eyalet genelinde 55 mph ile sınırlıdır","Kamyonlar tüm karayollarında belirtilen sınırın 10 mph altıyla sınırlıdır","Her eyaletler arası karayolunda otomobiller 70 mph gidebilirken kamyonlar 65 mph ile sınırlıdır"],"explanation":"Bazı eyaletlerden farklı olarak Maryland, kamyonlar için ayrı, daha düşük eyalet geneli bir hız sınırı BELİRLEMEZ. Ticari araçlar diğer trafikle aynı belirtilen sınırlara uyar (70 mph üst sınırına kadar). Kaynak: Md. Code, Transportation 21-801.1; MDOT SHA hız sınırı rehberliği."},"68":{"q":"Maryland'in CDL sürücülerine uyguladığı kurallar uyarınca hangi ticari araçlar demiryolu raylarını hemzemin geçitten geçmeden önce DURMALIDIR?","options":["Yolcu taşıyan otobüsler ve plaka (placard) taşıyan tehlikeli madde taşıyan araçlar","10,000 pound üzerindeki tüm ticari motorlu araçlar","Yalnızca çift veya üçlü römork çeken araçlar","Yalnızca daha önce yanıcı madde taşımış boş tank araçları"],"explanation":"Maryland, CDL kılavuzunda benimsediği federal kuralı (49 CFR 392.10) izler: yolcu taşıyan otobüsler ve plaka (placard) taşıyan tehlikeli madde araçları hemzemin geçitlerde durmalıdır. Diğer çoğu kamyonun, levhalar veya sinyaller yönlendirmediği sürece durması gerekmez. Kaynak: Maryland CDL Manual; 49 CFR 392.10."},"69":{"q":"Plaka (placard) taşıyan bir tehlikeli madde kamyonu veya yolcu otobüsünün bir Maryland demiryolu geçidinde durması gerektiğinde, en yakın raya hangi mesafe içinde durmalıdır?","options":["En yakın raya 15 fitten yakın olmadan ve 50 fitten uzak olmadan","En yakın raya 5 fitten yakın olmadan ve 25 fitten uzak olmadan","En yakın raya 25 fitten yakın olmadan ve 75 fitten uzak olmadan","En yakın raya 10 fitten yakın olmadan ve 100 fitten uzak olmadan"],"explanation":"Durması gereken CMV'ler, en yakın raya 50 fit içinde ancak 15 fitten yakın olmadan durmalı, ardından ilerlemeden önce bakıp dinlemelidir. Kaynak: Maryland CDL Manual; 49 CFR 392.10."},"70":{"q":"Bir demiryolu geçidinde durduktan sonra, bir Maryland otobüs veya plaka (placard) taşıyan tehlikeli madde sürücüsü yalnızca ne yaptıktan sonra ilerleyebilir?","options":["Yaklaşan bir tren için her iki yöne bakıp dinleyerek ve geçidin durmadan temizlenebileceğini doğrulayarak","Momentumu korumak için rayları geçerken en az bir kez vites değiştirerek","Bir trenin gelip gelmediğine bakılmaksızın zorunlu 30 saniye bekleyerek","Geçide girmeden önce kornayı üç kez çalarak"],"explanation":"15 ila 50 fitlik bölgede durduktan sonra, sürücü bir tren için her iki yöne bakıp dinlemeli ve rayları durmadan tamamen temizleyecek yer olmadıkça geçmeye başlamamalıdır. Sürücüler raylar üzerindeyken vites değiştirmemelidir. Kaynak: Maryland CDL Manual; 49 CFR 392.10."},"71":{"q":"Bir Maryland CDL sürücüsü bir karayolunun seyahat edilen kısmında veya banketinde bir kamyonu durdurmak zorunda kaldığında, uyarı cihazları (yansıtıcı üçgenler) kaç dakika içinde yerleştirilmelidir?","options":["Durduktan sonra 10 dakika içinde","Durduktan sonra 5 dakika içinde","Durduktan sonra 15 dakika içinde","Durduktan sonra 30 dakika içinde"],"explanation":"Duran bir CMV'nin sürücüsü uyarı cihazlarını 10 dakika içinde yerleştirmelidir. Bu federal standart Maryland CDL Manual'da öğretilir ve Maryland'de geçerlidir. Kaynak: Maryland CDL Manual; 49 CFR 392.22."},"72":{"q":"İki şeritli, çift yönlü bir yolda, bir Maryland CDL sürücüsü duran bir kamyon için gerekli üç uyarı üçgenini nereye yerleştirmelidir?","options":["Aracın yaklaşık 10 fit arkasına trafik tarafına, yaklaşık 100 fit arkasına ve aracın yaklaşık 100 fit önüne","Üç üçgenin tümünü aracın 200 fit arkasına bir sırada","Yalnızca aracın yaklaşık 50 fit, 150 fit ve 250 fit arkasına","Görünürlüğü en üst düzeye çıkarmak için biri kaputa ve ikisi tavana"],"explanation":"Çift yönlü bir yolda, bir üçgeni trafik tarafında yaklaşık 10 fit arkaya, birini yaklaşık 100 fit arkaya ve birini yaklaşık 100 fit öne yerleştirin; böylece her iki yönden gelen trafik uyarılır. Kaynak: Maryland CDL Manual; 49 CFR 392.22."},"73":{"q":"Tek yönlü veya bölünmüş bir karayolunda, bir Maryland CDL sürücüsü duran bir kamyonun arkasındaki üç uyarı üçgenini nasıl aralıklandırmalıdır?","options":["Yaklaşan trafiğe doğru yaklaşık 10 fit, 100 fit ve 200 fit mesafede","Yaklaşan trafiğe doğru yaklaşık 10 fit, 50 fit ve 100 fit mesafede","Yaklaşan trafiğe doğru yaklaşık 25 fit, 75 fit ve 150 fit mesafede","Yaklaşan trafiğe doğru yaklaşık 50 fit, 100 fit ve 500 fit mesafede"],"explanation":"Tek yönlü veya bölünmüş bir karayolunda, üç üçgen yaklaşan trafiğe doğru araçtan yaklaşık 10, 100 ve 200 fit mesafede yerleştirilir. Kaynak: Maryland CDL Manual; 49 CFR 392.22."},"74":{"q":"Maryland'in sağdan gitme yasası, yavaş bir aracın sağ şeridi kullanmasını gerektirir. Maksimum hız sınırının ne kadar altında seyahat eden bir araç (geçiş yapmak veya sola dönmek dışında) sağda kalmalıdır?","options":["Geçerli maksimum hız sınırının 10 mph veya daha fazla altında","Geçerli maksimum hız sınırının 5 mph veya daha fazla altında","Geçerli maksimum hız sınırının 15 mph veya daha fazla altında","Geçerli maksimum hız sınırının 20 mph veya daha fazla altında"],"explanation":"Md. Transportation 21-301, maksimum sınırın 10 mph veya daha fazla altında giden (veya koşullar gerektirdiğinde normal trafikten daha yavaş) herhangi bir aracın, geçiş yaparken veya sola dönüşe hazırlanırken hariç, sağ şeritte kalmasını gerektirir. Kaynak: Md. Code, Transportation 21-301."},"75":{"q":"Aynı yönde iki veya daha fazla şeride sahip bir Maryland yolunda, bir kamyon, kamyon çekici, römork veya otobüsün hangi şeridi kullanması gerektiğini ne belirler?","options":["Aracın belirli bir şeritte sürülmesini gerektiren herhangi bir trafik kontrol cihazının talimatları","Şerit levhaları ticari araçlar için geçerli olmadığından sürücünün tercihi","Tüm kamyonların yalnızca en soldaki şeridi kullanması gereken sabit bir kural","O sırada en az binek aracın bulunduğu şerit"],"explanation":"Maryland yasası (Transportation 21-301 ve ilgili şerit kullanım kuralları), kamyonların, kamyon çekicilerin, römorkların ve otobüslerin kendileri için belirli şeritler belirleyen trafik kontrol cihazlarına uymasını gerektirir. Kaynak: Md. Code, Transportation 21-301; 21-309."},"76":{"q":"Ticari kamyonların Baltimore-Washington Parkway'den (MD 295'in Milli Park Servisi bölümü) genellikle neden yasaklandığını açıklayan nedir?","options":["Ticari araçları yasaklayan federal bir parkyoludur; kamyonlar özel bir izne sahip olmadıkça I-95 veya diğer kamyon güzergahlarını kullanmalıdır","Kaplama, binek otomobilden daha geniş herhangi bir araç için çok dardır","Ticari transponderları kabul etmeyen bir paralı yoldur","Kamyonlara yalnızca gece yarısı ile sabah 5 arası izin verir"],"explanation":"NPS tarafından yönetilen Baltimore-Washington Parkway ticari araçları yasaklar; kamyonlar levhalarla yönlendirilir ve I-95 veya diğer belirlenmiş kamyon güzergahlarını kullanmalıdır. Karavanlara ve otobüslere genellikle izin verilir, ancak ticari kamyonlara izin olmadan izin verilmez. Kaynak: National Park Service parkyolu düzenlemeleri; Maryland kamyon güzergahı rehberliği."},"77":{"q":"Maryland'de Fort McHenry Tüneli (I-95) ve Baltimore Harbor Tüneli'nden (I-895) hangi yük sınıfları yasaklanmıştır?","options":["Diğer tehlikeli maddelerin yanı sıra patlayıcılar, dökme benzin ve yanıcı sıvılar ve izin verilen sınırların üzerindeki şişe propan","Soğutulmuş gıda yükleri ve canlı hayvanlar","40,000 pound brütten fazla ağırlıkta herhangi bir yük","İçeriğinden bağımsız olarak çift veya üçlü römorklarda taşınan tüm yükler"],"explanation":"MDTA, Fort McHenry ve Baltimore Harbor Tünellerinden patlayıcıları, dökme benzin/yanıcı sıvıları, belirli radyoaktif maddeleri ve izin verilen sınırın üzerindeki şişe propanı (kap başına 10 lb'den fazla) yasaklar. Kaynak: MDTA yasak tehlikeli madde listesi; mdta.maryland.gov."},"78":{"q":"Baltimore tünellerinden yasaklanmış plaka (placard) taşıyan tehlikeli madde taşıyan bir Maryland CDL sürücüsü Baltimore bölgesinden hangi güzergahı kullanmalıdır?","options":["Liman geçişlerinin etrafında I-695'in (dış Beltway) batı bölümü","Yoğun olmayan saatlerde I-95'te Fort McHenry Tüneli'nden doğrudan geçmek","Dörtlü flaşörler açık olarak I-895'te Baltimore Harbor Tüneli","Ücretlerden kaçınan Baltimore şehir merkezinden geçen herhangi bir şehir caddesi"],"explanation":"Tünellerden yasaklanmış tehlikeli madde yükleri, I-695'in batı bölümünü kullanarak limanın etrafından dolaşmalıdır. Key Bridge (güneydoğu I-695 geçişi) 2024'te çöktüğünden beri bu güzergah daha da önemlidir. Kaynak: MDTA tünel kısıtlaması/izin rehberliği; mdta.maryland.gov."},"79":{"q":"Batı Maryland'deki I-68'in dik dağ yokuşlarında (Sideling Hill ve Big Savage Mountain yakınında), uzun bir iniş yokuşunda frenlemesini kaybeden kamyonlar için hangi güvenlik özelliği sağlanmıştır?","options":["Aracı durdurmak için bir yokuş ve durdurucu malzeme kullanan kaçış rampaları (escape ramps)","Kamyonları inmeden önce yavaşlamaya zorlayan zorunlu tüneller","Yalnızca arızalı kamyonlar için açılan tersine çevrilebilir paralı şeritler","Yokuşta lastik tutuşunu artıran ısıtmalı kaplama şeritleri"],"explanation":"Batı Maryland boyunca I-68'in dik, uzun yokuşları vardır; frenleri arızalı veya aşırı ısınmış kamyonların güvenle durabilmesi için kaçış rampaları (bir yokuşta çakıl/kum durdurucu kaçış rampaları) sağlanmıştır. Sürücüler düşük viteste inmeli ve uygun frenleme tekniğini kullanmalıdır. Kaynak: MDOT SHA; Maryland CDL Manual dağ sürüşü bölümü."},"80":{"q":"Hangi Maryland kurumu Ticari Sürücü Belgesi (CDL) düzenler?","options":["MDOT Motor Vehicle Administration (MVA)","Maryland State Police Ticari Araç Bölümü","Federal Motor Carrier Safety Administration (FMCSA)","Maryland Çalışma Bakanlığı"],"explanation":"Maryland'de CDL'ler MDOT Motor Vehicle Administration (MVA) tarafından düzenlenir. FMCSA federal CDL standartlarını belirler ancak belgenin kendisini düzenlemez. Kaynak: Maryland MVA, Commercial Driver's License sayfaları."},"81":{"q":"Maryland'de CDL beceri (yol) testini planlamadan önce, Ticari Öğrenci İzninizi (CLP) ne kadar süre elinizde bulundurmuş olmanız gerekir?","options":["En az 14 gün","En az 7 gün","En az 30 gün","En az 60 gün"],"explanation":"Maryland federal kuralı izler: bir CLP sahibi, CLP düzenlendikten en az 14 gün sonrasına kadar CDL beceri testine girmeye uygun değildir. Kaynak: Maryland MVA, Get or Renew a CDL."},"82":{"q":"Bir Maryland başvuru sahibinin ilk Sınıf A veya Sınıf B belgesi için CDL beceri testine girebilmesinden önce hangi eğitim tamamlanmalıdır?","options":["Entry-Level Driver Training (ELDT)","Eyalet onaylı bir savunmacı sürüş kursu","Bir FMCSA tehlikeli maddeler semineri","40 saatlik bir MVA sınıf oryantasyonu"],"explanation":"Maryland, ilk Sınıf A veya B CDL için ve ilk P, S veya H onayları için gerekli olan federal olarak zorunlu Entry-Level Driver Training (ELDT) eğitimini tamamlayana kadar beceri testine girmenize izin vermez. Kaynak: Maryland MVA / FMCSA ELDT kuralı."},"83":{"q":"Maryland CDL beceri testinin geçilmesi gereken üç bölümü vardır. Bunlar nelerdir?","options":["Sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yolda sürüş","Yazılı bilgi, görme taraması ve yolda sürüş","Hava freni testi, geri geri park testi ve gece sürüşü","Sefer öncesi muayene, tehlikeli madde elleçleme ve yolda sürüş"],"explanation":"Maryland'in CDL beceri testi, sefer öncesi araç muayenesi, temel araç kontrol becerileri ve yolda sürüş testinden oluşur ve üçünün de başarıyla tamamlanması gerekir. Kaynak: Maryland MVA, CDL Skills Test."},"84":{"q":"Maryland'in CDL öz beyanı uyarınca, bir başvuru sahibi kaç ticari sürüş operasyonu kategorisi beyan edebilir?","options":["Dört","İki","Üç","Beş"],"explanation":"Maryland CDL sahipleri dört kategoriden birine öz beyanda bulunur: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"85":{"q":"Bir Maryland sürücüsü 'Non-Excepted Interstate (NI)' olarak beyanda bulunuyor. Bu ne anlama gelir?","options":["Eyalet sınırlarını aşarak sürdüklerini ve tüm federal tıbbi yeterlilik gereksinimlerini karşılamaları gerektiğini","Yalnızca Maryland içinde sürdüklerini ve federal tıbbi kurallardan muaf olduklarını","Yalnızca belirli muaf faaliyetler için eyalet sınırlarını aşarak sürdüklerini","Yalnızca onaylı bir MVA tıbbi muafiyeti kullanarak Maryland içinde sürdüklerini"],"explanation":"Non-Excepted Interstate (NI), sürücünün eyalet sınırlarını aşarak bir CMV kullandığı ve tüm federal yeterlilik (tıbbi dahil) gereksinimlerine uyduğu anlamına gelir. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"86":{"q":"Bir Maryland CDL sahibinin DOT Tıbbi Muayene Belgesi normalde MVA'ya nasıl ulaşır?","options":["Tıbbi muayene uzmanı bunu elektronik olarak FMCSA'nın National Registry'sine gönderir ve MVA bunu otomatik olarak alır","Sürücü kağıt belgeyi 10 gün içinde MVA genel merkezine postalamalıdır","Sürücünün işvereni bunu sürücü adına MVA'ya faksla gönderir","Belge yalnızca sürücü CDL'yi şahsen yenilediğinde yüklenir"],"explanation":"Sertifikalı tıbbi muayene uzmanı belge bilgilerini elektronik olarak FMCSA National Registry'sine gönderir ve MVA tıbbi sertifikasyonu otomatik olarak alır; sürücünün bunu postalaması veya göndermesi gerekmez. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"87":{"q":"Bir Maryland sürücüsünün DOT tıbbi sertifikasyonu süresi dolarsa ticari ayrıcalıklarına ne olur?","options":["CDL'leri düşürülür ve artık bir CMV kullanmaya yeterli değillerdir","Eyalet içi sürmeye devam ettikleri sürece 90 gün boyunca hiçbir şey değişmez","Temel sınıf dahil tüm sürücü belgeleri derhal askıya alınır","MVA otomatik bir geçici tıbbi muafiyet düzenler"],"explanation":"Tıbbi sertifikasyonun süresi dolarsa, sürücü artık yasal olarak bir CMV kullanmaya yeterli değildir ve ticari sürüş ayrıcalıkları düşürülür. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"88":{"q":"Bir Maryland CDL başvuru sahibinin MVA'da hangi belge setini sunması gerekir?","options":["Kimlik, yaş, Social Security numarası ve Maryland ikametgahı kanıtı","Yalnızca geçerli bir pasaport ve bir fatura","Yalnızca kimlik kanıtı ve noter onaylı bir işveren mektubu","Yalnızca bir doğum belgesi ve araç sigortası kanıtı"],"explanation":"Maryland CDL başvuru sahipleri kimlik, yaş, Social Security numarası ve Maryland ikametgahı kanıtı sunmalıdır. Kaynak: Maryland MVA, Get or Renew a CDL."},"89":{"q":"Maryland'de sürüş türünün öz beyanı, aşağıdaki durumların tümünde gereklidir, HANGİSİ HARİÇ?","options":["Yıllık araç tescilinizi her yenilediğinizde","Yeni bir CDL aldığınızda","CDL'nizi yenilediğinizde veya yükselttiğinizde","Eyaletler arası ve eyalet içi sürüş arasında geçiş yaptığınızda"],"explanation":"Öz beyan; bir CDL alırken, yenilerken, devrederken veya yükseltirken, tıbbi durumu değiştirirken veya eyaletler arası ve eyalet içi sürüş arasında geçiş yaparken gereklidir — rutin araç tescili için değil. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"90":{"q":"Bir CMV'yi yalnızca Maryland içinde kullanan ve onaylı bir MVA CDL Tıbbi Muafiyetine sahip bir Maryland CDL sahibini hangi kategori tanımlar?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA), yalnızca Maryland içinde kullanmaya yeterli olan ve onaylı bir MVA CDL Tıbbi Muafiyetine sahip bir sürücü için geçerlidir. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"91":{"q":"Onaylardan bağımsız olarak her Maryland CDL başvuru sahibinin geçmesi gereken ilk bilgi testi nedir?","options":["General Knowledge (Genel Bilgi) testi","Hazardous Materials (Tehlikeli Maddeler) testi","Air Brakes (Hava Frenleri) testi","Combination Vehicles (Kombinasyon Araçları) testi"],"explanation":"Tüm Maryland CDL başvuru sahipleri önce CDL General Knowledge testini geçmelidir; onaya özel testler (P, S, N, H, T) gerektiğinde ek olarak alınır. Kaynak: Maryland MVA / CDL Manual (DL-151)."},"92":{"q":"Bir Maryland başvuru sahibi CDL bilgi (yazılı) testlerini nerede alır?","options":["Maryland genelindeki MVA ofislerinde elektronik olarak","Yalnızca MVA genel merkezine postayla gönderilen kağıt sınav yoluyla","Herhangi bir FMCSA federal test merkezinde","Onaylı herhangi bir üçüncü taraf web sitesi aracılığıyla evden çevrimiçi olarak"],"explanation":"CDL bilgi testleri Maryland genelindeki MVA ofislerinde elektronik olarak uygulanır. Kaynak: Maryland MVA, Knowledge Tests / Prepare for a Driver's License Test."},"93":{"q":"Standart bir Maryland sürücü belgesi ve CDL için tipik yenileme döngüsü (süre uzunluğu) nedir?","options":["8 yıl","4 yıl","5 yıl","10 yıl"],"explanation":"Maryland sürücü belgeleri, CDL'ler dahil, tipik olarak 8 yıllık bir süre için düzenlenir/yenilenir. Kaynak: Maryland MVA, Renew a License or ID."},"94":{"q":"Maryland CDL beceri testinde, üç bileşen genellikle hangi sırayla yürütülür?","options":["Önce sefer öncesi muayene, sonra temel kontrol becerileri, sonra yolda sürüş","Önce yolda sürüş, sonra sefer öncesi muayene, sonra temel kontrol becerileri","Önce temel kontrol becerileri, sonra yolda sürüş, sonra sefer öncesi muayene","Önce yolda sürüş, sonra temel kontrol becerileri, sonra sefer öncesi muayene"],"explanation":"Maryland beceri testini sırayla yürütür: önce sefer öncesi araç muayenesi, sonra temel araç kontrol becerileri, sonra yolda sürüş testi. Kaynak: Maryland MVA, CDL Skills Test."},"95":{"q":"Bir Maryland CDL sahibi tıbbi sertifikasyonunun süresinin dolmasına izin verir ve bir yıldan fazla zaman geçerse, CDL'yi geri kazanmak için ne yapmalıdır?","options":["Tüm CDL bilgi ve beceri testlerini yeniden almak","Test olmadan yalnızca yeni bir tıbbi belge sunmak","Bir yeniden etkinleştirme ücreti ödemek ancak hiçbir test almamak","Yalnızca zorunlu 90 günlük bir askıyı beklemek"],"explanation":"Bir CDL süresi dolmuş bir tıbbi belge nedeniyle düşürülürse ve bir yıldan fazla zaman geçerse, sürücü CDL'yi geri almak için tüm CDL bilgi ve beceri testlerini yeniden almalıdır. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"96":{"q":"Eyalet sınırlarını yalnızca okul çocuklarını, hasta veya yaralı kişileri ya da cenazeleri taşımak için aşan bir Maryland CDL sahibine hangi kategori uyar?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Excepted Interstate (EI), eyalet sınırlarını yalnızca okul çocuklarını veya personeli, hasta veya yaralı kişileri ya da cenazeleri taşımak gibi belirli muaf faaliyetler için aşan sürücüleri kapsar. Kaynak: Maryland MVA, CDL Medical Certification Requirements."},"97":{"q":"Bir Maryland beceri testinden önce hangi senaryo, tek başına, federal ELDT gereksinimini tetiklemez?","options":["Mevcut bir Sınıf A CDL'yi aynı onaylarla yenilemek","İlk Sınıf A CDL için başvurmak","Bir Sınıf B'den Sınıf A CDL'ye yükseltmek","İlk Yolcu (P) veya Okul Otobüsü (S) onayını almak"],"explanation":"ELDT, ilk Sınıf A veya B CDL için, Sınıf B'den Sınıf A'ya yükseltmek için ve ilk P, S veya H onayı için gereklidir — ancak mevcut bir CDL'nin doğrudan yenilenmesi tek başına ELDT'yi tetiklemez. Kaynak: Maryland MVA / FMCSA ELDT kuralı."},"98":{"q":"Maryland CDL beceri (yol) testi randevusu tipik olarak nasıl planlanır?","options":["Başvuru sahibinin myMVA hesabı aracılığıyla bir randevu alınarak","Randevu olmadan herhangi bir MVA şubesine giderek","FMCSA'nın ulusal randevu hattını arayarak","CLP'nin düzenlendiği gün otomatik olarak"],"explanation":"Başvuru sahipleri CDL beceri testini myMVA hesapları aracılığıyla bir randevu alarak planlar; test, CLP bekleme süresi ve ELDT karşılandıktan sonra MVA tarafından uygulanır. Kaynak: Maryland MVA, CDL Skills Test."}},"es":{"0":{"q":"En las carreteras de Maryland, ¿cuál es el ancho máximo legal de un vehículo (sin contar los espejos ni otros dispositivos de seguridad/ahorro de energía) antes de que se requiera un permiso por sobredimensión?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"El artículo de Transporte de Maryland § 24-102 establece el ancho máximo del vehículo en 102 inches (8 feet 6 inches); el ancho se mide sin incluir los espejos, las luces de marcación/intermitentes ni los dispositivos de ahorro de energía. Cualquier cosa más ancha necesita un permiso por sobredimensión de la SHA. Fuente: Md. Transp. § 24-102; MD SHA Oversize/Overweight Hauling Permit Manual."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo y su carga en las carreteras de Maryland sin un permiso?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"Conforme al artículo de Transporte de Maryland § 24-104, la altura de un vehículo y su carga no puede exceder 13 feet 6 inches. El manual de permisos de la SHA indica 13'6\" como el límite legal sin condiciones especiales. Fuente: Md. Transp. § 24-104; MD SHA Hauling Permit Manual (sección de altura)."},"2":{"q":"¿Cuál es el peso bruto vehicular máximo permitido en las autopistas Interestatales de Maryland sin un permiso por sobrepeso?","options":["73,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"explanation":"Maryland sigue el estándar federal Interestatal: el peso bruto máximo es de 80,000 pounds (incluyendo la carga). Fuente: Md. Transp. § 24-109; 23 CFR 658.17 aplicado en las Interestatales de Maryland."},"3":{"q":"En las Interestatales de Maryland, ¿cuál es el peso máximo permitido en un solo eje?","options":["17,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"El límite de eje sencillo en el sistema Interestatal de Maryland es de 20,000 pounds, lo que coincide con el estándar federal del artículo de Transporte de Maryland § 24-109. Fuente: Md. Transp. § 24-109; 23 CFR 658.17."},"4":{"q":"En las Interestatales de Maryland, ¿cuál es el peso máximo permitido en un eje tándem?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"El límite del eje tándem (grupo de dos ejes separados por más de 40 pero no más de 96 inches) es de 34,000 pounds según el artículo de Transporte de Maryland § 24-109, en concordancia con el estándar federal Interestatal. Fuente: Md. Transp. § 24-109; 23 CFR 658.17."},"5":{"q":"¿Qué oficina de la agencia de Maryland emite los permisos de transporte por sobredimensión/sobrepeso para circular por las carreteras mantenidas por el estado?","options":["La Unidad de Licencias de Conducir de la Motor Vehicle Administration (MVA)","La SHA Office of Traffic and Safety, Motor Carrier Division, Hauling Permits Unit","La División de Control de Vehículos Comerciales de la Policía Estatal de Maryland","La Oficina de Instalaciones de Peaje de la Maryland Transportation Authority"],"explanation":"Los permisos de transporte por sobredimensión/sobrepeso (OS/OW) son emitidos por la Maryland State Highway Administration, Office of Traffic and Safety, Motor Carrier Division – Hauling Permits Unit (Hanover, MD). Fuente: MD SHA Oversize/Overweight Hauling Permit Manual (Introducción)."},"6":{"q":"Una carga no se puede reducir más, pero aun así excede los límites legales de Maryland. ¿Qué secciones del estatuto establecen los límites legales de tamaño y peso que generan la necesidad de un permiso especial de transporte?","options":["Artículo de Transporte, Título 16, Secciones 101 y 102","Artículo de Transporte, Título 24, Secciones 108 y 109","Artículo de Transporte, Título 21, Secciones 1101 y 1102","Artículo de Transporte, Título 11, Secciones 301 y 302"],"explanation":"El manual de permisos de la SHA establece que cuando una carga excede los límites legales fijados en la Ley de Vehículos Motorizados de Maryland, Título 24, Secciones 108 (cargas por eje) y 109 (peso bruto), se debe adquirir un Permiso Especial de Transporte. Fuente: MD SHA Hauling Permit Manual; Md. Transp. §§ 24-108, 24-109."},"7":{"q":"En la Red Nacional y las rutas de transporte de carga designadas de Maryland, ¿cuál es la longitud máxima de un semirremolque que no requiere permiso?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"En la Red Nacional y las rutas de transporte de carga designadas, se permiten semirremolques de hasta 53 feet sin un permiso (48 feet aplica en muchas otras carreteras estatales). Fuente: Md. Transp. § 24-104.1/24-104.2; resumen de tamaño/peso de Maryland de J.J. Keller."},"8":{"q":"Maryland no aplica un límite fijo de longitud total a una combinación de tractor-semirremolque en la Red Nacional, pero el peso sobre cualquier grupo de ejes aún está limitado por ¿cuál cálculo?","options":["La Fórmula Federal de Puentes (Tabla de Peso Bruto sobre Puentes)","Únicamente la clasificación de peso bruto por eje del fabricante","Una cifra fija de 1,000 pounds por inch de ancho de neumático","El peso de tara registrado multiplicado por dos"],"explanation":"Maryland aplica la Fórmula Federal de Puentes en su Red Interestatal/Nacional: el peso máximo sobre cualquier grupo de ejes consecutivos se rige por la fórmula de puentes, hasta el tope total de 80,000 pounds. Fuente: Md. Transp. § 24-109; 23 CFR 658.17 Fórmula Federal de Puentes."},"9":{"q":"Un vehículo combinado excede el peso legal de Maryland. ¿Hasta qué peso bruto puede autorizar la circulación un permiso ordinario de transporte por sobrepeso de la SHA, y en qué carreteras?","options":["Hasta 100,000 pounds en cualquier carretera estatal","Hasta 120,000 pounds en cualquier camino estatal","Hasta 150,000 pounds únicamente en rutas Interestatales","Hasta 200,000 pounds únicamente en el Capital Beltway"],"explanation":"El manual de la SHA dispone que las cargas con permiso para vehículos combinados de hasta 150,000 pounds, sin exceder ese valor, se permiten únicamente en rutas Interestatales (sin tener que acudir a la Office of Bridge Development), siempre que se cumplan las reglas de peso/separación de ejes. Fuente: MD SHA Hauling Permit Manual (Peso, 'Más de 60 Toneladas')."},"10":{"q":"Según la tabla de tarifas de permisos de la SHA de Maryland, ¿cuál es la tarifa base de un permiso de transporte cuando la carga combinada pesa 90,000 pounds (45 toneladas) o menos?","options":["$10.00","$30.00","$50.00","$100.00"],"explanation":"El manual de la SHA fija una tarifa base de $30.00 para un permiso de transporte cuando una carga sobredimensionada/combinada pesa menos de 90,000 pounds; las cargas de más de 45 toneladas (90,000 lb) suman $5.00 por cada tonelada adicional. Fuente: MD SHA Hauling Permit Manual (Información General; Tarifas de Permisos)."},"11":{"q":"Para una carga con permiso que excede 45 toneladas (90,000 pounds), ¿cuánto añade la SHA de Maryland a la tarifa del permiso por cada tonelada adicional?","options":["$2.00 por tonelada","$5.00 por tonelada","$10.00 por tonelada","$25.00 por tonelada"],"explanation":"El manual establece que para cargas que excedan 45 toneladas (90,000 lb), se cobra $5.00 adicionales por cada tonelada adicional (por ejemplo, 50 toneladas = $55.00). Fuente: MD SHA Hauling Permit Manual (Información General; tabla de Tarifas de Permisos)."},"12":{"q":"Según las reglas generales de horarios de circulación de Maryland, ¿cuándo NO se puede mover una carga con permiso por sobredimensión/sobrepeso?","options":["Solo entre la medianoche y las 6:00 a.m. en días hábiles","Cualquier sábado después de las 12:00 del mediodía y todo el día domingo","Solo el primer lunes de cada mes","Solo durante las horas pico señalizadas en Baltimore"],"explanation":"Según el manual de la SHA y el Título 11 de COMAR, ninguna carga con permiso puede moverse ningún sábado después de las 12:00 del mediodía, ningún domingo, ni durante los períodos festivos indicados. Por lo demás, la regla es la circulación diurna (desde 1/2 hora después del amanecer hasta 1/2 hora antes del atardecer). Fuente: MD SHA Hauling Permit Manual (Horarios de Circulación); COMAR 11.04."},"13":{"q":"¿A partir de qué ancho una carga con permiso (que no sea una casa móvil/modular) requiere por primera vez un solo vehículo escolta privado en Maryland?","options":["Más de 10 feet de ancho","Más de 12 feet de ancho","Más de 13 feet de ancho","Más de 14 feet de ancho"],"explanation":"El manual de la SHA exige una escolta privada para cargas de más de 13 feet de ancho (las cargas en el rango de 13'1\"–13'11\" necesitan 1 escolta privada), y se requieren dos escoltas privadas a partir de 14 feet de ancho. Fuente: MD SHA Hauling Permit Manual (Ancho; Escoltas – Condiciones Generales)."},"14":{"q":"En Maryland, una carga con permiso de 14 feet de ancho o más requiere ¿cuántos vehículos escolta privados?","options":["No se requiere escolta","Una escolta privada","Dos escoltas privadas","Cuatro escoltas privadas"],"explanation":"El manual de la SHA especifica que todas las cargas de 14 feet de ancho o más requieren dos escoltas privadas para moverse dentro y a través de Maryland. Fuente: MD SHA Hauling Permit Manual (Ancho; Escoltas – Condiciones Generales)."},"15":{"q":"¿Qué dimensión o peso convierte a una carga con permiso de Maryland en una 'Super Carga' en las autopistas Interestatales?","options":["Más de 90,000 pounds de peso bruto o 11 feet de ancho","Exceder 150,000 pounds (75 toneladas) o 27,000 pounds en cualquier eje","Exceder 80,000 pounds o 12 feet de alto","Cualquier carga que requiera una sola escolta privada"],"explanation":"El manual de la SHA define las Super Cargas, entre otras, como aquellas que exceden 150,000 lb (75 toneladas) o exceden 27,000 lb en cualquier eje en las autopistas Interestatales (o que exceden 120,000 lb / 60 toneladas o 27,000 lb por eje en las carreteras estatales de Maryland), o que miden 120 ft de largo, 16 ft de ancho o 16 ft de alto. Fuente: MD SHA Hauling Permit Manual (Escoltas – Condiciones Generales, Super Cargas)."},"16":{"q":"En las carreteras ESTATALES (no Interestatales) de Maryland, ¿al exceder qué peso bruto se clasifica una carga con permiso como una 'Super Carga' excesiva?","options":["80,000 pounds (40 toneladas)","100,000 pounds (50 toneladas)","120,000 pounds (60 toneladas)","150,000 pounds (75 toneladas)"],"explanation":"El manual de la SHA clasifica una carga como Super Carga en las carreteras estatales de Maryland cuando excede 120,000 pounds (60 toneladas) o excede 27,000 pounds en cualquier eje. El umbral de 150,000 pounds (75 toneladas) aplica a las autopistas Interestatales. Fuente: MD SHA Hauling Permit Manual (Super Cargas)."},"17":{"q":"Excepto en las autopistas Interestatales, ¿qué tolerancia de carga por eje permite la ley de Maryland a un vehículo agrícola que transporta productos agrícolas desde un campo durante los períodos de cosecha indicados?","options":["Una tolerancia de carga por eje del 5%","Una tolerancia de carga por eje del 10%","Una tolerancia de carga por eje del 15%","No se permite ninguna tolerancia en ningún momento"],"explanation":"El artículo de Transporte de Maryland § 24-109 permite a los vehículos agrícolas (fuera de las Interestatales) una tolerancia por eje del 5% normalmente, aumentada a una tolerancia de carga por eje del 15% durante los períodos de cosecha definidos (por ejemplo, trigo del June 1–Aug 15, maíz del July 1–Dec 1), con una tolerancia de peso bruto del 5% dentro de 100 miles del campo. Fuente: Md. Transp. § 24-109 (variación agrícola en época de cosecha)."},"18":{"q":"Excepto en las autopistas Interestatales, ¿qué tolerancia de carga por eje se permite a una combinación que transporta productos forestales desde un bosque (semirremolque de 45 feet o menos) del June 1 al September 30?","options":["Tolerancia de carga por eje del 5%","Tolerancia de carga por eje del 10%","Tolerancia de carga por eje del 15%","Tolerancia de carga por eje del 20%"],"explanation":"El artículo de Transporte de Maryland § 24-109 permite a una combinación de productos forestales (semirremolque de 45 ft o menos, cargado fuera de la vía, no en las Interestatales) una tolerancia por eje del 5%, aumentada al 15% del June 1 al September 30. Fuente: Md. Transp. § 24-109 (variación de productos forestales)."},"19":{"q":"Maryland (siguiendo la ley federal) permite a un vehículo pesado una pequeña asignación de peso adicional para compensar el peso de ¿qué dispositivo de ahorro de combustible, sin violar los límites de peso bruto/por eje/de la fórmula de puentes?","options":["Un sistema automático de inflado de neumáticos, hasta 1,000 pounds adicionales","Una unidad de potencia auxiliar / tecnología de reducción de ralentí, hasta 550 pounds adicionales","Una unidad de refrigeración, hasta 2,000 pounds adicionales","Un neumático sencillo de base ancha, hasta 250 pounds adicionales"],"explanation":"El artículo de Transporte de Maryland § 24-109 permite hasta 550 pounds adicionales en total en el peso bruto, por eje, por tándem o de la fórmula de puentes para tener en cuenta una unidad de potencia auxiliar o una unidad de tecnología de reducción de ralentí, en concordancia con la ley federal. Fuente: Md. Transp. § 24-109 (asignación por reducción de ralentí); 23 CFR 658.17."},"20":{"q":"En Maryland, ¿qué clase de CDL se requiere para operar un vehículo combinado con una Clasificación de Peso Bruto Combinado (GCWR) de 26,001 pounds o más, donde la unidad remolcada tiene un GVWR superior a 10,000 pounds?","options":["Clase A","Clase B","Clase C","Clase D"],"explanation":"Maryland define una CDL Clase A como un vehículo combinado con una unidad de potencia/tractor y remolque(s) con un GCWR de 26,001+ pounds, donde la unidad remolcada tiene un GVWR superior a 10,000 pounds. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"21":{"q":"Según las reglas de la Maryland MVA, ¿qué clase de CDL autoriza conducir cualquier vehículo sencillo con un GVWR de 26,001 pounds o más (remolcando una unidad que no exceda 10,000 pounds)?","options":["Clase A","Clase B","Clase C","Clase M"],"explanation":"Una CDL Clase B de Maryland cubre vehículos sencillos con un GVWR de 26,001+ pounds, o un vehículo de ese tipo que remolque una unidad que no exceda 10,000 pounds de GVWR. Algunos ejemplos incluyen camiones de caja rígida y la mayoría de los autobuses. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"22":{"q":"Un vehículo de Maryland está clasificado por debajo de 26,001 pounds, pero está diseñado para transportar 16 o más pasajeros (incluyendo al conductor), o transporta materiales peligrosos con cartel (placarded). ¿Qué clase de CDL aplica?","options":["Clase A","Clase B","Clase C","Clase E"],"explanation":"La CDL Clase C de Maryland cubre vehículos comerciales más pequeños que no cumplen los criterios de peso de la Clase A o B, pero que están diseñados para transportar 16+ pasajeros (incluyendo al conductor) o transportar materiales peligrosos que requieren carteles (placards). Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151."},"23":{"q":"En Maryland, ¿qué código de endoso se requiere para operar un vehículo diseñado para transportar 16 o más pasajeros, como un autobús?","options":["Endoso N","Endoso P","Endoso T","Endoso H"],"explanation":"Maryland requiere el endoso P (Pasajeros) para operar vehículos que transportan 16 o más pasajeros. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"24":{"q":"Para conducir un autobús escolar en Maryland, ¿qué combinación de endosos requiere la MVA?","options":["Solo el endoso S","Solo el endoso P","Ambos endosos P (Pasajeros) y S (Autobús Escolar)","Ambos endosos S (Autobús Escolar) y H (HazMat)"],"explanation":"Maryland requiere ambos endosos, P (Pasajeros) y S (Autobús Escolar), para operar un autobús escolar. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"25":{"q":"¿Qué endoso de CDL de Maryland se requiere para operar un vehículo que transporta líquidos o gases en un tanque, como un camión cisterna de combustible o de agua?","options":["Endoso H","Endoso N","Endoso T","Endoso P"],"explanation":"Maryland usa el endoso N (Vehículo Cisterna) para vehículos que transportan líquidos o gases en tanques, como camiones cisterna de combustible o de agua. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"26":{"q":"En Maryland, ¿qué combina el endoso 'X' en una CDL?","options":["Pasajeros (P) y Autobús Escolar (S)","Vehículo Cisterna (N) y HazMat (H)","Dobles/Triples (T) y Cisterna (N)","HazMat (H) y Pasajeros (P)"],"explanation":"El endoso X de Maryland es una combinación de los endosos N (Vehículo Cisterna) y H (HazMat), que autoriza el transporte de materiales peligrosos en vehículos cisterna. Fuente: Maryland MVA, CDL Classifications, Endorsements & Restrictions."},"27":{"q":"¿Cuál es la edad mínima para obtener una CDL de Maryland restringida a la conducción comercial intraestatal (solo dentro de Maryland)?","options":["16 años","18 años","21 años","25 años"],"explanation":"Maryland permite una CDL a los 18 para la conducción intraestatal (dentro de Maryland), mientras que la conducción interestatal requiere tener 21 años. Fuente: Maryland MVA, Get or Renew a CDL; Manual DL-151."},"28":{"q":"Según la Maryland MVA, ¿cuál es la edad mínima requerida para conducir un vehículo comercial en el comercio interestatal (cruzando líneas estatales)?","options":["18 años","19 años","21 años","23 años"],"explanation":"Maryland requiere que los conductores tengan al menos 21 años para operar un vehículo con CDL de manera interestatal (cruzando líneas estatales), para transportar materiales peligrosos que requieren carteles, o para transportar pasajeros de manera interestatal. Fuente: Maryland MVA, Get or Renew a CDL."},"29":{"q":"A un titular de CDL de Maryland de 19 años se le restringe legalmente hacer ¿cuál de las siguientes acciones?","options":["Conducir un camión de unidad rígida dentro de Maryland","Conducir un vehículo comercial cruzando líneas estatales","Tener un endoso de Pasajeros (P) para uso intraestatal","Conducir un vehículo Clase B dentro de Maryland"],"explanation":"Un conductor de Maryland que tenga entre 18 y 21 años no puede conducir un vehículo comercial fuera de Maryland (interestatal), no puede conducir un vehículo que requiera carteles de materiales peligrosos, y no puede operar equipos de remolques dobles/triples. Fuente: Maryland MVA / Manual DL-151."},"30":{"q":"Según la regla federal aplicada en Maryland, ¿durante cuánto tiempo debe un solicitante tener un Permiso de Aprendiz Comercial (CLP) antes de que se le permita tomar el examen de habilidades (de manejo) de la CDL?","options":["Al menos 7 días","Al menos 10 días","Al menos 14 días","Al menos 30 días"],"explanation":"Maryland aplica la regla federal que exige que un CLP se mantenga durante al menos 14 días antes de poder tomar el examen de habilidades (de manejo) de la CDL. Fuente: Maryland MVA, Get or Renew a CDL; 49 CFR 383.25."},"31":{"q":"Antes de que se le emita un Permiso de Aprendiz Comercial (CLP) de Maryland, un solicitante ya debe poseer ¿qué credencial?","options":["Una licencia de conducir válida de Maryland (que no sea de motocicleta)","Una licencia de motocicleta de Maryland","Una tarjeta TWIC federal","Una CDL de otro estado"],"explanation":"Maryland requiere que los solicitantes de CLP ya posean una licencia de conducir válida de Maryland (que no sea una licencia solo de motocicleta) y que aprueben los exámenes de visión y de conocimientos. Fuente: Maryland MVA / Manual DL-151."},"32":{"q":"¿Qué conjunto de documentos requiere la Maryland MVA que presente un solicitante al solicitar una CDL?","options":["Solo una licencia de conducir vigente y una foto","Prueba de identidad, edad, número de Seguro Social y residencia en Maryland","Solo un pasaporte y una carta del empleador","Prueba de identidad y una tarjeta de registro del vehículo"],"explanation":"La Maryland MVA requiere prueba de identidad, edad, número de Seguro Social y residencia en Maryland (la presencia legal se establece a través de estos documentos de identidad). Fuente: Maryland MVA, Get or Renew a CDL."},"33":{"q":"¿Dónde se debe completar la Capacitación para Conductores de Nivel Inicial (ELDT) para un solicitante por primera vez de una CDL Clase A o B de Maryland?","options":["Cualquier escuela de manejo privada que el solicitante elija","Un proveedor incluido en el FMCSA Training Provider Registry","Solo en una oficina sucursal de la Maryland MVA","Un programa acreditado por el Maryland State Department of Education"],"explanation":"Maryland requiere que la ELDT para los solicitantes por primera vez de Clase A/B (y para los endosos S, P y H por primera vez) se complete a través de un proveedor incluido en el FMCSA Training Provider Registry antes del examen de habilidades o el examen de conocimientos de materiales peligrosos. Fuente: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"34":{"q":"¿Para cuál de las siguientes situaciones requiere Maryland la Capacitación para Conductores de Nivel Inicial (ELDT) antes del examen?","options":["Renovar una CDL Clase A existente","Añadir una restricción de transmisión automática","Obtener una CDL Clase A o B por primera vez, o añadir S, P o H por primera vez","Actualizar una dirección residencial en la CDL"],"explanation":"Maryland exige la ELDT para las CDL Clase A o B por primera vez y para añadir por primera vez los endosos de Autobús Escolar (S), Pasajeros (P) o HazMat (H). No se requiere para renovaciones ni cambios administrativos. Fuente: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380."},"35":{"q":"¿Cuál es una de las cuatro categorías de autocertificación médica entre las que debe elegir un titular de CDL de Maryland?","options":["Interestatal No Exento (NI)","Comercial Restringido (RC)","Interestatal Provisional (PI)","HazMat Limitado (LH)"],"explanation":"Las cuatro categorías de autocertificación de Maryland son Interestatal No Exento (NI), Interestatal Exento (EI), Intraestatal No Exento (NA) e Intraestatal Exento (EA). Fuente: Maryland MVA, CDL Medical Certification Requirements."},"36":{"q":"Un titular de CDL de Maryland que conduce cruzando líneas estatales y debe cumplir con todos los requisitos federales de calificación del conductor debe autocertificarse en ¿qué categoría?","options":["Intraestatal Exento (EA)","Interestatal Exento (EI)","Interestatal No Exento (NI)","Intraestatal No Exento (NA)"],"explanation":"Interestatal No Exento (NI) aplica a un titular de CDL que conduce cruzando líneas estatales y cumple con todos los requisitos federales de calificación, incluyendo un certificado médico válido del DOT. Fuente: Maryland MVA, CDL Medical Certification Requirements."},"37":{"q":"En Maryland, antes de poder tomar el examen de conocimientos del endoso HazMat (H) y de que se emita el endoso, el solicitante debe aprobar ¿qué?","options":["Una evaluación de amenaza a la seguridad de la TSA con una verificación de antecedentes basada en huellas dactilares","Una inspección estatal de emisiones del vehículo","Únicamente una consulta de pre-empleo en el clearinghouse de drogas y alcohol","Únicamente una auditoría del historial de conducción de la Policía Estatal de Maryland"],"explanation":"Maryland requiere que los solicitantes de HazMat aprueben una evaluación de amenaza a la seguridad de la TSA, que incluye una Verificación de Antecedentes basada en huellas dactilares (procesada a través del DPSCS), además de aprobar el examen de conocimientos de materiales peligrosos. Fuente: Maryland MVA, CDL HazMat Endorsement; 49 CFR Part 1572."},"38":{"q":"Después de recibir la aprobación de la TSA, ¿dentro de qué plazo debe un solicitante de Maryland obtener el endoso HazMat?","options":["Dentro de 30 días","Dentro de 90 días","Dentro de seis meses","Dentro de dos años"],"explanation":"Maryland requiere que el solicitante obtenga el endoso HazMat dentro de los seis meses a partir de la fecha de la carta de aprobación de la TSA. Fuente: Maryland MVA, CDL HazMat Endorsement."},"39":{"q":"¿Con qué frecuencia debe un titular de CDL de Maryland con un endoso de Autobús Escolar (S) renovar normalmente su certificado del examinador médico para mantener válido ese endoso?","options":["Cada 6 meses","Anualmente (cada año)","Cada 2 años","Cada 5 años"],"explanation":"Si bien la mayoría de los certificados del examinador médico son válidos hasta por dos años, los titulares del endoso de Autobús Escolar (S) de Maryland generalmente necesitan una certificación médica anual para mantener esa designación. Fuente: Maryland MVA, CDL Medical Certification Requirements."},"40":{"q":"En Maryland, ¿cuál es la concentración máxima de alcohol en sangre/aliento (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.04","0.08","0.02","0.10"],"explanation":"Un conductor de CMV en Maryland queda inhabilitado por conducir con un BAC de 0.04 o más, la mitad del límite de 0.08 para conductores no comerciales. Fuente: Maryland Transportation Article §16-812(a) y §11-127.1; Maryland CDL Manual; 49 CFR 383.51 Table 1."},"41":{"q":"Según la ley de consentimiento implícito de Maryland, ¿qué sucede si a un titular de CDL se le solicita legalmente realizar una prueba química de alcohol y se rehúsa?","options":["La CDL se inhabilita por al menos 1 año (una primera negativa se trata como una infracción grave)","El conductor recibe una multa pero conserva la CDL","La CDL se suspende por 60 días","No pasa nada hasta que haya una condena"],"explanation":"Maryland aplica el consentimiento implícito: rehusarse a una prueba química solicitada legalmente inhabilita la CDL por 1 año por una primera infracción, igual que otras infracciones graves. Fuente: Maryland Transportation Article §16-205.1 y §16-812(b); 49 CFR 383.51 Table 1."},"42":{"q":"¿Cuál es el período de inhabilitación de la CDL en Maryland por una primera infracción grave (como un DUI, un BAC de 0.04+ en un CMV, o una negativa a la prueba) cuando NO se transportan materiales peligrosos con cartel?","options":["1 año","60 días","3 años","6 meses"],"explanation":"Una primera infracción grave inhabilita la CDL por 1 año (3 años si ocurrió mientras se transportaba HazMat con cartel). Fuente: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"43":{"q":"Si un conductor de CDL de Maryland comete una primera infracción grave (por ejemplo, DUI o BAC de 0.04+) mientras transporta materiales peligrosos que requieren cartel, ¿cuánto dura la inhabilitación?","options":["3 años","1 año","5 años","De por vida"],"explanation":"La inhabilitación estándar de 1 año por primera infracción se aumenta a 3 años cuando el conductor transportaba materiales peligrosos con cartel en ese momento. Fuente: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"44":{"q":"¿Cuál es la inhabilitación de la CDL en Maryland por una SEGUNDA infracción grave (un segundo DUI, BAC de 0.04+, negativa, etc.) cometida en un incidente separado?","options":["Inhabilitación de por vida","5 años","3 años","2 años"],"explanation":"Una segunda infracción grave resulta en la inhabilitación de la CDL de por vida, aunque la reinstauración puede ser posible después de 10 años en casos que califiquen. Fuente: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"45":{"q":"Usar un CMV para cometer un delito grave que involucre la fabricación, distribución o suministro de una sustancia controlada resulta en ¿qué sanción de CDL en Maryland?","options":["Inhabilitación de por vida sin reinstauración a los 10 años","Inhabilitación de 1 año","Inhabilitación de 3 años","Inhabilitación de por vida, pero elegible para reinstauración después de 10 años"],"explanation":"Un delito grave que involucre la fabricación, distribución o suministro de una sustancia controlada usando un CMV es una inhabilitación de por vida que NO es elegible para la reinstauración a los 10 años. Fuente: 49 CFR 383.51 Table 1; Maryland Transportation Article §16-812."},"46":{"q":"¿Cuántas infracciones de tránsito serias dentro de un período de 3 años generan una inhabilitación de la CDL de 60 días en Maryland?","options":["2 infracciones serias","3 infracciones serias","4 infracciones serias","1 infracción seria"],"explanation":"Dos infracciones de tránsito serias dentro de 3 años (en cualquier combinación, en un CMV) resultan en una inhabilitación de 60 días. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"47":{"q":"Tres infracciones de tránsito serias dentro de un período de 3 años resultan en ¿qué período de inhabilitación de la CDL en Maryland?","options":["120 días","60 días","180 días","1 año"],"explanation":"Tres infracciones de tránsito serias dentro de 3 años inhabilitan la CDL por 120 días; esto se suma a cualquier inhabilitación previa de 60 días. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"48":{"q":"¿Por cuántas millas por hora sobre el límite señalizado debe excederse una infracción de velocidad para contar como una 'infracción de tránsito seria' a efectos de la CDL en Maryland?","options":["15 mph o más sobre el límite","10 mph o más sobre el límite","20 mph o más sobre el límite","25 mph o más sobre el límite"],"explanation":"Conducir a 15 mph o más por encima del límite de velocidad señalizado es una infracción de tránsito seria que cuenta para las inhabilitaciones de 2-en-3-años (60 días) y 3-en-3-años (120 días). Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"49":{"q":"¿Cuál de las siguientes se clasifica como una 'infracción de tránsito seria' para un titular de CDL de Maryland?","options":["Conducción imprudente","Estacionarse en un carril de bomberos","Una luz trasera fundida","Una calcomanía de registro vencida"],"explanation":"Las infracciones de tránsito serias incluyen la conducción imprudente, exceder la velocidad en 15+ mph, cambios de carril indebidos/erráticos, seguir demasiado de cerca, enviar mensajes de texto y usar el teléfono de mano. Los problemas rutinarios de equipo/estacionamiento no son infracciones serias. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 2."},"50":{"q":"En Maryland, conducir un CMV mientras se envían mensajes de texto en violación de la ley se trata como ¿qué tipo de infracción para la inhabilitación de la CDL?","options":["Una infracción de tránsito seria","Una infracción grave","Una infracción de fuera de servicio (out-of-service)","Una infracción de cruce de ferrocarril"],"explanation":"Enviar mensajes de texto mientras se conduce un CMV es una infracción de tránsito seria que cuenta para las inhabilitaciones de 60 días (2-en-3-años) y 120 días (3-en-3-años). Maryland prohíbe los mensajes de texto bajo una ley de aplicación primaria. Fuente: Maryland Transportation Article §21-1124.1; 49 CFR 383.51 Table 2."},"51":{"q":"Según la ley de Maryland, un conductor adulto de un CMV que usa un teléfono móvil de mano mientras el vehículo está en movimiento comete ¿qué tipo de infracción de CDL?","options":["Una infracción de tránsito seria","Una infracción menor no reportable","Una infracción grave con una inhabilitación de 1 año","Una infracción de una orden de fuera de servicio (out-of-service)"],"explanation":"Usar un teléfono de mano mientras se conduce un CMV es una infracción de tránsito seria que cuenta para los umbrales de inhabilitación de 60/120 días. La prohibición del teléfono de mano en Maryland es una infracción primaria. Fuente: Maryland Transportation Article §21-1124.2; 49 CFR 383.51 Table 2."},"52":{"q":"¿Cuál es la inhabilitación mínima de la CDL en Maryland por una PRIMERA infracción de cruce a nivel de ferrocarril-carretera?","options":["No menos de 60 días","No menos de 30 días","No menos de 120 días","No menos de 1 año"],"explanation":"Una primera infracción de cruce a nivel de ferrocarril-carretera inhabilita la CDL por no menos de 60 días. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"53":{"q":"Una SEGUNDA infracción de cruce a nivel de ferrocarril-carretera dentro de un período de 3 años resulta en ¿qué inhabilitación mínima de la CDL en Maryland?","options":["No menos de 120 días","No menos de 60 días","No menos de 1 año","No menos de 180 días"],"explanation":"Una segunda infracción de cruce de ferrocarril dentro de 3 años inhabilita la CDL por no menos de 120 días. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"54":{"q":"Una TERCERA infracción de cruce a nivel de ferrocarril-carretera dentro de un período de 3 años resulta en ¿qué inhabilitación mínima de la CDL en Maryland?","options":["No menos de 1 año","No menos de 120 días","No menos de 180 días","De por vida"],"explanation":"Una tercera (o posterior) infracción de cruce de ferrocarril dentro de 3 años inhabilita la CDL por no menos de 1 año. Fuente: Maryland CDL Manual; 49 CFR 383.51 Table 3."},"55":{"q":"¿Cuál es el rango de inhabilitación de la CDL en Maryland por una PRIMERA condena de violar una orden de fuera de servicio (out-of-service) mientras se conduce un CMV que NO transporta HazMat?","options":["180 días hasta 1 año","60 a 120 días","1 a 3 años","30 a 90 días"],"explanation":"Una primera violación de una orden de fuera de servicio (no HazMat, menos de 16 pasajeros) inhabilita la CDL por no menos de 180 días y no más de 1 año. Fuente: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"56":{"q":"Una SEGUNDA violación de una orden de fuera de servicio (out-of-service) dentro de cualquier período de 10 años (no HazMat) resulta en ¿qué rango de inhabilitación de la CDL en Maryland?","options":["2 a 5 años","180 días a 1 año","1 a 3 años","De por vida"],"explanation":"Una segunda violación de una orden de fuera de servicio dentro de 10 años inhabilita la CDL por no menos de 2 años y no más de 5 años. Fuente: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"57":{"q":"Una PRIMERA violación de una orden de fuera de servicio (out-of-service) mientras se transportan materiales peligrosos con cartel o mientras se opera un vehículo diseñado para 16 o más pasajeros conlleva ¿qué rango de inhabilitación de la CDL en Maryland?","options":["180 días hasta 2 años","180 días hasta 1 año","2 a 5 años","3 a 5 años"],"explanation":"Una primera violación de una orden de fuera de servicio que involucre HazMat con cartel o un vehículo de 16+ pasajeros inhabilita la CDL por no menos de 180 días y no más de 2 años. Fuente: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4."},"58":{"q":"¿Cuándo puede la Maryland MVA iniciar una inhabilitación de la CDL relacionada con una detención comercial por alto BAC?","options":["Tras una citación/acción administrativa per se por un alto BAC en un CMV, incluso antes de la condena","Solo después de una condena penal en el tribunal","Solo después de una segunda infracción","Solo si el conductor provoca un choque"],"explanation":"Maryland puede inhabilitar una CDL con base en una citación o una orden administrativa per se por un alto BAC mientras se conduce un vehículo comercial, incluso antes de cualquier condena judicial. Fuente: MDOT MVA CDL Disqualification & Reinstatement page; Maryland Transportation Article §16-205.1, §16-812."},"59":{"q":"Después de una inhabilitación de la CDL de por vida, un conductor de Maryland generalmente puede solicitar la reinstauración después de ¿cuántos años, siempre que se cumplan los requisitos de elegibilidad?","options":["10 años","5 años","3 años","Nunca — la inhabilitación de por vida es permanente en todos los casos"],"explanation":"Una inhabilitación de la CDL de por vida puede reducirse a un mínimo de 10 años si el conductor cumple los requisitos de reinstauración, excepto en infracciones como el narcotráfico o la trata de personas mediante un CMV, que no permiten reinstauración. Fuente: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1."},"60":{"q":"Según la ley \"Muévase\" (Move Over) de Maryland, cuando un conductor con CDL se aproxima a un vehículo de emergencia detenido, una grúa o un vehículo de servicio que muestra luces de advertencia, ¿cuál es la PRIMERA acción que exige la ley?","options":["Cambiarse a un carril que no esté inmediatamente contiguo al vehículo detenido, si es seguro y legal hacerlo","Detenerse por completo hasta que un oficial le indique que puede continuar","Tocar la bocina de forma continua mientras pasa junto al vehículo detenido","Reducir la velocidad a exactamente 20 mph por debajo del límite establecido y mantenerse en el carril"],"explanation":"El artículo de Transporte 21-405.1 de Maryland (ley \"Muévase\") exige que el conductor se cambie a un carril que no esté inmediatamente contiguo al vehículo detenido cuando sea seguro y legal. Solo si el cambio de carril no es seguro o no es posible, el conductor debe en cambio reducir a una velocidad razonable y prudente. Fuente: Md. Code, Transportation 21-405.1; orientación de Maryland MVA/MSP."},"61":{"q":"Si un conductor con CDL de Maryland no puede cambiar de carril de forma segura al pasar junto a un vehículo de emergencia o de servicio detenido con las luces encendidas, ¿qué debe hacer en su lugar?","options":["Reducir a una velocidad que sea razonable y prudente para las condiciones existentes","Detenerse por completo en el acotamiento hasta que se despeje la escena","Mantener el límite de velocidad establecido y pasar sin cambiar la velocidad","Orillarse en el camellón y esperar a que el tránsito despeje el carril"],"explanation":"Según Md. Transportation 21-405.1, si moverse de carril no es seguro o no es posible, el conductor debe reducir a una velocidad razonable y prudente que sea segura para las condiciones. La ley de Maryland no establece una sola cifra fija; exige una velocidad razonable para las condiciones. Fuente: Md. Code, Transportation 21-405.1."},"62":{"q":"A partir de una ampliación del 1 de octubre de 2022, ¿a cuál de los siguientes, cuando están detenidos al costado de la vía, se aplica la ley \"Muévase\" de Maryland?","options":["Cualquier vehículo que muestre luces de emergencia, conos de advertencia o bengalas de carretera, incluidos los automóviles de pasajeros comunes","Solo vehículos identificados de policía y bomberos que usan luces intermitentes","Solo grúas y vehículos de mantenimiento de carreteras","Solo vehículos comerciales de más de 26,001 libras"],"explanation":"A partir del 1 de octubre de 2022, Maryland amplió el 21-405.1 de modo que el deber de \"Muévase\" se aplica a CUALQUIER vehículo detenido que muestre luces de emergencia, bengalas de carretera o conos de advertencia, no solo a vehículos de emergencia o de servicio. Fuente: Md. Code, Transportation 21-405.1 (enmienda de 2022); Maryland MVA."},"63":{"q":"Cuando un autobús escolar de Maryland está detenido con sus luces rojas intermitentes encendidas y el brazo de pare extendido en un camino de dos carriles sin división, ¿qué debe hacer un conductor con CDL que se aproxima desde CUALQUIERA de las dos direcciones?","options":["Detenerse y permanecer detenido hasta que las luces dejen de parpadear y el autobús se mueva o indique que se puede avanzar","Reducir a 15 mph y pasar por la izquierda con precaución","Detenerse solo si viaja en la misma dirección que el autobús","Continuar si no se ven niños cerca del autobús"],"explanation":"En una calzada de doble sentido sin división en Maryland, el tránsito en AMBAS direcciones debe detenerse ante un autobús escolar con luces rojas intermitentes y el brazo de pare extendido, y permanecer detenido hasta que las señales se apaguen. Fuente: Md. Code, Transportation 21-706; Maryland MVA/MSP."},"64":{"q":"Según la excepción de carretera dividida de Maryland, ¿cuándo NO están obligados a detenerse los conductores que viajan en la dirección OPUESTA a un autobús escolar detenido?","options":["Cuando las direcciones de circulación están separadas por un camellón o barrera física, como césped, tierra o un divisor de concreto","Cuando el camino tiene cuatro o más carriles, sin importar si hay camellón","Cuando una doble línea amarilla central separa las direcciones de circulación","Cuando el autobús está a más de 100 pies de distancia en los carriles opuestos"],"explanation":"Maryland exime de detenerse al tránsito en sentido opuesto SOLO cuando un camellón físico, una barrera o una franja sin pavimentar separa las calzadas. Las líneas pintadas NO crean una carretera dividida, por lo que una doble línea amarilla por sí sola no activa la excepción. Fuente: Md. Code, Transportation 21-706; orientación de Maryland MVA."},"65":{"q":"En una carretera dividida de Maryland con un camellón físico, ¿quién aún debe detenerse cuando un autobús escolar del lado opuesto enciende sus luces rojas intermitentes?","options":["Los conductores que viajan en la misma dirección que el autobús, detrás de él","Todos los conductores en ambas calzadas deben detenerse","Ningún conductor está obligado a detenerse en ninguna carretera dividida","Solo los conductores en el carril inmediatamente contiguo al camellón"],"explanation":"Incluso en una carretera dividida, el tránsito que sigue al autobús en la MISMA dirección debe detenerse. Solo el tránsito en sentido contrario separado por el camellón físico queda exento. Fuente: Md. Code, Transportation 21-706."},"66":{"q":"¿Cuál es el límite de velocidad máximo absoluto que puede establecerse en cualquier carretera de Maryland, incluidas las autopistas interestatales y las vías rápidas?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"La ley de Maryland limita la velocidad máxima a 70 mph, que puede establecerse solo en ciertas autopistas interestatales y vías rápidas; ninguna carretera de Maryland puede establecer más de 70 mph. Fuente: Md. Code, Transportation 21-801.1; MDOT SHA."},"67":{"q":"¿Cómo establece Maryland el límite de velocidad máximo para camiones y otros vehículos comerciales en comparación con los automóviles de pasajeros en la misma carretera?","options":["Los camiones siguen el mismo máximo establecido que los demás vehículos; Maryland no tiene un límite de velocidad estatal más bajo y separado para camiones","Los camiones están limitados a 55 mph en todo el estado, sin importar el límite establecido","Los camiones están limitados a 10 mph por debajo del límite establecido en todas las carreteras","Los camiones están limitados a 65 mph mientras que los automóviles pueden ir a 70 mph en todas las interestatales"],"explanation":"A diferencia de algunos estados, Maryland NO establece un límite de velocidad estatal más bajo y separado para camiones. Los vehículos comerciales obedecen los mismos límites establecidos que el resto del tránsito (hasta el tope de 70 mph). Fuente: Md. Code, Transportation 21-801.1; orientación sobre límites de velocidad de MDOT SHA."},"68":{"q":"¿Cuáles vehículos comerciales deben DETENERSE antes de cruzar vías de ferrocarril a nivel según las normas que Maryland aplica a los conductores con CDL?","options":["Los autobuses que llevan pasajeros y los vehículos que transportan materiales peligrosos con rótulos (placards)","Todos los vehículos comerciales de más de 10,000 libras","Solo los vehículos que arrastran remolques dobles o triples","Solo los vehículos cisterna vacíos que anteriormente transportaron inflamables"],"explanation":"Maryland sigue la norma federal (49 CFR 392.10) adoptada en su manual de CDL: los autobuses que llevan pasajeros y los vehículos con materiales peligrosos rotulados (placards) deben detenerse en los cruces a nivel. La mayoría de los demás camiones no están obligados a detenerse, salvo que las señales o los semáforos lo indiquen. Fuente: Manual de CDL de Maryland; 49 CFR 392.10."},"69":{"q":"Cuando un camión con materiales peligrosos rotulados (placards) o un autobús de pasajeros debe detenerse en un cruce de ferrocarril de Maryland, ¿dentro de qué distancia del riel más cercano debe detenerse?","options":["A no menos de 15 pies y a no más de 50 pies del riel más cercano","A no menos de 5 pies y a no más de 25 pies del riel más cercano","A no menos de 25 pies y a no más de 75 pies del riel más cercano","A no menos de 10 pies y a no más de 100 pies del riel más cercano"],"explanation":"Los CMV obligados a detenerse deben hacer alto a no más de 50 pies, pero no más cerca de 15 pies, del riel más cercano, y luego mirar y escuchar antes de continuar. Fuente: Manual de CDL de Maryland; 49 CFR 392.10."},"70":{"q":"Después de detenerse en un cruce de ferrocarril, un conductor de autobús o de un vehículo con materiales peligrosos rotulados (placards) de Maryland puede continuar solo después de hacer ¿qué?","options":["Mirar y escuchar en ambas direcciones por si se acerca un tren y confirmar que el cruce se puede despejar sin detenerse","Cambiar de marcha al menos una vez mientras cruza las vías para mantener el impulso","Esperar obligatoriamente 30 segundos sin importar si viene un tren","Tocar la bocina tres veces antes de entrar al cruce"],"explanation":"Después de detenerse dentro de la zona de 15 a 50 pies, el conductor debe mirar y escuchar en ambos sentidos por si viene un tren y no debe empezar a cruzar a menos que haya espacio para despejar las vías por completo sin detenerse. Los conductores no deben cambiar de marcha mientras están sobre las vías. Fuente: Manual de CDL de Maryland; 49 CFR 392.10."},"71":{"q":"Cuando un conductor con CDL de Maryland debe detener un camión en la parte transitada o en el acotamiento de una carretera, ¿dentro de cuántos minutos deben colocarse los dispositivos de advertencia (triángulos reflectantes)?","options":["Dentro de los 10 minutos posteriores a la detención","Dentro de los 5 minutos posteriores a la detención","Dentro de los 15 minutos posteriores a la detención","Dentro de los 30 minutos posteriores a la detención"],"explanation":"El conductor de un CMV detenido debe colocar los dispositivos de advertencia dentro de los 10 minutos. Esta norma federal se enseña en el Manual de CDL de Maryland y se aplica en Maryland. Fuente: Manual de CDL de Maryland; 49 CFR 392.22."},"72":{"q":"En un camino de dos carriles y doble sentido, ¿dónde debe colocar un conductor con CDL de Maryland los tres triángulos de advertencia requeridos para un camión detenido?","options":["Aproximadamente a 10 pies detrás del vehículo, del lado del tránsito; aproximadamente a 100 pies detrás; y aproximadamente a 100 pies por delante del vehículo","Los tres triángulos a 200 pies detrás del vehículo, en fila","Solo a aproximadamente 50 pies, 150 pies y 250 pies detrás del vehículo","Uno sobre el cofre y dos sobre el techo para maximizar la visibilidad"],"explanation":"En un camino de doble sentido, coloque un triángulo a aproximadamente 10 pies detrás, del lado del tránsito; uno a aproximadamente 100 pies hacia atrás; y uno a aproximadamente 100 pies hacia adelante, de modo que se advierta al tránsito de ambas direcciones. Fuente: Manual de CDL de Maryland; 49 CFR 392.22."},"73":{"q":"En una carretera de un solo sentido o dividida, ¿cómo debe espaciar un conductor con CDL de Maryland los tres triángulos de advertencia detrás de un camión detenido?","options":["A aproximadamente 10 pies, 100 pies y 200 pies hacia el tránsito que se aproxima","A aproximadamente 10 pies, 50 pies y 100 pies hacia el tránsito que se aproxima","A aproximadamente 25 pies, 75 pies y 150 pies hacia el tránsito que se aproxima","A aproximadamente 50 pies, 100 pies y 500 pies hacia el tránsito que se aproxima"],"explanation":"En una carretera de un solo sentido o dividida, los tres triángulos van hacia el tránsito que se aproxima, a aproximadamente 10, 100 y 200 pies del vehículo. Fuente: Manual de CDL de Maryland; 49 CFR 392.22."},"74":{"q":"La ley de Maryland de mantenerse a la derecha exige que un vehículo lento use el carril de la derecha. ¿Cuánto por debajo del límite de velocidad máximo debe ir un vehículo para tener que mantenerse a la derecha (excepto para rebasar o girar a la izquierda)?","options":["10 mph o más por debajo del límite de velocidad máximo aplicable","5 mph o más por debajo del límite de velocidad máximo aplicable","15 mph o más por debajo del límite de velocidad máximo aplicable","20 mph o más por debajo del límite de velocidad máximo aplicable"],"explanation":"Md. Transportation 21-301 exige que todo vehículo que circule a 10 mph o más por debajo del límite máximo (o más lento que el tránsito normal cuando las condiciones lo requieran) se mantenga en el carril de la derecha, excepto al rebasar o al prepararse para girar a la izquierda. Fuente: Md. Code, Transportation 21-301."},"75":{"q":"En una calzada de Maryland con dos o más carriles en la misma dirección, ¿qué determina cuál carril debe usar un camión, un tractor de camión, un remolque o un autobús?","options":["Las indicaciones de cualquier dispositivo de control de tránsito que exija que el vehículo circule por un carril determinado","La preferencia del conductor, ya que las señales de carril no se aplican a los vehículos comerciales","Una regla fija de que todos los camiones deben usar únicamente el carril del extremo izquierdo","El carril que tenga la menor cantidad de vehículos de pasajeros en ese momento"],"explanation":"La ley de Maryland (Transportation 21-301 y las normas de uso de carriles relacionadas) exige que los camiones, tractores de camión, remolques y autobuses obedezcan los dispositivos de control de tránsito que designan carriles específicos para ellos. Fuente: Md. Code, Transportation 21-301; 21-309."},"76":{"q":"¿Por qué se prohíbe en general la circulación de camiones comerciales en la Baltimore-Washington Parkway (el tramo del Servicio de Parques Nacionales de la MD 295)?","options":["Es una parkway federal que prohíbe los vehículos comerciales; los camiones deben usar la I-95 u otras rutas para camiones, salvo que tengan un permiso especial","El pavimento es demasiado angosto para cualquier vehículo más ancho que un automóvil de pasajeros","Es una carretera de peaje que no acepta transpondedores comerciales","Permite camiones solo entre la medianoche y las 5 a.m."],"explanation":"La Baltimore-Washington Parkway, administrada por el NPS, prohíbe los vehículos comerciales; los camiones están señalizados para salir y deben usar la I-95 u otras rutas designadas para camiones. Las casas rodantes (RV) y los autobuses por lo general están permitidos, pero los camiones comerciales no lo están sin un permiso. Fuente: regulaciones de parkways del Servicio de Parques Nacionales; orientación sobre rutas de camiones de Maryland."},"77":{"q":"¿Qué clases de carga están prohibidas en el Fort McHenry Tunnel (I-95) y el Baltimore Harbor Tunnel (I-895) en Maryland?","options":["Explosivos, gasolina y líquidos inflamables a granel, y propano embotellado por encima de los límites permitidos, entre otros materiales peligrosos","Cargas de alimentos refrigerados y animales vivos","Cualquier carga que pese más de 40,000 libras de peso bruto","Todas las cargas transportadas en remolques dobles o triples, sin importar el contenido"],"explanation":"La MDTA prohíbe explosivos, gasolina/líquidos inflamables a granel, ciertos materiales radiactivos y propano embotellado por encima del límite permitido (más de 10 lb por contenedor) en el Fort McHenry Tunnel y el Baltimore Harbor Tunnel. Fuente: lista de materiales peligrosos prohibidos de la MDTA; mdta.maryland.gov."},"78":{"q":"Un conductor con CDL de Maryland que transporta materiales peligrosos rotulados (placards) prohibidos en los túneles de Baltimore, ¿qué ruta debe tomar a través de la zona de Baltimore?","options":["El tramo oeste de la I-695 (el Beltway exterior) rodeando los cruces del puerto","Directamente por el Fort McHenry Tunnel en la I-95 durante horas de menor tránsito","El Baltimore Harbor Tunnel en la I-895 con las luces de emergencia encendidas","Cualquier calle de la ciudad que atraviese el centro de Baltimore y evite los peajes"],"explanation":"Las cargas de materiales peligrosos prohibidas en los túneles deben rodear el puerto usando el tramo oeste de la I-695. Esta ruta es aún más importante desde que el Key Bridge (el cruce sureste de la I-695) colapsó en 2024. Fuente: orientación sobre restricciones/permisos de túneles de la MDTA; mdta.maryland.gov."},"79":{"q":"En las empinadas pendientes de montaña de la I-68 en el oeste de Maryland (cerca de Sideling Hill y Big Savage Mountain), ¿qué dispositivo de seguridad se proporciona para los camiones que pierden el frenado en una bajada larga?","options":["Rampas de escape para camiones sin frenos (escape ramps) que usan una pendiente ascendente y material de detención para detener el vehículo","Túneles obligatorios que obligan a los camiones a reducir la velocidad antes de descender","Carriles de peaje reversibles que se abren solo para camiones averiados","Franjas de pavimento calentado que aumentan la tracción de las llantas en la pendiente"],"explanation":"La I-68 a través del oeste de Maryland tiene pendientes empinadas y largas; se proporcionan rampas de escape para camiones sin frenos (rampas de detención de grava/arena en una pendiente ascendente) para que los camiones con frenos fallados o sobrecalentados puedan detenerse de forma segura. Los conductores deben descender en una marcha baja y usar la técnica de frenado adecuada. Fuente: MDOT SHA; sección de manejo en montaña del Manual de CDL de Maryland."},"80":{"q":"¿Cuál agencia de Maryland emite las Licencias de Conducir Comerciales (CDL)?","options":["La MDOT Motor Vehicle Administration (MVA)","La División de Vehículos Comerciales de la Policía Estatal de Maryland","La Federal Motor Carrier Safety Administration (FMCSA)","El Departamento de Trabajo de Maryland"],"explanation":"Las CDL en Maryland son emitidas por la MDOT Motor Vehicle Administration (MVA). La FMCSA establece las normas federales de la CDL, pero no emite la licencia en sí. Fuente: Maryland MVA, páginas de Licencia de Conducir Comercial."},"81":{"q":"Antes de programar el examen de destrezas (en carretera) de la CDL en Maryland, ¿cuánto tiempo debe haber tenido su Permiso de Aprendiz Comercial (CLP)?","options":["Al menos 14 días","Al menos 7 días","Al menos 30 días","Al menos 60 días"],"explanation":"Maryland sigue la norma federal: el titular de un CLP no es elegible para tomar el examen de destrezas de la CDL hasta al menos 14 días después de que se emite el CLP. Fuente: Maryland MVA, Obtener o Renovar una CDL."},"82":{"q":"¿Qué capacitación debe completarse antes de que un solicitante de Maryland pueda tomar el examen de destrezas de la CDL para una primera licencia Clase A o Clase B?","options":["Capacitación para Conductores Principiantes (ELDT)","Un curso de manejo defensivo aprobado por el estado","Un seminario de materiales peligrosos de la FMCSA","Una orientación en aula de 40 horas de la MVA"],"explanation":"Maryland no le permitirá tomar el examen de destrezas hasta que complete la Capacitación para Conductores Principiantes (ELDT) exigida a nivel federal, requerida para una primera CDL Clase A o B y para los primeros endosos P, S o H. Fuente: norma ELDT de Maryland MVA / FMCSA."},"83":{"q":"El examen de destrezas de la CDL de Maryland tiene tres partes que deben aprobarse. ¿Cuáles son?","options":["Inspección del vehículo antes del viaje, destrezas básicas de control del vehículo y manejo en carretera","Conocimientos por escrito, examen de la vista y manejo en carretera","Examen de frenos de aire, examen de retroceso y manejo nocturno","Inspección antes del viaje, manejo de materiales peligrosos y manejo en carretera"],"explanation":"El examen de destrezas de la CDL de Maryland consta de la inspección del vehículo antes del viaje, las destrezas básicas de control del vehículo y el examen de manejo en carretera, y las tres partes deben completarse con éxito. Fuente: Maryland MVA, Examen de Destrezas de la CDL."},"84":{"q":"Según la autocertificación de la CDL de Maryland, ¿cuántas categorías de operación de manejo comercial puede declarar un solicitante?","options":["Cuatro","Dos","Tres","Cinco"],"explanation":"Los titulares de una CDL de Maryland se autocertifican en una de cuatro categorías: Interestatal No Exento (NI), Interestatal Exento (EI), Intraestatal No Exento (NA) e Intraestatal Exento (EA). Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"85":{"q":"Un conductor de Maryland se certifica como 'Interestatal No Exento (NI)'. ¿Qué significa esto?","options":["Conduce cruzando fronteras estatales y debe cumplir con todos los requisitos federales de calificación médica","Conduce únicamente dentro de Maryland y está exento de las normas médicas federales","Conduce cruzando fronteras estatales solo para actividades exentas específicas","Conduce únicamente dentro de Maryland usando una exención médica aprobada por la MVA"],"explanation":"Interestatal No Exento (NI) significa que el conductor opera un CMV cruzando fronteras estatales y cumple con todos los requisitos federales de calificación (incluida la médica). Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"86":{"q":"¿Cómo llega normalmente a la MVA el Certificado del Examinador Médico del DOT de un titular de una CDL de Maryland?","options":["El examinador médico lo envía electrónicamente al Registro Nacional de la FMCSA y la MVA lo recibe automáticamente","El conductor debe enviar por correo el certificado en papel a la sede de la MVA dentro de los 10 días","El empleador del conductor lo envía por fax a la MVA en nombre del conductor","El certificado se carga únicamente cuando el conductor renueva la CDL en persona"],"explanation":"El examinador médico certificado envía la información del certificado electrónicamente al Registro Nacional de la FMCSA, y la MVA recibe la certificación médica automáticamente; el conductor no necesita enviarla por correo ni presentarla. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"87":{"q":"¿Qué ocurre con los privilegios comerciales de un conductor de Maryland si su certificación médica del DOT caduca?","options":["Su CDL se degrada y deja de estar calificado para operar un CMV","Nada cambia durante 90 días siempre que siga conduciendo dentro del estado","Toda su licencia de conducir, incluida la clase base, se suspende de inmediato","La MVA emite una exención médica temporal automática"],"explanation":"Si la certificación médica caduca, el conductor deja de estar legalmente calificado para operar un CMV y los privilegios de manejo comercial se degradan. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"88":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de una CDL de Maryland en la MVA?","options":["Comprobante de identidad, edad, número de Seguro Social y residencia en Maryland","Solo un pasaporte válido y un recibo de servicios","Comprobante de identidad y solo una carta notariada del empleador","Solo un acta de nacimiento y comprobante del seguro del vehículo"],"explanation":"Los solicitantes de una CDL de Maryland deben presentar comprobante de identidad, edad, número de Seguro Social y residencia en Maryland. Fuente: Maryland MVA, Obtener o Renovar una CDL."},"89":{"q":"La autocertificación del tipo de manejo se exige en Maryland en todas las siguientes situaciones, EXCEPTO en ¿cuál?","options":["Cada vez que renueva el registro anual de su vehículo","Cuando obtiene una nueva CDL","Cuando renueva o mejora su CDL","Cuando cambia entre el manejo interestatal e intraestatal"],"explanation":"La autocertificación se exige al obtener, renovar, transferir o mejorar una CDL, al cambiar el estado médico o al cambiar entre el manejo interestatal e intraestatal; no para el registro rutinario del vehículo. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"90":{"q":"¿Cuál categoría describe a un titular de una CDL de Maryland que opera un CMV únicamente dentro de Maryland y posee una Exención Médica de CDL aprobada por la MVA?","options":["Intraestatal No Exento (NA)","Interestatal No Exento (NI)","Interestatal Exento (EI)","Intraestatal Exento (EA)"],"explanation":"Intraestatal No Exento (NA) se aplica a un conductor calificado para operar únicamente dentro de Maryland que tiene una Exención Médica de CDL aprobada por la MVA. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"91":{"q":"¿Cuál es el primer examen de conocimientos que todo solicitante de una CDL de Maryland debe aprobar, sin importar los endosos?","options":["El examen de Conocimientos Generales","El examen de Materiales Peligrosos","El examen de Frenos de Aire","El examen de Vehículos Combinados"],"explanation":"Todos los solicitantes de una CDL de Maryland deben aprobar primero el examen de Conocimientos Generales de la CDL; los exámenes específicos de endosos (P, S, N, H, T) se toman además, según sea necesario. Fuente: Maryland MVA / Manual de CDL (DL-151)."},"92":{"q":"¿Dónde toma un solicitante de Maryland los exámenes de conocimientos (escritos) de la CDL?","options":["Electrónicamente en las oficinas de la MVA en todo Maryland","Solo mediante examen en papel enviado por correo a la sede de la MVA","En cualquier centro de pruebas federal de la FMCSA","En línea desde casa a través de cualquier sitio web de terceros aprobado"],"explanation":"Los exámenes de conocimientos de la CDL se administran electrónicamente en las oficinas de la MVA en todo Maryland. Fuente: Maryland MVA, Exámenes de Conocimientos / Prepárese para un Examen de Licencia de Conducir."},"93":{"q":"¿Cuál es el ciclo de renovación típico (duración de la vigencia) de una licencia de conducir estándar de Maryland y de una CDL?","options":["8 años","4 años","5 años","10 años"],"explanation":"Las licencias de conducir de Maryland, incluidas las CDL, normalmente se emiten/renuevan por un período de 8 años. Fuente: Maryland MVA, Renovar una Licencia o Identificación."},"94":{"q":"En el examen de destrezas de la CDL de Maryland, ¿en qué orden se realizan generalmente los tres componentes?","options":["Inspección antes del viaje, luego destrezas básicas de control, luego manejo en carretera","Manejo en carretera, luego inspección antes del viaje, luego destrezas básicas de control","Destrezas básicas de control, luego manejo en carretera, luego inspección antes del viaje","Manejo en carretera, luego destrezas básicas de control, luego inspección antes del viaje"],"explanation":"Maryland realiza el examen de destrezas en este orden: primero la inspección del vehículo antes del viaje, luego las destrezas básicas de control del vehículo y luego el examen de manejo en carretera. Fuente: Maryland MVA, Examen de Destrezas de la CDL."},"95":{"q":"Si un titular de una CDL de Maryland deja caducar su certificación médica y pasa más de un año, ¿qué debe hacer para recuperar la CDL?","options":["Volver a tomar todos los exámenes de conocimientos y de destrezas de la CDL","Simplemente presentar un nuevo certificado médico sin ningún examen","Pagar una cuota de reinstalación pero no tomar ningún examen","Solo esperar a que transcurra una suspensión obligatoria de 90 días"],"explanation":"Si una CDL se degrada por un certificado médico caducado y pasa más de un año, el conductor debe volver a tomar todos los exámenes de conocimientos y de destrezas de la CDL para recuperarla. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"96":{"q":"¿Cuál categoría corresponde a un titular de una CDL de Maryland que cruza fronteras estatales únicamente para transportar niños en edad escolar, personas enfermas o lesionadas, o cadáveres?","options":["Interestatal Exento (EI)","Interestatal No Exento (NI)","Intraestatal No Exento (NA)","Intraestatal Exento (EA)"],"explanation":"Interestatal Exento (EI) cubre a los conductores que operan cruzando fronteras estatales únicamente para actividades exentas específicas, como transportar niños en edad escolar o personal, personas enfermas o lesionadas, o cadáveres. Fuente: Maryland MVA, Requisitos de Certificación Médica de la CDL."},"97":{"q":"¿Cuál situación NO activa por sí sola el requisito federal de ELDT antes de un examen de destrezas en Maryland?","options":["Renovar una CDL Clase A existente con los mismos endosos","Solicitar una primera CDL Clase A","Mejorar de una CDL Clase B a una Clase A","Obtener un primer endoso de Pasajeros (P) o de Autobús Escolar (S)"],"explanation":"La ELDT se exige para una primera CDL Clase A o B, para mejorar de Clase B a Clase A y para un primer endoso P, S o H; pero una renovación simple de una CDL existente no activa por sí sola la ELDT. Fuente: norma ELDT de Maryland MVA / FMCSA."},"98":{"q":"¿Cómo se programa normalmente la cita para el examen de destrezas (en carretera) de la CDL de Maryland?","options":["Haciendo una cita a través de la cuenta myMVA del solicitante","Presentándose sin cita en cualquier sucursal de la MVA","Llamando a la línea nacional de programación de la FMCSA","Automáticamente el mismo día en que se emite el CLP"],"explanation":"Los solicitantes programan el examen de destrezas de la CDL haciendo una cita a través de su cuenta myMVA; el examen lo administra la MVA después de cumplir con el período de espera del CLP y la ELDT. Fuente: Maryland MVA, Examen de Destrezas de la CDL."}},"hi":{"0":{"q":"मैरीलैंड के राजमार्गों पर, ओवरसाइज़ परमिट की आवश्यकता होने से पहले किसी वाहन की अधिकतम वैध चौड़ाई (दर्पणों और अन्य सुरक्षा/ऊर्जा उपकरणों को छोड़कर) कितनी होती है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"Maryland Transportation Article § 24-102 वाहन की अधिकतम चौड़ाई 102 inches (8 feet 6 inches) निर्धारित करता है; चौड़ाई दर्पणों, मार्कर/टर्न लैंप, और ऊर्जा-संरक्षण उपकरणों को छोड़कर मापी जाती है। इससे चौड़ी किसी भी चीज़ के लिए SHA ओवरसाइज़ परमिट की आवश्यकता होती है। स्रोत: Md. Transp. § 24-102; MD SHA Oversize/Overweight Hauling Permit Manual।"},"1":{"q":"मैरीलैंड के राजमार्गों पर परमिट के बिना किसी वाहन और उसके भार की अधिकतम वैध ऊंचाई कितनी होती है?","options":["12 feet 6 inches","13 feet","13 feet 6 inches","14 feet"],"explanation":"Maryland Transportation Article § 24-104 के तहत, किसी वाहन और उसके भार की ऊंचाई 13 feet 6 inches से अधिक नहीं हो सकती। SHA परमिट मैनुअल बिना किसी विशेष शर्त के 13'6\" को वैध सीमा के रूप में सूचीबद्ध करता है। स्रोत: Md. Transp. § 24-104; MD SHA Hauling Permit Manual (Height section)।"},"2":{"q":"ओवरवेट परमिट के बिना मैरीलैंड के इंटरस्टेट राजमार्गों पर अनुमत अधिकतम कुल वाहन भार कितना होता है?","options":["73,000 pounds","80,000 pounds","90,000 pounds","100,000 pounds"],"explanation":"मैरीलैंड संघीय इंटरस्टेट मानक का पालन करता है: अधिकतम कुल भार 80,000 pounds है (भार सहित)। स्रोत: Md. Transp. § 24-109; मैरीलैंड के इंटरस्टेट पर लागू 23 CFR 658.17।"},"3":{"q":"मैरीलैंड के इंटरस्टेट पर, एक सिंगल एक्सल पर अनुमत अधिकतम भार कितना होता है?","options":["17,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"मैरीलैंड की इंटरस्टेट प्रणाली पर सिंगल-एक्सल सीमा 20,000 pounds है, जो Maryland Transportation Article § 24-109 में संघीय मानक से मेल खाती है। स्रोत: Md. Transp. § 24-109; 23 CFR 658.17।"},"4":{"q":"मैरीलैंड के इंटरस्टेट पर, एक टैंडम एक्सल पर अनुमत अधिकतम भार कितना होता है?","options":["20,000 pounds","32,000 pounds","34,000 pounds","40,000 pounds"],"explanation":"टैंडम-एक्सल (दो-एक्सल समूह जो 40 inches से अधिक लेकिन 96 inches से अधिक नहीं की दूरी पर हो) सीमा Maryland Transportation Article § 24-109 के तहत 34,000 pounds है, जो संघीय इंटरस्टेट मानक के अनुरूप है। स्रोत: Md. Transp. § 24-109; 23 CFR 658.17।"},"5":{"q":"राज्य द्वारा अनुरक्षित सड़कों पर यात्रा के लिए ओवरसाइज़/ओवरवेट हॉलिंग परमिट कौन सा मैरीलैंड एजेंसी कार्यालय जारी करता है?","options":["The Motor Vehicle Administration (MVA) Driver Licensing Unit","The SHA Office of Traffic and Safety, Motor Carrier Division, Hauling Permits Unit","The Maryland State Police Commercial Vehicle Enforcement Division","The Maryland Transportation Authority Toll Facilities Office"],"explanation":"ओवरसाइज़/ओवरवेट (OS/OW) हॉलिंग परमिट Maryland State Highway Administration, Office of Traffic and Safety, Motor Carrier Division – Hauling Permits Unit (Hanover, MD) द्वारा जारी किए जाते हैं। स्रोत: MD SHA Oversize/Overweight Hauling Permit Manual (Introduction)।"},"6":{"q":"किसी भार को और कम नहीं किया जा सकता लेकिन वह फिर भी मैरीलैंड की वैध सीमाओं से अधिक है। कौन से क़ानून खंड वैध आकार और भार सीमाएं स्थापित करते हैं जो एक विशेष हॉलिंग परमिट की आवश्यकता को ट्रिगर करते हैं?","options":["Transportation Article, Title 16, Sections 101 and 102","Transportation Article, Title 24, Sections 108 and 109","Transportation Article, Title 21, Sections 1101 and 1102","Transportation Article, Title 11, Sections 301 and 302"],"explanation":"SHA परमिट मैनुअल में कहा गया है कि जब कोई भार Maryland Motor Vehicle Law, Title 24, Sections 108 (axle loads) और 109 (gross weight) में निर्धारित वैध सीमाओं से अधिक होता है, तो एक Special Hauling Permit खरीदना आवश्यक होता है। स्रोत: MD SHA Hauling Permit Manual; Md. Transp. §§ 24-108, 24-109।"},"7":{"q":"मैरीलैंड के National Network और निर्दिष्ट ट्रकिंग मार्गों पर, उस सेमीट्रेलर की अधिकतम लंबाई कितनी होती है जिसके लिए परमिट की आवश्यकता नहीं होती?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"National Network और निर्दिष्ट ट्रकिंग मार्गों पर, 53 feet तक के सेमीट्रेलर बिना परमिट के अनुमत हैं (48 feet कई अन्य राज्य राजमार्गों पर लागू होता है)। स्रोत: Md. Transp. § 24-104.1/24-104.2; J.J. Keller Maryland size/weight summary।"},"8":{"q":"मैरीलैंड National Network पर ट्रैक्टर-सेमीट्रेलर संयोजन पर एक निश्चित समग्र लंबाई सीमा लागू नहीं करता, लेकिन एक्सल के किसी भी समूह पर भार किस गणना द्वारा सीमित रहता है?","options":["The Federal Bridge Formula (Bridge Gross Weight Table)","The manufacturer's gross axle weight rating only","A flat 1,000 pounds per inch of tire width","The registered tare weight times two"],"explanation":"मैरीलैंड अपने Interstate/National Network पर Federal Bridge Formula लागू करता है: लगातार एक्सल के किसी भी समूह पर अधिकतम भार ब्रिज फॉर्मूला द्वारा नियंत्रित होता है, 80,000-pound की समग्र सीमा तक। स्रोत: Md. Transp. § 24-109; 23 CFR 658.17 Federal Bridge Formula।"},"9":{"q":"एक संयोजन वाहन मैरीलैंड के वैध भार से अधिक है। एक नियमित SHA ओवरवेट हॉलिंग परमिट किस कुल भार तक और किन सड़कों पर यात्रा को अधिकृत कर सकता है?","options":["Up to 100,000 pounds on any state highway","Up to 120,000 pounds on any state road","Up to 150,000 pounds on Interstate routes only","Up to 200,000 pounds on the Capital Beltway only"],"explanation":"SHA मैनुअल प्रावधान करता है कि 150,000 pounds तक लेकिन उससे अधिक नहीं के संयोजन-वाहन परमिट भार केवल Interstate मार्गों पर अनुमत हैं (Office of Bridge Development में गए बिना), बशर्ते एक्सल भार/दूरी नियमों का पालन किया जाए। स्रोत: MD SHA Hauling Permit Manual (Weight, 'Over 60 Tons')।"},"10":{"q":"Maryland SHA परमिट शुल्क अनुसूची के तहत, जब संयुक्त भार का वजन 90,000 pounds (45 tons) या उससे कम हो, तो हॉलिंग परमिट के लिए आधार शुल्क कितना होता है?","options":["$10.00","$30.00","$50.00","$100.00"],"explanation":"SHA मैनुअल हॉलिंग परमिट के लिए $30.00 का आधार शुल्क निर्धारित करता है जब कोई ओवर-डाइमेंशनल/संयुक्त भार 90,000 pounds से कम वजन का हो; 45 tons (90,000 lb) से अधिक के भार में प्रत्येक अतिरिक्त टन के लिए $5.00 जोड़ा जाता है। स्रोत: MD SHA Hauling Permit Manual (General Information; Permit Fees)।"},"11":{"q":"45 tons (90,000 pounds) से अधिक के एक परमिटेड भार के लिए, Maryland SHA प्रत्येक अतिरिक्त टन के लिए परमिट शुल्क में कितना जोड़ता है?","options":["$2.00 per ton","$5.00 per ton","$10.00 per ton","$25.00 per ton"],"explanation":"मैनुअल में कहा गया है कि 45 tons (90,000 lb) से अधिक के भार के लिए, प्रत्येक अतिरिक्त टन के लिए अतिरिक्त $5.00 लिया जाता है (जैसे, 50 tons = $55.00)। स्रोत: MD SHA Hauling Permit Manual (General Information; Permit Fees schedule)।"},"12":{"q":"मैरीलैंड के सामान्य संचलन-समय नियमों के तहत, एक परमिटेड ओवरसाइज़/ओवरवेट भार कब नहीं ले जाया जा सकता?","options":["Only between midnight and 6:00 a.m. on weekdays","Any Saturday after 12:00 noon and all day Sunday","Only on the first Monday of each month","Only during posted rush hours in Baltimore"],"explanation":"SHA मैनुअल और COMAR Title 11 के अनुसार, किसी भी परमिट भार को किसी भी शनिवार को 12:00 noon के बाद, किसी भी रविवार को, या सूचीबद्ध अवकाश अवधियों के दौरान नहीं ले जाया जा सकता। अन्यथा दिन के उजाले में संचलन (सूर्योदय के 1/2 घंटे बाद से सूर्यास्त के 1/2 घंटे पहले तक) नियम है। स्रोत: MD SHA Hauling Permit Manual (Hours of Movement); COMAR 11.04।"},"13":{"q":"मैरीलैंड में किस चौड़ाई पर एक परमिटेड भार (मोबाइल/मॉड्यूलर होम के अलावा) के लिए सबसे पहले एक एकल निजी एस्कॉर्ट वाहन की आवश्यकता होती है?","options":["Over 10 feet wide","Over 12 feet wide","Over 13 feet wide","Over 14 feet wide"],"explanation":"SHA मैनुअल 13 feet से अधिक चौड़े भार के लिए एक निजी एस्कॉर्ट की आवश्यकता रखता है (13'1\"–13'11\" सीमा के भार के लिए 1 निजी एस्कॉर्ट की आवश्यकता होती है), तथा 14 feet चौड़े या उससे अधिक पर दो निजी एस्कॉर्ट की आवश्यकता होती है। स्रोत: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)।"},"14":{"q":"मैरीलैंड में, 14 feet चौड़े या उससे अधिक के परमिटेड भार के लिए कितने निजी एस्कॉर्ट वाहनों की आवश्यकता होती है?","options":["No escort is required","One private escort","Two private escorts","Four private escorts"],"explanation":"SHA मैनुअल निर्दिष्ट करता है कि 14 feet चौड़े या उससे अधिक के सभी भारों को मैरीलैंड में और उसके आर-पार ले जाने के लिए दो निजी एस्कॉर्ट की आवश्यकता होती है। स्रोत: MD SHA Hauling Permit Manual (Width; Escorts – General Conditions)।"},"15":{"q":"इंटरस्टेट राजमार्गों पर कौन सा आयाम या भार एक मैरीलैंड परमिटेड भार को 'Super Load' बनाता है?","options":["Over 90,000 pounds gross or 11 feet wide","Exceeding 150,000 pounds (75 tons) or 27,000 pounds on any axle","Exceeding 80,000 pounds or 12 feet high","Any load requiring a single private escort"],"explanation":"SHA मैनुअल Super Loads को, अन्य के अलावा, इंटरस्टेट राजमार्गों पर 150,000 lb (75 tons) से अधिक या किसी भी एक्सल पर 27,000 lb से अधिक वाले भारों के रूप में परिभाषित करता है (या मैरीलैंड राज्य राजमार्गों पर 120,000 lb / 60 tons या 27,000 lb प्रति एक्सल से अधिक), या 120 ft लंबे, 16 ft चौड़े, या 16 ft ऊंचे भार। स्रोत: MD SHA Hauling Permit Manual (Escorts – General Conditions, Super Loads)।"},"16":{"q":"मैरीलैंड STATE (गैर-इंटरस्टेट) राजमार्गों पर, किस कुल भार से अधिक होने पर एक परमिटेड भार को एक अत्यधिक 'Super Load' के रूप में वर्गीकृत किया जाता है?","options":["80,000 pounds (40 tons)","100,000 pounds (50 tons)","120,000 pounds (60 tons)","150,000 pounds (75 tons)"],"explanation":"SHA मैनुअल किसी भार को मैरीलैंड राज्य राजमार्गों पर Super Load के रूप में वर्गीकृत करता है जब यह 120,000 pounds (60 tons) से अधिक हो या किसी भी एक्सल पर 27,000 pounds से अधिक हो। 150,000-pound (75-ton) सीमा इंटरस्टेट राजमार्गों पर लागू होती है। स्रोत: MD SHA Hauling Permit Manual (Super Loads)।"},"17":{"q":"इंटरस्टेट राजमार्गों को छोड़कर, सूचीबद्ध कटाई अवधियों के दौरान किसी खेत से कृषि उत्पाद ढोने वाले एक फार्म वाहन को मैरीलैंड कानून किस एक्सल-भार सहनशीलता की अनुमति देता है?","options":["A 5% axle-load tolerance","A 10% axle-load tolerance","A 15% axle-load tolerance","No tolerance is allowed at any time"],"explanation":"Maryland Transportation Article § 24-109 फार्म वाहनों (इंटरस्टेट से बाहर) को सामान्यतः 5% एक्सल सहनशीलता की अनुमति देता है, जो निर्धारित कटाई अवधियों के दौरान 15% एक्सल-भार सहनशीलता तक बढ़ जाती है (जैसे, गेहूं June 1–Aug 15, मक्का July 1–Dec 1), खेत के 100 miles के भीतर 5% कुल-भार सहनशीलता के साथ। स्रोत: Md. Transp. § 24-109 (harvest-time agricultural variance)।"},"18":{"q":"इंटरस्टेट राजमार्गों को छोड़कर, किसी जंगल से वन उत्पाद ढोने वाले एक संयोजन (45 feet या उससे कम का सेमीट्रेलर) को June 1 से September 30 तक किस एक्सल-भार सहनशीलता की अनुमति है?","options":["5% axle-load tolerance","10% axle-load tolerance","15% axle-load tolerance","20% axle-load tolerance"],"explanation":"Maryland Transportation Article § 24-109 एक वन-उत्पाद संयोजन (45 ft या उससे कम का सेमीट्रेलर, राजमार्ग से बाहर लोड किया गया, इंटरस्टेट पर नहीं) को 5% एक्सल सहनशीलता की अनुमति देता है, जो June 1 से September 30 तक बढ़कर 15% हो जाती है। स्रोत: Md. Transp. § 24-109 (forest-products variance)।"},"19":{"q":"मैरीलैंड (संघीय कानून का पालन करते हुए) एक भारी वाहन को gross/axle/bridge-formula सीमाओं का उल्लंघन किए बिना किस ईंधन-बचत उपकरण के भार की भरपाई के लिए एक छोटा अतिरिक्त भार भत्ता देता है?","options":["An automatic tire-inflation system, up to 1,000 extra pounds","An auxiliary power unit / idle-reduction technology, up to 550 extra pounds","A refrigeration unit, up to 2,000 extra pounds","A wide-base single tire, up to 250 extra pounds"],"explanation":"Maryland Transportation Article § 24-109 एक auxiliary power unit या idle-reduction technology unit के लिए gross, axle, tandem, या bridge-formula भार में कुल मिलाकर अतिरिक्त 550 pounds तक की अनुमति देता है, जो संघीय कानून के अनुरूप है। स्रोत: Md. Transp. § 24-109 (idle-reduction allowance); 23 CFR 658.17।"},"20":{"q":"मैरीलैंड में, 26,001 pounds या उससे अधिक की Gross Combination Weight Rating (GCWR) वाले एक संयोजन वाहन को चलाने के लिए, जहां खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो, कौन सी CDL श्रेणी आवश्यक होती है?","options":["Class A","Class B","Class C","Class D"],"explanation":"मैरीलैंड एक Class A CDL को एक ट्रैक्टर/पावर यूनिट और ट्रेलर(ओं) वाले संयोजन वाहन के रूप में परिभाषित करता है जिसका GCWR 26,001+ pounds हो, तथा खींची जाने वाली इकाई का GVWR 10,000 pounds से अधिक हो। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151।"},"21":{"q":"Maryland MVA नियमों के तहत, कौन सी CDL श्रेणी 26,001 pounds या उससे अधिक GVWR वाले किसी भी एकल वाहन को चलाने का अधिकार देती है (10,000 pounds से अधिक नहीं वाली इकाई खींचते हुए)?","options":["Class A","Class B","Class C","Class M"],"explanation":"एक Maryland Class B CDL 26,001+ pounds GVWR वाले एकल वाहनों, या ऐसे वाहन जो 10,000 pounds GVWR से अधिक नहीं वाली इकाई खींच रहे हों, को कवर करता है। उदाहरणों में स्ट्रेट बॉक्स ट्रक और अधिकांश बसें शामिल हैं। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions।"},"22":{"q":"एक मैरीलैंड वाहन का रेटिंग 26,001 pounds से कम है लेकिन इसे 16 या अधिक यात्रियों (चालक सहित) को ले जाने के लिए डिज़ाइन किया गया है, या यह प्लेकार्डेड खतरनाक सामग्री ले जाता है। कौन सी CDL श्रेणी लागू होती है?","options":["Class A","Class B","Class C","Class E"],"explanation":"मैरीलैंड का Class C CDL छोटे वाणिज्यिक वाहनों को कवर करता है जो Class A या B भार मानदंड को पूरा नहीं करते लेकिन जिन्हें 16+ यात्रियों (चालक सहित) को ले जाने या प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाने के लिए डिज़ाइन किया गया है। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions; Manual DL-151।"},"23":{"q":"मैरीलैंड में, 16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किए गए वाहन, जैसे कि एक बस, को चलाने के लिए कौन सा एंडोर्समेंट कोड आवश्यक है?","options":["Endorsement N","Endorsement P","Endorsement T","Endorsement H"],"explanation":"मैरीलैंड में 16 या अधिक यात्रियों को ले जाने वाले वाहनों को चलाने के लिए P (Passenger) एंडोर्समेंट आवश्यक है। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions।"},"24":{"q":"मैरीलैंड में स्कूल बस चलाने के लिए, MVA को किस एंडोर्समेंट संयोजन की आवश्यकता होती है?","options":["S endorsement only","P endorsement only","Both P (Passenger) and S (School Bus) endorsements","Both S (School Bus) and H (HazMat) endorsements"],"explanation":"मैरीलैंड में स्कूल बस चलाने के लिए P (Passenger) और S (School Bus) दोनों एंडोर्समेंट की आवश्यकता होती है। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions।"},"25":{"q":"टैंक में तरल पदार्थ या गैस ले जाने वाले वाहन, जैसे कि एक ईंधन या पानी का टैंकर, को चलाने के लिए कौन सा मैरीलैंड CDL एंडोर्समेंट आवश्यक है?","options":["Endorsement H","Endorsement N","Endorsement T","Endorsement P"],"explanation":"मैरीलैंड टैंकों में तरल पदार्थ या गैस ले जाने वाले वाहनों, जैसे ईंधन या पानी के टैंकर, के लिए N (Tank Vehicle) एंडोर्समेंट का उपयोग करता है। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions।"},"26":{"q":"मैरीलैंड में, CDL पर 'X' एंडोर्समेंट किसका संयोजन है?","options":["Passenger (P) and School Bus (S)","Tank Vehicle (N) and HazMat (H)","Doubles/Triples (T) and Tank (N)","HazMat (H) and Passenger (P)"],"explanation":"मैरीलैंड का X एंडोर्समेंट N (Tank Vehicle) और H (HazMat) एंडोर्समेंट का एक संयोजन है, जो टैंक वाहनों में खतरनाक सामग्री के परिवहन को अधिकृत करता है। स्रोत: Maryland MVA, CDL Classifications, Endorsements & Restrictions।"},"27":{"q":"इंट्रास्टेट (केवल-मैरीलैंड) वाणिज्यिक ड्राइविंग तक सीमित एक मैरीलैंड CDL प्राप्त करने की न्यूनतम आयु कितनी है?","options":["16 years old","18 years old","21 years old","25 years old"],"explanation":"मैरीलैंड इंट्रास्टेट (मैरीलैंड के भीतर) ड्राइविंग के लिए 18 वर्ष की आयु में CDL की अनुमति देता है, जबकि इंटरस्टेट ड्राइविंग के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: Maryland MVA, Get or Renew a CDL; Manual DL-151।"},"28":{"q":"Maryland MVA के अनुसार, इंटरस्टेट कॉमर्स (राज्य की सीमाओं के पार) में वाणिज्यिक वाहन चलाने के लिए आवश्यक न्यूनतम आयु कितनी है?","options":["18 years old","19 years old","21 years old","23 years old"],"explanation":"मैरीलैंड में चालकों को CDL वाहन इंटरस्टेट (राज्य की सीमाओं के पार) चलाने, प्लेकार्ड की आवश्यकता वाली खतरनाक सामग्री ले जाने, या इंटरस्टेट यात्रियों को ले जाने के लिए कम से कम 21 वर्ष का होना आवश्यक है। स्रोत: Maryland MVA, Get or Renew a CDL।"},"29":{"q":"एक 19 वर्षीय मैरीलैंड CDL धारक को निम्नलिखित में से किस कार्य से कानूनी रूप से प्रतिबंधित किया गया है?","options":["Driving a straight truck within Maryland","Driving a commercial vehicle across state lines","Holding a Passenger (P) endorsement for intrastate use","Driving a Class B vehicle within Maryland"],"explanation":"18 और 21 वर्ष के बीच का एक मैरीलैंड चालक मैरीलैंड के बाहर (इंटरस्टेट) वाणिज्यिक वाहन नहीं चला सकता, हैज़मैट प्लेकार्ड की आवश्यकता वाला वाहन नहीं चला सकता, और डबल/ट्रिपल ट्रेलर रिग नहीं चला सकता। स्रोत: Maryland MVA / Manual DL-151।"},"30":{"q":"मैरीलैंड में लागू संघीय नियम के तहत, CDL कौशल (सड़क) परीक्षा देने की अनुमति मिलने से पहले एक आवेदक को कितने समय तक एक Commercial Learner's Permit (CLP) रखना आवश्यक है?","options":["At least 7 days","At least 10 days","At least 14 days","At least 30 days"],"explanation":"मैरीलैंड संघीय नियम लागू करता है जिसके अनुसार CDL कौशल (सड़क) परीक्षा देने से पहले एक CLP को कम से कम 14 days तक रखना आवश्यक है। स्रोत: Maryland MVA, Get or Renew a CDL; 49 CFR 383.25।"},"31":{"q":"एक मैरीलैंड Commercial Learner's Permit (CLP) जारी किए जाने से पहले, एक आवेदक के पास पहले से कौन सी क्रेडेंशियल होनी चाहिए?","options":["A valid Maryland (non-motorcycle) driver's license","A Maryland motorcycle license","A federal TWIC card","An out-of-state CDL"],"explanation":"मैरीलैंड के अनुसार CLP आवेदकों के पास पहले से एक वैध मैरीलैंड ड्राइवर लाइसेंस (केवल-मोटरसाइकिल लाइसेंस नहीं) होना चाहिए और उन्हें दृष्टि और ज्ञान परीक्षाएं पास करनी चाहिए। स्रोत: Maryland MVA / Manual DL-151।"},"32":{"q":"CDL के लिए आवेदन करते समय Maryland MVA किस दस्तावेज़ सेट को प्रस्तुत करने की आवश्यकता रखता है?","options":["Only a current driver's license and a photo","Proof of identity, age, Social Security number, and Maryland residency","Only a passport and an employer letter","Proof of identity and a vehicle registration card"],"explanation":"Maryland MVA पहचान, आयु, Social Security number, और मैरीलैंड निवास का प्रमाण आवश्यक करता है (कानूनी उपस्थिति इन पहचान दस्तावेज़ों के माध्यम से स्थापित की जाती है)। स्रोत: Maryland MVA, Get or Renew a CDL।"},"33":{"q":"पहली बार मैरीलैंड Class A या B CDL आवेदक के लिए Entry-Level Driver Training (ELDT) कहां पूरा किया जाना चाहिए?","options":["Any private driving school of the applicant's choice","A provider listed in the FMCSA Training Provider Registry","Only at a Maryland MVA branch office","A program accredited by the Maryland State Department of Education"],"explanation":"मैरीलैंड के अनुसार पहली बार Class A/B आवेदकों के लिए (और पहली बार S, P, और H एंडोर्समेंट के लिए) ELDT को कौशल परीक्षा या हैज़मैट ज्ञान परीक्षा से पहले FMCSA Training Provider Registry में सूचीबद्ध एक प्रदाता के माध्यम से पूरा किया जाना चाहिए। स्रोत: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380।"},"34":{"q":"निम्नलिखित में से किसके लिए मैरीलैंड परीक्षण से पहले Entry-Level Driver Training (ELDT) आवश्यक करता है?","options":["Renewing an existing Class A CDL","Adding an automatic-transmission restriction","Obtaining a Class A or B CDL for the first time, or adding S, P, or H for the first time","Updating a residential address on the CDL"],"explanation":"मैरीलैंड पहली बार Class A या B CDL के लिए और पहली बार School Bus (S), Passenger (P), या HazMat (H) एंडोर्समेंट जोड़ने के लिए ELDT अनिवार्य करता है। यह नवीनीकरण या प्रशासनिक परिवर्तनों के लिए आवश्यक नहीं है। स्रोत: Maryland MVA, Get or Renew a CDL; 49 CFR Part 380।"},"35":{"q":"निम्नलिखित में से कौन सा चार चिकित्सा स्व-प्रमाणन श्रेणियों में से एक है जिसमें से एक मैरीलैंड CDL धारक को चुनना होता है?","options":["Non-Excepted Interstate (NI)","Restricted Commercial (RC)","Provisional Interstate (PI)","Limited Hazmat (LH)"],"explanation":"मैरीलैंड की चार स्व-प्रमाणन श्रेणियां Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA) हैं। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"36":{"q":"एक मैरीलैंड CDL धारक जो राज्य की सीमाओं के पार गाड़ी चलाता है और जिसे सभी संघीय चालक-योग्यता आवश्यकताओं का पालन करना होता है, उसे किस श्रेणी के रूप में स्व-प्रमाणित करना चाहिए?","options":["Excepted Intrastate (EA)","Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI) एक ऐसे CDL धारक पर लागू होता है जो राज्य की सीमाओं के पार गाड़ी चलाता है और एक वैध DOT चिकित्सा प्रमाणपत्र सहित सभी संघीय योग्यता आवश्यकताओं को पूरा करता है। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"37":{"q":"मैरीलैंड में, HazMat (H) एंडोर्समेंट ज्ञान परीक्षा देने और एंडोर्समेंट जारी किए जाने से पहले, आवेदक को किसे क्लियर करना होता है?","options":["A TSA security threat assessment with a fingerprint-based background check","A state vehicle emissions inspection","A drug and alcohol clearinghouse pre-employment query only","A Maryland State Police driving-record audit only"],"explanation":"मैरीलैंड के अनुसार HazMat आवेदकों को हैज़मैट ज्ञान परीक्षा पास करने के अलावा एक TSA security threat assessment क्लियर करना आवश्यक है, जिसमें एक फिंगरप्रिंट-आधारित Background Record Check (DPSCS के माध्यम से संसाधित) शामिल है। स्रोत: Maryland MVA, CDL HazMat Endorsement; 49 CFR Part 1572।"},"38":{"q":"TSA अनुमोदन प्राप्त करने के बाद, एक मैरीलैंड आवेदक को किस समय सीमा के भीतर HazMat एंडोर्समेंट प्राप्त करना होता है?","options":["Within 30 days","Within 90 days","Within six months","Within two years"],"explanation":"मैरीलैंड के अनुसार आवेदक को TSA अनुमोदन पत्र पर अंकित तिथि से six months के भीतर HazMat एंडोर्समेंट प्राप्त करना आवश्यक है। स्रोत: Maryland MVA, CDL HazMat Endorsement।"},"39":{"q":"School Bus (S) एंडोर्समेंट वाले एक मैरीलैंड CDL धारक को उस एंडोर्समेंट को वैध रखने के लिए आमतौर पर कितनी बार अपने मेडिकल एग्ज़ामिनर के प्रमाणपत्र का नवीनीकरण करना होता है?","options":["Every 6 months","Annually (every year)","Every 2 years","Every 5 years"],"explanation":"हालांकि अधिकांश मेडिकल एग्ज़ामिनर के प्रमाणपत्र two years तक वैध होते हैं, मैरीलैंड School Bus (S) एंडोर्समेंट धारकों को आमतौर पर उस पदनाम को बनाए रखने के लिए एक वार्षिक चिकित्सा प्रमाणन की आवश्यकता होती है। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"40":{"q":"मैरीलैंड में, अधिकतम रक्त/श्वास अल्कोहल सांद्रता (BAC) कितनी होती है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.04","0.08","0.02","0.10"],"explanation":"मैरीलैंड में एक CMV चालक को 0.04 या उससे अधिक BAC के साथ गाड़ी चलाने पर अयोग्य ठहराया जाता है — जो गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा है। स्रोत: Maryland Transportation Article §16-812(a) and §11-127.1; Maryland CDL Manual; 49 CFR 383.51 Table 1।"},"41":{"q":"मैरीलैंड के निहित-सहमति (implied-consent) कानून के तहत, यदि किसी CDL धारक से अल्कोहल के लिए एक रासायनिक परीक्षण देने को कानूनी रूप से कहा जाता है और वह मना कर देता है तो क्या होता है?","options":["The CDL is disqualified for at least 1 year (a first refusal is treated like a major offense)","The driver is fined but keeps the CDL","The CDL is suspended for 60 days","Nothing happens until a conviction"],"explanation":"मैरीलैंड निहित सहमति लागू करता है: कानूनी रूप से अनुरोधित रासायनिक परीक्षण से इनकार करने पर पहले अपराध के लिए CDL को 1 year के लिए अयोग्य ठहराया जाता है, जो अन्य प्रमुख अपराधों के समान है। स्रोत: Maryland Transportation Article §16-205.1 and §16-812(b); 49 CFR 383.51 Table 1।"},"42":{"q":"प्लेकार्डेड खतरनाक सामग्री का परिवहन नहीं करते समय एक पहले प्रमुख अपराध (जैसे DUI, एक CMV में 0.04+ BAC, या परीक्षण से इनकार) के लिए मैरीलैंड में CDL अयोग्यता अवधि कितनी होती है?","options":["1 year","60 days","3 years","6 months"],"explanation":"एक पहला प्रमुख अपराध CDL को 1 year के लिए अयोग्य ठहराता है (यदि यह प्लेकार्डेड HazMat का परिवहन करते समय हुआ हो तो 3 years)। स्रोत: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1।"},"43":{"q":"यदि कोई मैरीलैंड CDL चालक प्लेकार्डिंग की आवश्यकता वाली खतरनाक सामग्री का परिवहन करते समय एक पहला प्रमुख अपराध (जैसे DUI या 0.04+ BAC) करता है, तो अयोग्यता कितने समय की होती है?","options":["3 years","1 year","5 years","Lifetime"],"explanation":"मानक 1-year पहले-अपराध की अयोग्यता बढ़कर 3 years हो जाती है जब चालक उस समय प्लेकार्डेड खतरनाक सामग्री का परिवहन कर रहा था। स्रोत: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1।"},"44":{"q":"एक अलग घटना में किए गए दूसरे प्रमुख अपराध (एक दूसरा DUI, 0.04+ BAC, इनकार, आदि) के लिए मैरीलैंड में CDL अयोग्यता कितनी होती है?","options":["Lifetime disqualification","5 years","3 years","2 years"],"explanation":"एक दूसरा प्रमुख अपराध आजीवन CDL अयोग्यता में परिणत होता है, हालांकि योग्य मामलों में 10 साल के बाद पुनर्बहाली संभव हो सकती है। स्रोत: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1।"},"45":{"q":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से संबंधित अपराध (felony) करने के लिए एक CMV का उपयोग करने पर कौन सा मैरीलैंड CDL दंड लगता है?","options":["Lifetime disqualification with no 10-year reinstatement","1-year disqualification","3-year disqualification","Lifetime disqualification, but eligible for reinstatement after 10 years"],"explanation":"एक CMV का उपयोग करके किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से संबंधित एक felony एक आजीवन अयोग्यता है जो 10 साल की पुनर्बहाली के लिए पात्र नहीं है। स्रोत: 49 CFR 383.51 Table 1; Maryland Transportation Article §16-812।"},"46":{"q":"मैरीलैंड में 3 साल की अवधि के भीतर कितने गंभीर यातायात उल्लंघन 60-दिन की CDL अयोग्यता को ट्रिगर करते हैं?","options":["2 serious violations","3 serious violations","4 serious violations","1 serious violation"],"explanation":"3 साल के भीतर दो गंभीर यातायात उल्लंघन (किसी भी संयोजन में, एक CMV में) 60-दिन की अयोग्यता में परिणत होते हैं। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 2।"},"47":{"q":"3 साल की अवधि के भीतर तीन गंभीर यातायात उल्लंघन मैरीलैंड में किस CDL अयोग्यता अवधि में परिणत होते हैं?","options":["120 days","60 days","180 days","1 year"],"explanation":"3 साल के भीतर तीन गंभीर यातायात उल्लंघन CDL को 120 days के लिए अयोग्य ठहराते हैं; यह किसी भी पूर्व 60-दिन की अयोग्यता के अतिरिक्त है। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 2।"},"48":{"q":"मैरीलैंड में CDL प्रयोजनों के लिए एक 'गंभीर यातायात उल्लंघन' के रूप में गिने जाने के लिए एक ओवरस्पीडिंग अपराध को पोस्ट की गई सीमा से कितने मील प्रति घंटे अधिक होना चाहिए?","options":["15 mph or more over the limit","10 mph or more over the limit","20 mph or more over the limit","25 mph or more over the limit"],"explanation":"पोस्ट की गई गति सीमा से 15 mph या उससे अधिक ओवरस्पीडिंग एक गंभीर यातायात उल्लंघन है जो 2-इन-3-वर्ष (60 day) और 3-इन-3-वर्ष (120 day) अयोग्यताओं की ओर गिना जाता है। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 2।"},"49":{"q":"एक मैरीलैंड CDL धारक के लिए निम्नलिखित में से किसे एक 'गंभीर यातायात उल्लंघन' के रूप में वर्गीकृत किया जाता है?","options":["Reckless driving","Parking in a fire lane","A burned-out taillight","An expired registration sticker"],"explanation":"गंभीर यातायात उल्लंघनों में लापरवाह ड्राइविंग (reckless driving), 15+ mph ओवरस्पीडिंग, अनुचित/अनियमित लेन परिवर्तन, बहुत करीब से चलना, टेक्स्टिंग, और हैंडहेल्ड फोन का उपयोग शामिल हैं। नियमित उपकरण/पार्किंग मुद्दे गंभीर उल्लंघन नहीं हैं। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 2।"},"50":{"q":"मैरीलैंड में, कानून का उल्लंघन करते हुए टेक्स्टिंग करते समय एक CMV चलाने को CDL अयोग्यता के लिए किस प्रकार के अपराध के रूप में माना जाता है?","options":["A serious traffic violation","A major offense","An out-of-service violation","A railroad-crossing violation"],"explanation":"एक CMV चलाते समय टेक्स्टिंग करना एक गंभीर यातायात उल्लंघन है जो 60-दिन (2-इन-3-वर्ष) और 120-दिन (3-इन-3-वर्ष) अयोग्यताओं की ओर गिना जाता है। मैरीलैंड एक प्राथमिक-प्रवर्तन कानून के तहत टेक्स्टिंग पर प्रतिबंध लगाता है। स्रोत: Maryland Transportation Article §21-1124.1; 49 CFR 383.51 Table 2।"},"51":{"q":"मैरीलैंड कानून के तहत, एक CMV का एक वयस्क चालक जो वाहन के गतिमान होने के दौरान एक हैंड-हेल्ड मोबाइल फोन का उपयोग करता है, किस प्रकार का CDL अपराध करता है?","options":["A serious traffic violation","A minor non-reportable offense","A major offense with a 1-year disqualification","An out-of-service order violation"],"explanation":"एक CMV चलाते समय एक हैंड-हेल्ड फोन का उपयोग करना एक गंभीर यातायात उल्लंघन है जो 60/120-दिन की अयोग्यता सीमाओं की ओर गिना जाता है। मैरीलैंड का हैंड-हेल्ड प्रतिबंध एक प्राथमिक अपराध है। स्रोत: Maryland Transportation Article §21-1124.2; 49 CFR 383.51 Table 2।"},"52":{"q":"एक पहले रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन के लिए मैरीलैंड में न्यूनतम CDL अयोग्यता कितनी होती है?","options":["Not less than 60 days","Not less than 30 days","Not less than 120 days","Not less than 1 year"],"explanation":"एक पहला रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन CDL को 60 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 3।"},"53":{"q":"3 साल की अवधि के भीतर एक दूसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन मैरीलैंड में किस न्यूनतम CDL अयोग्यता में परिणत होता है?","options":["Not less than 120 days","Not less than 60 days","Not less than 1 year","Not less than 180 days"],"explanation":"3 साल के भीतर एक दूसरा रेलरोड-क्रॉसिंग उल्लंघन CDL को 120 days से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 3।"},"54":{"q":"3 साल की अवधि के भीतर एक तीसरा रेलरोड-हाईवे ग्रेड क्रॉसिंग उल्लंघन मैरीलैंड में किस न्यूनतम CDL अयोग्यता में परिणत होता है?","options":["Not less than 1 year","Not less than 120 days","Not less than 180 days","Lifetime"],"explanation":"3 साल के भीतर एक तीसरा (या उसके बाद का) रेलरोड-क्रॉसिंग उल्लंघन CDL को 1 year से कम नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland CDL Manual; 49 CFR 383.51 Table 3।"},"55":{"q":"एक गैर-HazMat CMV चलाते समय एक आउट-ऑफ-सर्विस आदेश के उल्लंघन की एक पहली दोषसिद्धि के लिए मैरीलैंड में CDL अयोग्यता सीमा कितनी होती है?","options":["180 days up to 1 year","60 to 120 days","1 to 3 years","30 to 90 days"],"explanation":"एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन (गैर-HazMat, 16 से कम यात्री) CDL को 180 days से कम नहीं और 1 year से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4।"},"56":{"q":"किसी भी 10-वर्ष की अवधि के भीतर एक दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन (गैर-HazMat) मैरीलैंड में किस CDL अयोग्यता सीमा में परिणत होता है?","options":["2 to 5 years","180 days to 1 year","1 to 3 years","Lifetime"],"explanation":"10 साल के भीतर एक दूसरा आउट-ऑफ-सर्विस आदेश उल्लंघन CDL को 2 years से कम नहीं और 5 years से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4।"},"57":{"q":"प्लेकार्डेड खतरनाक सामग्री का परिवहन करते समय या 16 या अधिक यात्रियों के लिए डिज़ाइन किए गए वाहन को चलाते समय एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन मैरीलैंड में किस CDL अयोग्यता सीमा को वहन करता है?","options":["180 days up to 2 years","180 days up to 1 year","2 to 5 years","3 to 5 years"],"explanation":"प्लेकार्डेड HazMat या एक 16+ यात्री वाहन से संबंधित एक पहला आउट-ऑफ-सर्विस आदेश उल्लंघन CDL को 180 days से कम नहीं और 2 years से अधिक नहीं के लिए अयोग्य ठहराता है। स्रोत: Maryland Transportation Article §16-813; 49 CFR 383.51 Table 4।"},"58":{"q":"Maryland MVA एक उच्च-BAC वाणिज्यिक स्टॉप से संबंधित एक CDL अयोग्यता कब शुरू कर सकता है?","options":["Upon a citation/administrative per se action for a high BAC in a CMV, even before conviction","Only after a criminal conviction in court","Only after a second offense","Only if the driver causes a crash"],"explanation":"मैरीलैंड एक वाणिज्यिक वाहन चलाते समय एक उच्च BAC के लिए एक साइटेशन या प्रशासनिक per se आदेश के आधार पर एक CDL को अयोग्य ठहरा सकता है, यहां तक कि किसी भी अदालती दोषसिद्धि से पहले भी। स्रोत: MDOT MVA CDL Disqualification & Reinstatement page; Maryland Transportation Article §16-205.1, §16-812।"},"59":{"q":"एक आजीवन CDL अयोग्यता के बाद, एक मैरीलैंड चालक आम तौर पर कितने वर्षों के बाद पुनर्बहाली के लिए आवेदन कर सकता है, बशर्ते पात्रता आवश्यकताएं पूरी हों?","options":["10 years","5 years","3 years","Never — lifetime is permanent in all cases"],"explanation":"एक आजीवन CDL अयोग्यता को न्यूनतम 10 years तक कम किया जा सकता है यदि चालक पुनर्बहाली आवश्यकताओं को पूरा करता है — सिवाय CMV द्वारा ड्रग-तस्करी या मानव-तस्करी जैसे अपराधों के, जो कोई पुनर्बहाली की अनुमति नहीं देते। स्रोत: Maryland Transportation Article §16-812; 49 CFR 383.51 Table 1।"},"60":{"q":"मैरीलैंड के मूव ओवर कानून के तहत, जब कोई CDL ड्राइवर चेतावनी लाइटें दिखा रहे किसी रुके हुए आपातकालीन वाहन, टो ट्रक, या सेवा वाहन के पास पहुँचता है, तो कानून के अनुसार पहली कार्रवाई क्या आवश्यक है?","options":["यदि ऐसा करना सुरक्षित और कानूनी हो, तो ऐसी लेन में चले जाएँ जो रुके हुए वाहन से तुरंत सटी हुई न हो","किसी अधिकारी द्वारा आगे बढ़ने का निर्देश दिए जाने तक पूरी तरह रुक जाएँ","रुके हुए वाहन के पास से गुजरते समय लगातार हॉर्न बजाएँ","गति को निर्धारित सीमा से ठीक 20 mph नीचे कम करें और लेन बनाए रखें"],"explanation":"मैरीलैंड ट्रांसपोर्टेशन आर्टिकल 21-405.1 (मूव ओवर कानून) के अनुसार ड्राइवर को, जब ऐसा करना सुरक्षित और कानूनी हो, रुके हुए वाहन से तुरंत सटी हुई लेन से हटकर किसी अन्य लेन में जाना आवश्यक है। केवल तभी जब लेन बदलना असुरक्षित या असंभव हो, ड्राइवर को इसके बजाय एक उचित और विवेकपूर्ण गति तक धीमा होना चाहिए। स्रोत: Md. Code, Transportation 21-405.1; Maryland MVA/MSP मार्गदर्शन।"},"61":{"q":"यदि कोई मैरीलैंड CDL ड्राइवर लाइटें जलाए रुके हुए आपातकालीन या सेवा वाहन के पास से गुजरते समय सुरक्षित रूप से लेन नहीं बदल सकता, तो इसके बजाय ड्राइवर को क्या करना चाहिए?","options":["मौजूदा परिस्थितियों के लिए उचित और विवेकपूर्ण गति तक धीमा हो जाएँ","दृश्य के साफ होने तक शोल्डर पर पूरी तरह रुक जाएँ","निर्धारित गति सीमा बनाए रखें और बिना गति बदले गुजर जाएँ","मीडियन पर रुकें और यातायात के लेन साफ करने का इंतज़ार करें"],"explanation":"Md. Transportation 21-405.1 के तहत, यदि हटना असुरक्षित या संभव न हो, तो ड्राइवर को परिस्थितियों के लिए सुरक्षित उचित और विवेकपूर्ण गति तक धीमा होना चाहिए। मैरीलैंड कानून कोई एकल निश्चित संख्या निर्धारित नहीं करता; यह परिस्थितियों के लिए उचित गति की माँग करता है। स्रोत: Md. Code, Transportation 21-405.1।"},"62":{"q":"1 अक्टूबर 2022 के विस्तार के अनुसार, मैरीलैंड का मूव ओवर कानून सड़क के किनारे रुके निम्नलिखित में से किस पर लागू होता है?","options":["खतरे की लाइटें, चेतावनी शंकु, या रोड फ्लेयर दिखाने वाला कोई भी वाहन, जिसमें सामान्य यात्री कारें भी शामिल हैं","केवल चमकती लाइटों का उपयोग करने वाले चिह्नित पुलिस और अग्निशमन वाहन","केवल टो ट्रक और राजमार्ग रखरखाव वाहन","केवल 26,001 पाउंड से अधिक के वाणिज्यिक मोटर वाहन"],"explanation":"1 अक्टूबर 2022 से प्रभावी, मैरीलैंड ने 21-405.1 का विस्तार किया ताकि मूव ओवर का कर्तव्य खतरे की लाइटें, रोड फ्लेयर, या चेतावनी शंकु दिखाने वाले किसी भी रुके हुए वाहन पर लागू हो, न कि केवल आपातकालीन या सेवा वाहनों पर। स्रोत: Md. Code, Transportation 21-405.1 (2022 संशोधन); Maryland MVA।"},"63":{"q":"जब कोई मैरीलैंड स्कूल बस दो-लेन वाली अविभाजित सड़क पर अपनी लाल लाइटें चमकाते और स्टॉप आर्म फैलाए रुकी हो, तो किसी भी दिशा से आ रहे CDL ड्राइवर को क्या करना चाहिए?","options":["रुक जाएँ और तब तक रुके रहें जब तक लाइटें चमकना बंद न कर दें और बस चल न पड़े या जाने का संकेत न दे","15 mph तक धीमा हो जाएँ और सावधानी से बाईं ओर से गुजरें","केवल तभी रुकें जब बस के समान दिशा में यात्रा कर रहे हों","यदि बस के पास कोई बच्चे दिखाई न दें तो आगे बढ़ें"],"explanation":"मैरीलैंड में अविभाजित दो-तरफा सड़क पर, चमकती लाल लाइटों और फैले स्टॉप आर्म वाली स्कूल बस के लिए दोनों दिशाओं का यातायात रुकना चाहिए, और तब तक रुके रहना चाहिए जब तक संकेत बंद न हो जाएँ। स्रोत: Md. Code, Transportation 21-706; Maryland MVA/MSP।"},"64":{"q":"मैरीलैंड के विभाजित-राजमार्ग अपवाद के तहत, रुकी हुई स्कूल बस से विपरीत दिशा में यात्रा कर रहे ड्राइवरों को रुकने की आवश्यकता कब नहीं होती?","options":["जब यात्रा की दिशाएँ किसी भौतिक मीडियन या अवरोध, जैसे घास, मिट्टी, या कंक्रीट विभाजक से अलग हों","जब सड़क में चार या अधिक लेन हों, चाहे कोई मीडियन हो या न हो","जब दोहरी पीली केंद्र रेखा यात्रा की दिशाओं को अलग करती हो","जब बस विपरीत लेन में 100 फीट से अधिक दूर हो"],"explanation":"मैरीलैंड विपरीत-दिशा के यातायात को रुकने से केवल तभी छूट देता है जब कोई भौतिक मीडियन, अवरोध, या बिना पक्की पट्टी सड़कों को अलग करती हो। पेंट की हुई रेखाएँ विभाजित राजमार्ग नहीं बनातीं, इसलिए केवल दोहरी पीली रेखा अकेले अपवाद को लागू नहीं करती। स्रोत: Md. Code, Transportation 21-706; Maryland MVA मार्गदर्शन।"},"65":{"q":"भौतिक मीडियन वाले मैरीलैंड विभाजित राजमार्ग पर, जब विपरीत ओर की स्कूल बस अपनी लाल लाइटें चमकाती है, तो किसे फिर भी रुकना चाहिए?","options":["बस के समान दिशा में, उसके पीछे यात्रा कर रहे ड्राइवर","दोनों सड़कों पर सभी ड्राइवरों को रुकना चाहिए","किसी भी विभाजित राजमार्ग पर किसी ड्राइवर को रुकने की आवश्यकता नहीं है","केवल मीडियन के तुरंत बगल की लेन में मौजूद ड्राइवर"],"explanation":"विभाजित राजमार्ग पर भी, बस का समान दिशा में पीछा कर रहे यातायात को रुकना चाहिए। केवल भौतिक मीडियन से अलग किए गए विपरीत यातायात को छूट है। स्रोत: Md. Code, Transportation 21-706।"},"66":{"q":"इंटरस्टेट राजमार्गों और एक्सप्रेसवे सहित मैरीलैंड के किसी भी राजमार्ग पर पोस्ट की जा सकने वाली पूर्ण अधिकतम गति सीमा क्या है?","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"मैरीलैंड कानून अधिकतम गति सीमा को 70 mph तक सीमित करता है, जिसे केवल कुछ इंटरस्टेट राजमार्गों और एक्सप्रेसवे पर पोस्ट किया जा सकता है; कोई भी मैरीलैंड राजमार्ग 70 mph से अधिक पोस्ट नहीं कर सकता। स्रोत: Md. Code, Transportation 21-801.1; MDOT SHA।"},"67":{"q":"मैरीलैंड उसी राजमार्ग पर यात्री कारों की तुलना में ट्रकों और अन्य वाणिज्यिक मोटर वाहनों के लिए अधिकतम गति सीमा कैसे निर्धारित करता है?","options":["ट्रक अन्य वाहनों के समान पोस्ट की गई अधिकतम सीमा का पालन करते हैं; मैरीलैंड में ट्रकों के लिए कोई अलग कम राज्यव्यापी गति सीमा नहीं है","ट्रक पोस्ट की गई सीमा की परवाह किए बिना राज्यव्यापी रूप से 55 mph तक सीमित हैं","ट्रक सभी राजमार्गों पर पोस्ट की गई सीमा से 10 mph नीचे तक सीमित हैं","ट्रक 65 mph तक सीमित हैं जबकि कारें हर इंटरस्टेट पर 70 mph चल सकती हैं"],"explanation":"कुछ राज्यों के विपरीत, मैरीलैंड ट्रकों के लिए कोई अलग, कम राज्यव्यापी गति सीमा निर्धारित नहीं करता। वाणिज्यिक वाहन अन्य यातायात के समान पोस्ट की गई सीमाओं का पालन करते हैं (70 mph की अधिकतम सीमा तक)। स्रोत: Md. Code, Transportation 21-801.1; MDOT SHA गति-सीमा मार्गदर्शन।"},"68":{"q":"मैरीलैंड द्वारा CDL ड्राइवरों पर लागू नियमों के अनुसार, किन वाणिज्यिक वाहनों को रेल पटरियों को समतल पर पार करने से पहले रुकना चाहिए?","options":["यात्रियों को ले जाने वाली बसें और प्लेकार्ड वाली खतरनाक सामग्री ले जाने वाले वाहन","10,000 पाउंड से अधिक के सभी वाणिज्यिक मोटर वाहन","केवल डबल या ट्रिपल ट्रेलर खींचने वाले वाहन","केवल खाली टैंक वाहन जो पहले ज्वलनशील पदार्थ ले जा चुके हों"],"explanation":"मैरीलैंड अपने CDL मैनुअल में अपनाए गए संघीय नियम (49 CFR 392.10) का पालन करता है: यात्रियों को ले जाने वाली बसें और प्लेकार्ड वाले हैजमैट वाहनों को समतल क्रॉसिंग पर रुकना चाहिए। अधिकांश अन्य ट्रकों को रुकने की आवश्यकता नहीं है जब तक कि संकेत या सिग्नल इसका निर्देश न दें। स्रोत: Maryland CDL Manual; 49 CFR 392.10।"},"69":{"q":"जब किसी प्लेकार्ड वाले हैजमैट ट्रक या यात्री बस को मैरीलैंड रेलमार्ग क्रॉसिंग पर रुकना आवश्यक हो, तो उसे निकटतम रेल से कितनी दूरी के भीतर रुकना चाहिए?","options":["निकटतम रेल से 15 फीट से अधिक पास नहीं और 50 फीट से अधिक दूर नहीं","निकटतम रेल से 5 फीट से अधिक पास नहीं और 25 फीट से अधिक दूर नहीं","निकटतम रेल से 25 फीट से अधिक पास नहीं और 75 फीट से अधिक दूर नहीं","निकटतम रेल से 10 फीट से अधिक पास नहीं और 100 फीट से अधिक दूर नहीं"],"explanation":"रुकना-आवश्यक CMVs को निकटतम रेल से 50 फीट के भीतर, लेकिन 15 फीट से अधिक पास नहीं, रुकना चाहिए, फिर आगे बढ़ने से पहले देखना और सुनना चाहिए। स्रोत: Maryland CDL Manual; 49 CFR 392.10।"},"70":{"q":"रेलमार्ग क्रॉसिंग पर रुकने के बाद, कोई मैरीलैंड बस या प्लेकार्ड वाला हैजमैट ड्राइवर केवल क्या करने के बाद आगे बढ़ सकता है?","options":["आने वाली ट्रेन के लिए दोनों दिशाओं में देखना और सुनना और यह पुष्टि करना कि क्रॉसिंग को बिना रुके साफ किया जा सकता है","गति बनाए रखने के लिए पटरियों को पार करते समय कम से कम एक बार गियर बदलना","ट्रेन आ रही हो या न आ रही हो, अनिवार्य 30 सेकंड प्रतीक्षा करना","क्रॉसिंग में प्रवेश करने से पहले तीन बार हॉर्न बजाना"],"explanation":"15-से-50-फीट क्षेत्र के भीतर रुकने के बाद, ड्राइवर को ट्रेन के लिए दोनों ओर देखना और सुनना चाहिए और तब तक पार करना शुरू नहीं करना चाहिए जब तक पटरियों को बिना रुके पूरी तरह साफ करने के लिए जगह न हो। ड्राइवरों को पटरियों पर रहते हुए गियर नहीं बदलना चाहिए। स्रोत: Maryland CDL Manual; 49 CFR 392.10।"},"71":{"q":"जब किसी मैरीलैंड CDL ड्राइवर को राजमार्ग के यात्रा किए जाने वाले भाग या शोल्डर पर ट्रक रोकना पड़े, तो चेतावनी उपकरण (परावर्तक त्रिकोण) कितने मिनट के भीतर रखे जाने चाहिए?","options":["रुकने के 10 मिनट के भीतर","रुकने के 5 मिनट के भीतर","रुकने के 15 मिनट के भीतर","रुकने के 30 मिनट के भीतर"],"explanation":"रुके हुए CMV के ड्राइवर को 10 मिनट के भीतर चेतावनी उपकरण रखने चाहिए। यह संघीय मानक मैरीलैंड CDL मैनुअल में पढ़ाया जाता है और मैरीलैंड में लागू होता है। स्रोत: Maryland CDL Manual; 49 CFR 392.22।"},"72":{"q":"दो-लेन, दो-तरफा सड़क पर, किसी मैरीलैंड CDL ड्राइवर को रुके हुए ट्रक के लिए तीन आवश्यक चेतावनी त्रिकोण कहाँ रखने चाहिए?","options":["वाहन के लगभग 10 फीट पीछे यातायात की ओर, लगभग 100 फीट पीछे, और वाहन के लगभग 100 फीट आगे","तीनों त्रिकोण वाहन के 200 फीट पीछे एक पंक्ति में","केवल वाहन के लगभग 50 फीट, 150 फीट, और 250 फीट पीछे","दृश्यता को अधिकतम करने के लिए एक हुड पर और दो छत पर"],"explanation":"दो-तरफा सड़क पर, एक त्रिकोण यातायात की ओर लगभग 10 फीट पीछे, एक लगभग 100 फीट पीछे, और एक लगभग 100 फीट आगे रखें, ताकि दोनों दिशाओं के यातायात को चेतावनी मिले। स्रोत: Maryland CDL Manual; 49 CFR 392.22।"},"73":{"q":"एक-तरफा या विभाजित राजमार्ग पर, किसी मैरीलैंड CDL ड्राइवर को रुके हुए ट्रक के पीछे तीन चेतावनी त्रिकोणों को कैसे रखना चाहिए?","options":["आने वाले यातायात की ओर लगभग 10 फीट, 100 फीट, और 200 फीट पर","आने वाले यातायात की ओर लगभग 10 फीट, 50 फीट, और 100 फीट पर","आने वाले यातायात की ओर लगभग 25 फीट, 75 फीट, और 150 फीट पर","आने वाले यातायात की ओर लगभग 50 फीट, 100 फीट, और 500 फीट पर"],"explanation":"एक-तरफा या विभाजित राजमार्ग पर, तीनों त्रिकोण आने वाले यातायात की ओर वाहन से लगभग 10, 100, और 200 फीट पर जाते हैं। स्रोत: Maryland CDL Manual; 49 CFR 392.22।"},"74":{"q":"मैरीलैंड का दाएँ-रहो कानून धीमे वाहन को दाहिनी ओर की लेन का उपयोग करने के लिए आवश्यक करता है। अधिकतम गति सीमा से कितना नीचे यात्रा करने वाले वाहन को दाएँ रहना चाहिए (पास करने या बाएँ मुड़ने को छोड़कर)?","options":["लागू अधिकतम गति सीमा से 10 mph या अधिक नीचे","लागू अधिकतम गति सीमा से 5 mph या अधिक नीचे","लागू अधिकतम गति सीमा से 15 mph या अधिक नीचे","लागू अधिकतम गति सीमा से 20 mph या अधिक नीचे"],"explanation":"Md. Transportation 21-301 के अनुसार अधिकतम सीमा से 10 mph या अधिक नीचे जा रहे किसी भी वाहन (या जब परिस्थितियाँ आवश्यक करें तो सामान्य यातायात से धीमे) को दाहिनी ओर की लेन में रहना चाहिए, सिवाय जब आगे निकलते समय या बाएँ मुड़ने की तैयारी कर रहे हों। स्रोत: Md. Code, Transportation 21-301।"},"75":{"q":"समान दिशा में दो या अधिक लेन वाली मैरीलैंड सड़क पर, यह क्या नियंत्रित करता है कि ट्रक, ट्रक ट्रैक्टर, ट्रेलर, या बस को किस लेन का उपयोग करना चाहिए?","options":["किसी भी यातायात-नियंत्रण उपकरण के निर्देश जो वाहन को किसी निश्चित लेन में चलाए जाने की आवश्यकता करते हैं","ड्राइवर की पसंद, क्योंकि लेन संकेत वाणिज्यिक वाहनों पर लागू नहीं होते","एक निश्चित नियम कि सभी ट्रकों को केवल सबसे बाईं लेन का उपयोग करना चाहिए","जिस भी लेन में उस समय सबसे कम यात्री वाहन हों"],"explanation":"मैरीलैंड कानून (Transportation 21-301 और संबंधित लेन-उपयोग नियम) ट्रकों, ट्रक ट्रैक्टरों, ट्रेलरों, और बसों को उनके लिए विशिष्ट लेन निर्धारित करने वाले यातायात-नियंत्रण उपकरणों का पालन करने के लिए आवश्यक करता है। स्रोत: Md. Code, Transportation 21-301; 21-309।"},"76":{"q":"वाणिज्यिक ट्रकों को आम तौर पर बाल्टीमोर-वाशिंगटन पार्कवे (MD 295 का नेशनल पार्क सर्विस खंड) से क्यों प्रतिबंधित किया जाता है?","options":["यह एक संघीय पार्कवे है जो वाणिज्यिक वाहनों पर प्रतिबंध लगाता है; ट्रकों को विशेष परमिट न होने तक I-95 या अन्य ट्रक मार्गों का उपयोग करना चाहिए","किसी भी यात्री कार से चौड़े वाहन के लिए सड़क बहुत संकरी है","यह एक टोल सड़क है जो वाणिज्यिक ट्रांसपोंडर स्वीकार नहीं करती","यह ट्रकों को केवल आधी रात और सुबह 5 बजे के बीच अनुमति देती है"],"explanation":"NPS द्वारा संचालित बाल्टीमोर-वाशिंगटन पार्कवे वाणिज्यिक वाहनों पर प्रतिबंध लगाती है; ट्रकों के लिए संकेत दिए गए हैं और उन्हें I-95 या अन्य निर्धारित ट्रक मार्गों का उपयोग करना चाहिए। RV और बसों को आम तौर पर अनुमति है, लेकिन वाणिज्यिक ट्रकों को परमिट के बिना नहीं। स्रोत: National Park Service पार्कवे विनियम; Maryland ट्रक-मार्ग मार्गदर्शन।"},"77":{"q":"मैरीलैंड में फोर्ट मैकहेनरी टनल (I-95) और बाल्टीमोर हार्बर टनल (I-895) से किन वर्गों के कार्गो प्रतिबंधित हैं?","options":["विस्फोटक, थोक गैसोलीन और ज्वलनशील तरल पदार्थ, और अनुमत सीमा से अधिक बोतलबंद प्रोपेन, अन्य खतरनाक सामग्रियों के साथ","प्रशीतित खाद्य लोड और जीवित जानवर","40,000 पाउंड सकल से अधिक वजन का कोई भी लोड","सामग्री की परवाह किए बिना डबल या ट्रिपल ट्रेलरों में ले जाए गए सभी लोड"],"explanation":"MDTA फोर्ट मैकहेनरी और बाल्टीमोर हार्बर टनल से विस्फोटक, थोक गैसोलीन/ज्वलनशील तरल पदार्थ, कुछ रेडियोधर्मी सामग्री, और अनुमत सीमा से अधिक बोतलबंद प्रोपेन (प्रति कंटेनर 10 lb से अधिक) पर प्रतिबंध लगाता है। स्रोत: MDTA निषिद्ध-खतरनाक-सामग्री सूची; mdta.maryland.gov।"},"78":{"q":"बाल्टीमोर टनलों से प्रतिबंधित प्लेकार्ड वाली हैजमैट ढो रहे मैरीलैंड CDL ड्राइवर को बाल्टीमोर क्षेत्र से कौन सा मार्ग लेना चाहिए?","options":["हार्बर क्रॉसिंग के चारों ओर I-695 (बाहरी बेल्टवे) का पश्चिमी खंड","ऑफ-पीक घंटों के दौरान I-95 पर फोर्ट मैकहेनरी टनल से सीधे होकर","खतरे की लाइटें जलाकर I-895 पर बाल्टीमोर हार्बर टनल","डाउनटाउन बाल्टीमोर से कोई भी शहर की सड़क जो टोल से बचती हो"],"explanation":"टनलों से प्रतिबंधित हैजमैट लोड को I-695 के पश्चिमी भाग का उपयोग करके हार्बर के चारों ओर मोड़ना चाहिए। यह मार्ग और भी महत्वपूर्ण है क्योंकि की ब्रिज (दक्षिण-पूर्व I-695 क्रॉसिंग) 2024 में ढह गया था। स्रोत: MDTA टनल-प्रतिबंध/परमिट मार्गदर्शन; mdta.maryland.gov।"},"79":{"q":"पश्चिमी मैरीलैंड में I-68 की खड़ी पहाड़ी ढलानों (साइडलिंग हिल और बिग सैवेज माउंटेन के पास) पर, लंबी ढलान पर ब्रेक खोने वाले ट्रकों के लिए कौन सी सुरक्षा सुविधा प्रदान की जाती है?","options":["रनअवे ट्रक रैंप (एस्केप रैंप) जो वाहन को रोकने के लिए चढ़ाई और अवरोधक सामग्री का उपयोग करते हैं","अनिवार्य टनल जो ट्रकों को उतरने से पहले धीमा होने के लिए बाध्य करती हैं","उलटी जा सकने वाली टोल लेन जो केवल खराब ट्रकों के लिए खुलती हैं","गर्म फुटपाथ पट्टियाँ जो ढलान पर टायर की पकड़ बढ़ाती हैं"],"explanation":"पश्चिमी मैरीलैंड से होकर गुजरने वाली I-68 में खड़ी, लंबी ढलानें हैं; रनअवे ट्रक रैंप (चढ़ाई पर बजरी/रेत अवरोधक एस्केप रैंप) प्रदान किए जाते हैं ताकि विफल या अधिक गरम ब्रेक वाले ट्रक सुरक्षित रूप से रुक सकें। ड्राइवरों को कम गियर में उतरना चाहिए और उचित ब्रेकिंग तकनीक का उपयोग करना चाहिए। स्रोत: MDOT SHA; Maryland CDL Manual पर्वतीय-ड्राइविंग अनुभाग।"},"80":{"q":"कौन सी मैरीलैंड एजेंसी वाणिज्यिक ड्राइवर लाइसेंस (CDLs) जारी करती है?","options":["MDOT मोटर व्हीकल एडमिनिस्ट्रेशन (MVA)","मैरीलैंड स्टेट पुलिस कमर्शियल व्हीकल डिवीजन","फेडरल मोटर कैरियर सेफ्टी एडमिनिस्ट्रेशन (FMCSA)","मैरीलैंड डिपार्टमेंट ऑफ लेबर"],"explanation":"मैरीलैंड में CDLs MDOT मोटर व्हीकल एडमिनिस्ट्रेशन (MVA) द्वारा जारी किए जाते हैं। FMCSA संघीय CDL मानक निर्धारित करता है लेकिन स्वयं लाइसेंस जारी नहीं करता। स्रोत: Maryland MVA, Commercial Driver's License पेज।"},"81":{"q":"मैरीलैंड में CDL स्किल्स (रोड) टेस्ट निर्धारित करने से पहले, आपको अपना कमर्शियल लर्नर्स परमिट (CLP) कितने समय तक रखना आवश्यक है?","options":["कम से कम 14 दिन","कम से कम 7 दिन","कम से कम 30 दिन","कम से कम 60 दिन"],"explanation":"मैरीलैंड संघीय नियम का पालन करता है: CLP धारक CLP जारी होने के कम से कम 14 दिन बाद तक CDL स्किल्स टेस्ट देने के लिए पात्र नहीं है। स्रोत: Maryland MVA, Get or Renew a CDL।"},"82":{"q":"पहले Class A या Class B लाइसेंस के लिए कोई मैरीलैंड आवेदक CDL स्किल्स टेस्ट देने से पहले कौन सा प्रशिक्षण पूरा करना आवश्यक है?","options":["एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT)","राज्य-अनुमोदित डिफेंसिव ड्राइविंग कोर्स","FMCSA खतरनाक सामग्री सेमिनार","40-घंटे का MVA कक्षा अभिविन्यास"],"explanation":"मैरीलैंड आपको तब तक स्किल्स टेस्ट देने की अनुमति नहीं देगा जब तक आप संघीय रूप से आवश्यक एंट्री-लेवल ड्राइवर ट्रेनिंग (ELDT) पूरी नहीं कर लेते, जो पहले Class A या B CDL के लिए और पहले P, S, या H एंडोर्समेंट के लिए आवश्यक है। स्रोत: Maryland MVA / FMCSA ELDT नियम।"},"83":{"q":"मैरीलैंड CDL स्किल्स टेस्ट के तीन भाग हैं जिन्हें पास करना आवश्यक है। वे क्या हैं?","options":["प्री-ट्रिप वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग","लिखित ज्ञान, दृष्टि जाँच, और ऑन-रोड ड्राइविंग","एयर-ब्रेक टेस्ट, बैकिंग टेस्ट, और रात्रि ड्राइविंग","प्री-ट्रिप निरीक्षण, खतरनाक सामग्री संचालन, और ऑन-रोड ड्राइविंग"],"explanation":"मैरीलैंड के CDL स्किल्स टेस्ट में प्री-ट्रिप वाहन निरीक्षण, बुनियादी वाहन नियंत्रण कौशल, और ऑन-रोड ड्राइविंग टेस्ट शामिल हैं, और तीनों को सफलतापूर्वक पूरा किया जाना आवश्यक है। स्रोत: Maryland MVA, CDL Skills Test।"},"84":{"q":"मैरीलैंड के CDL स्व-प्रमाणन के तहत, कोई आवेदक वाणिज्यिक ड्राइविंग संचालन की कितनी श्रेणियाँ घोषित कर सकता है?","options":["चार","दो","तीन","पाँच"],"explanation":"मैरीलैंड CDL धारक चार श्रेणियों में से एक में स्व-प्रमाणित होते हैं: Non-Excepted Interstate (NI), Excepted Interstate (EI), Non-Excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"85":{"q":"कोई मैरीलैंड ड्राइवर 'Non-Excepted Interstate (NI)' के रूप में प्रमाणित होता है। इसका क्या अर्थ है?","options":["वे राज्य की सीमाओं के पार ड्राइव करते हैं और सभी संघीय चिकित्सा योग्यता आवश्यकताओं को पूरा करना चाहिए","वे केवल मैरीलैंड के भीतर ड्राइव करते हैं और संघीय चिकित्सा नियमों से छूट प्राप्त हैं","वे राज्य की सीमाओं के पार केवल विशिष्ट छूट प्राप्त गतिविधियों के लिए ड्राइव करते हैं","वे एक अनुमोदित MVA चिकित्सा छूट का उपयोग करके केवल मैरीलैंड के भीतर ड्राइव करते हैं"],"explanation":"Non-Excepted Interstate (NI) का अर्थ है कि ड्राइवर राज्य की सीमाओं के पार CMV संचालित करता है और सभी संघीय योग्यता (चिकित्सा सहित) आवश्यकताओं का पालन करता है। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"86":{"q":"किसी मैरीलैंड CDL धारक का DOT मेडिकल एग्जामिनर सर्टिफिकेट सामान्यतः MVA तक कैसे पहुँचता है?","options":["मेडिकल एग्जामिनर इसे FMCSA के नेशनल रजिस्ट्री में इलेक्ट्रॉनिक रूप से जमा करता है और MVA इसे स्वचालित रूप से प्राप्त करता है","ड्राइवर को 10 दिनों के भीतर कागज़ी सर्टिफिकेट MVA मुख्यालय को डाक से भेजना चाहिए","ड्राइवर का नियोक्ता ड्राइवर की ओर से इसे MVA को फैक्स करता है","सर्टिफिकेट केवल तभी अपलोड किया जाता है जब ड्राइवर व्यक्तिगत रूप से CDL का नवीनीकरण करता है"],"explanation":"प्रमाणित मेडिकल एग्जामिनर सर्टिफिकेट जानकारी इलेक्ट्रॉनिक रूप से FMCSA नेशनल रजिस्ट्री को भेजता है, और MVA चिकित्सा प्रमाणन स्वचालित रूप से प्राप्त करता है; ड्राइवर को इसे डाक से भेजने या जमा करने की आवश्यकता नहीं है। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"87":{"q":"यदि किसी मैरीलैंड ड्राइवर का DOT चिकित्सा प्रमाणन समाप्त हो जाए तो उसके वाणिज्यिक विशेषाधिकारों का क्या होता है?","options":["उनका CDL डाउनग्रेड हो जाता है और वे अब CMV संचालित करने के लिए योग्य नहीं रहते","जब तक वे इंट्रास्टेट ड्राइविंग जारी रखते हैं, 90 दिनों तक कुछ नहीं बदलता","बेस क्लास सहित उनका पूरा ड्राइवर लाइसेंस तुरंत निलंबित हो जाता है","MVA एक स्वचालित अस्थायी चिकित्सा छूट जारी करता है"],"explanation":"यदि चिकित्सा प्रमाणन समाप्त हो जाता है, तो ड्राइवर अब कानूनी रूप से CMV संचालित करने के लिए योग्य नहीं रहता और वाणिज्यिक ड्राइविंग विशेषाधिकार डाउनग्रेड हो जाते हैं। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"88":{"q":"किसी मैरीलैंड CDL आवेदक को MVA में दस्तावेज़ों का कौन सा सेट प्रदान करना आवश्यक है?","options":["पहचान, आयु, सामाजिक सुरक्षा संख्या, और मैरीलैंड निवास का प्रमाण","केवल एक वैध पासपोर्ट और एक उपयोगिता बिल","केवल पहचान का प्रमाण और एक नोटरीकृत नियोक्ता पत्र","केवल जन्म प्रमाणपत्र और वाहन बीमा का प्रमाण"],"explanation":"मैरीलैंड CDL आवेदकों को पहचान, आयु, सामाजिक सुरक्षा संख्या, और मैरीलैंड निवास का प्रमाण प्रस्तुत करना आवश्यक है। स्रोत: Maryland MVA, Get or Renew a CDL।"},"89":{"q":"मैरीलैंड में ड्राइविंग प्रकार का स्व-प्रमाणन निम्नलिखित सभी स्थितियों में आवश्यक है, सिवाय किसके?","options":["हर बार जब आप अपना वार्षिक वाहन पंजीकरण नवीनीकृत करते हैं","जब आप एक नया CDL प्राप्त करते हैं","जब आप अपना CDL नवीनीकृत या उन्नत करते हैं","जब आप इंटरस्टेट और इंट्रास्टेट ड्राइविंग के बीच बदलते हैं"],"explanation":"स्व-प्रमाणन तब आवश्यक है जब CDL प्राप्त करना, नवीनीकृत करना, स्थानांतरित करना, या उन्नत करना, चिकित्सा स्थिति बदलना, या इंटरस्टेट और इंट्रास्टेट ड्राइविंग के बीच बदलना — न कि नियमित वाहन पंजीकरण के लिए। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"90":{"q":"कौन सी श्रेणी ऐसे मैरीलैंड CDL धारक का वर्णन करती है जो केवल मैरीलैंड के भीतर CMV चलाता है और एक अनुमोदित MVA CDL मेडिकल वेवर रखता है?","options":["Non-Excepted Intrastate (NA)","Non-Excepted Interstate (NI)","Excepted Interstate (EI)","Excepted Intrastate (EA)"],"explanation":"Non-Excepted Intrastate (NA) ऐसे ड्राइवर पर लागू होता है जो केवल मैरीलैंड के भीतर संचालित करने के लिए योग्य है और जिसके पास एक अनुमोदित MVA CDL मेडिकल वेवर है। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"91":{"q":"एंडोर्समेंट की परवाह किए बिना, हर मैरीलैंड CDL आवेदक को पास करना आवश्यक पहला ज्ञान परीक्षण कौन सा है?","options":["जनरल नॉलेज टेस्ट","हैज़र्डस मैटेरियल्स टेस्ट","एयर ब्रेक्स टेस्ट","कॉम्बिनेशन व्हीकल्स टेस्ट"],"explanation":"सभी मैरीलैंड CDL आवेदकों को पहले CDL जनरल नॉलेज टेस्ट पास करना आवश्यक है; एंडोर्समेंट-विशिष्ट परीक्षण (P, S, N, H, T) आवश्यकतानुसार अतिरिक्त रूप से दिए जाते हैं। स्रोत: Maryland MVA / CDL Manual (DL-151)।"},"92":{"q":"कोई मैरीलैंड आवेदक CDL ज्ञान (लिखित) परीक्षण कहाँ देता है?","options":["पूरे मैरीलैंड में MVA कार्यालयों में इलेक्ट्रॉनिक रूप से","केवल MVA मुख्यालय को डाक से भेजे गए कागज़ी परीक्षा द्वारा","किसी भी FMCSA संघीय परीक्षण केंद्र पर","किसी भी अनुमोदित तृतीय-पक्ष वेबसाइट के माध्यम से घर से ऑनलाइन"],"explanation":"CDL ज्ञान परीक्षण पूरे मैरीलैंड में MVA कार्यालयों में इलेक्ट्रॉनिक रूप से प्रशासित किए जाते हैं। स्रोत: Maryland MVA, Knowledge Tests / Prepare for a Driver's License Test।"},"93":{"q":"मानक मैरीलैंड ड्राइवर लाइसेंस और CDL के लिए विशिष्ट नवीनीकरण चक्र (अवधि की लंबाई) क्या है?","options":["8 वर्ष","4 वर्ष","5 वर्ष","10 वर्ष"],"explanation":"मैरीलैंड ड्राइवर लाइसेंस, जिसमें CDLs भी शामिल हैं, आम तौर पर 8-वर्ष की अवधि के लिए जारी/नवीनीकृत किए जाते हैं। स्रोत: Maryland MVA, Renew a License or ID।"},"94":{"q":"मैरीलैंड CDL स्किल्स टेस्ट पर, तीन घटक आम तौर पर किस क्रम में संचालित किए जाते हैं?","options":["प्री-ट्रिप निरीक्षण, फिर बुनियादी नियंत्रण कौशल, फिर ऑन-रोड ड्राइविंग","ऑन-रोड ड्राइविंग, फिर प्री-ट्रिप निरीक्षण, फिर बुनियादी नियंत्रण कौशल","बुनियादी नियंत्रण कौशल, फिर ऑन-रोड ड्राइविंग, फिर प्री-ट्रिप निरीक्षण","ऑन-रोड ड्राइविंग, फिर बुनियादी नियंत्रण कौशल, फिर प्री-ट्रिप निरीक्षण"],"explanation":"मैरीलैंड स्किल्स टेस्ट को क्रम में संचालित करता है: पहले प्री-ट्रिप वाहन निरीक्षण, फिर बुनियादी वाहन नियंत्रण कौशल, फिर ऑन-रोड ड्राइविंग टेस्ट। स्रोत: Maryland MVA, CDL Skills Test।"},"95":{"q":"यदि कोई मैरीलैंड CDL धारक अपना चिकित्सा प्रमाणन समाप्त होने देता है और एक वर्ष से अधिक समय बीत जाता है, तो CDL वापस पाने के लिए उन्हें क्या करना चाहिए?","options":["सभी CDL ज्ञान और कौशल परीक्षण फिर से देना","बिना किसी परीक्षण के केवल एक नया चिकित्सा प्रमाणपत्र जमा करना","पुनर्बहाली शुल्क का भुगतान करना लेकिन कोई परीक्षण नहीं देना","केवल अनिवार्य 90-दिन के निलंबन की प्रतीक्षा करना"],"explanation":"यदि समाप्त चिकित्सा प्रमाणपत्र के कारण CDL डाउनग्रेड हो जाता है और एक वर्ष से अधिक समय बीत जाता है, तो ड्राइवर को CDL वापस पाने के लिए सभी CDL ज्ञान और कौशल परीक्षण फिर से देने होंगे। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"96":{"q":"कौन सी श्रेणी ऐसे मैरीलैंड CDL धारक के लिए उपयुक्त है जो राज्य की सीमाओं को केवल स्कूली बच्चों, बीमार या घायल व्यक्तियों, या शवों को ले जाने के लिए पार करता है?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Non-Excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Excepted Interstate (EI) ऐसे ड्राइवरों को कवर करता है जो राज्य की सीमाओं के पार केवल विशिष्ट छूट प्राप्त गतिविधियों के लिए संचालित करते हैं जैसे स्कूली बच्चों या कर्मचारियों, बीमार या घायल व्यक्तियों, या शवों को ले जाना। स्रोत: Maryland MVA, CDL Medical Certification Requirements।"},"97":{"q":"कौन सा परिदृश्य, अपने आप में, मैरीलैंड स्किल्स टेस्ट से पहले संघीय ELDT आवश्यकता को लागू नहीं करता?","options":["समान एंडोर्समेंट के साथ मौजूदा Class A CDL का नवीनीकरण करना","पहले Class A CDL के लिए आवेदन करना","Class B से Class A CDL में उन्नयन करना","पहला पैसेंजर (P) या स्कूल बस (S) एंडोर्समेंट प्राप्त करना"],"explanation":"ELDT पहले Class A या B CDL के लिए, Class B से Class A में उन्नयन के लिए, और पहले P, S, या H एंडोर्समेंट के लिए आवश्यक है — लेकिन मौजूदा CDL का सीधा नवीनीकरण अपने आप ELDT को लागू नहीं करता। स्रोत: Maryland MVA / FMCSA ELDT नियम।"},"98":{"q":"मैरीलैंड CDL स्किल्स (रोड) टेस्ट अपॉइंटमेंट आम तौर पर कैसे निर्धारित की जाती है?","options":["आवेदक के myMVA खाते के माध्यम से अपॉइंटमेंट बनाकर","बिना अपॉइंटमेंट के किसी भी MVA शाखा में वॉक-इन करके","FMCSA की राष्ट्रीय शेड्यूलिंग लाइन पर कॉल करके","CLP जारी होने के उसी दिन स्वचालित रूप से"],"explanation":"आवेदक अपने myMVA खाते के माध्यम से अपॉइंटमेंट बनाकर CDL स्किल्स टेस्ट निर्धारित करते हैं; CLP होल्ड और ELDT पूरा होने के बाद टेस्ट MVA द्वारा प्रशासित किया जाता है। स्रोत: Maryland MVA, CDL Skills Test।"}},"ar":{"0":{"q":"على طرق ولاية ماريلاند السريعة، ما هو الحد الأقصى القانوني لعرض المركبة (باستثناء المرايا وأجهزة السلامة/توفير الطاقة الأخرى) قبل أن يصبح تصريح الحمولة الزائدة عن الحجم مطلوباً؟","options":["96 بوصة (8 أقدام)","102 بوصة (8 أقدام و6 بوصات)","108 بوصات (9 أقدام)","120 بوصة (10 أقدام)"],"explanation":"تحدد المادة 24-102 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-102) الحد الأقصى لعرض المركبة بـ 102 بوصة (8 أقدام و6 بوصات)؛ ويُقاس العرض باستثناء المرايا ومصابيح الإشارة/الانعطاف وأجهزة توفير الطاقة. وأي مركبة أعرض من ذلك تحتاج إلى تصريح الحمولة الزائدة عن الحجم من إدارة الطرق السريعة بالولاية (SHA). المصدر: Md. Transp. § 24-102؛ دليل تصاريح النقل للحمولات الزائدة عن الحجم/الوزن الصادر عن MD SHA."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة وحمولتها على طرق ماريلاند السريعة دون تصريح؟","options":["12 قدماً و6 بوصات","13 قدماً","13 قدماً و6 بوصات","14 قدماً"],"explanation":"بموجب المادة 24-104 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-104)، لا يجوز أن يتجاوز ارتفاع المركبة وحمولتها 13 قدماً و6 بوصات. ويُدرج دليل التصاريح الصادر عن SHA القيمة 13'6\" بوصفها الحد القانوني دون أي شروط خاصة. المصدر: Md. Transp. § 24-104؛ دليل تصاريح النقل الصادر عن MD SHA (قسم الارتفاع)."},"2":{"q":"ما هو الحد الأقصى للوزن الإجمالي للمركبة المسموح به على الطرق السريعة بين الولايات في ماريلاند دون تصريح الوزن الزائد؟","options":["73,000 رطل","80,000 رطل","90,000 رطل","100,000 رطل"],"explanation":"تتبع ماريلاند المعيار الفيدرالي للطرق بين الولايات: الحد الأقصى للوزن الإجمالي هو 80,000 رطل (شاملاً الحمولة). المصدر: Md. Transp. § 24-109؛ 23 CFR 658.17 كما يُطبَّق على الطرق بين الولايات في ماريلاند."},"3":{"q":"على الطرق بين الولايات في ماريلاند، ما هو الحد الأقصى للوزن المسموح به على المحور الواحد؟","options":["17,000 رطل","20,000 رطل","22,400 رطل","34,000 رطل"],"explanation":"الحد الأقصى للمحور الواحد على شبكة الطرق بين الولايات في ماريلاند هو 20,000 رطل، بما يطابق المعيار الفيدرالي في المادة 24-109 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-109). المصدر: Md. Transp. § 24-109؛ 23 CFR 658.17."},"4":{"q":"على الطرق بين الولايات في ماريلاند، ما هو الحد الأقصى للوزن المسموح به على المحور المزدوج (التاندم)؟","options":["20,000 رطل","32,000 رطل","34,000 رطل","40,000 رطل"],"explanation":"الحد الأقصى للمحور المزدوج (التاندم) (مجموعة محورين تفصل بينهما مسافة أكثر من 40 بوصة ولا تزيد على 96 بوصة) هو 34,000 رطل بموجب المادة 24-109 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-109)، بما يتوافق مع المعيار الفيدرالي للطرق بين الولايات. المصدر: Md. Transp. § 24-109؛ 23 CFR 658.17."},"5":{"q":"أي مكتب تابع لجهة حكومية في ماريلاند يصدر تصاريح النقل للحمولات الزائدة عن الحجم/الوزن للسفر على الطرق التي تصونها الولاية؟","options":["وحدة ترخيص السائقين التابعة لإدارة المركبات الآلية (MVA)","مكتب المرور والسلامة التابع لـ SHA، شعبة الناقلين الآليين، وحدة تصاريح النقل","شعبة إنفاذ قوانين المركبات التجارية التابعة لشرطة ولاية ماريلاند","مكتب مرافق الرسوم التابع لهيئة النقل في ماريلاند"],"explanation":"تصدر تصاريح النقل للحمولات الزائدة عن الحجم/الوزن (OS/OW) عن إدارة الطرق السريعة بولاية ماريلاند (Maryland State Highway Administration)، مكتب المرور والسلامة، شعبة الناقلين الآليين – وحدة تصاريح النقل (هانوفر، ماريلاند). المصدر: دليل تصاريح النقل للحمولات الزائدة عن الحجم/الوزن الصادر عن MD SHA (المقدمة)."},"6":{"q":"لا يمكن تقليل الحمولة أكثر من ذلك ولكنها لا تزال تتجاوز الحدود القانونية في ماريلاند. أي مواد القانون تحدد الحدود القانونية للحجم والوزن التي تستوجب الحاجة إلى تصريح نقل خاص؟","options":["قانون النقل، الباب 16، المادتان 101 و102","قانون النقل، الباب 24، المادتان 108 و109","قانون النقل، الباب 21، المادتان 1101 و1102","قانون النقل، الباب 11، المادتان 301 و302"],"explanation":"ينص دليل التصاريح الصادر عن SHA على أنه عندما تتجاوز الحمولة الحدود القانونية المنصوص عليها في قانون المركبات الآلية في ماريلاند، الباب 24، المادتان 108 (أحمال المحاور) و109 (الوزن الإجمالي)، يجب شراء تصريح نقل خاص. المصدر: دليل تصاريح النقل الصادر عن MD SHA؛ Md. Transp. §§ 24-108, 24-109."},"7":{"q":"على الشبكة الوطنية وطرق النقل بالشاحنات المخصصة في ماريلاند، ما هو الحد الأقصى لطول نصف المقطورة الذي لا يتطلب تصريحاً؟","options":["48 قدماً","53 قدماً","57 قدماً","60 قدماً"],"explanation":"على الشبكة الوطنية وطرق النقل بالشاحنات المخصصة، يُسمح بأنصاف المقطورات حتى 53 قدماً دون تصريح (وتنطبق قيمة 48 قدماً على العديد من طرق الولاية السريعة الأخرى). المصدر: Md. Transp. § 24-104.1/24-104.2؛ ملخص J.J. Keller للحجم/الوزن في ماريلاند."},"8":{"q":"لا تفرض ماريلاند حداً ثابتاً للطول الكلي لتركيبة الجرار ونصف المقطورة على الشبكة الوطنية، لكن الوزن على أي مجموعة من المحاور يبقى محدوداً بأي حساب؟","options":["الصيغة الفيدرالية للجسور (جدول الوزن الإجمالي للجسور)","تقدير الوزن الإجمالي للمحور من الشركة المصنّعة فقط","قيمة ثابتة قدرها 1,000 رطل لكل بوصة من عرض الإطار","الوزن الفارغ المسجَّل مضروباً في اثنين"],"explanation":"تطبّق ماريلاند الصيغة الفيدرالية للجسور على شبكتها بين الولايات/الشبكة الوطنية: يخضع الحد الأقصى للوزن على أي مجموعة من المحاور المتتالية لصيغة الجسور، حتى الحد الكلي البالغ 80,000 رطل. المصدر: Md. Transp. § 24-109؛ 23 CFR 658.17 الصيغة الفيدرالية للجسور."},"9":{"q":"تتجاوز مركبة مركّبة الوزن القانوني في ماريلاند. حتى أي وزن إجمالي يجوز لتصريح نقل الوزن الزائد الاعتيادي الصادر عن SHA أن يأذن بالسفر، وعلى أي طرق؟","options":["حتى 100,000 رطل على أي طريق سريع تابع للولاية","حتى 120,000 رطل على أي طريق تابع للولاية","حتى 150,000 رطل على الطرق بين الولايات فقط","حتى 200,000 رطل على الطريق الدائري للعاصمة فقط"],"explanation":"ينص دليل SHA على أن حمولات التصاريح للمركبات المركّبة التي تصل حتى 150,000 رطل دون تجاوزها مسموح بها على الطرق بين الولايات فقط (دون اللجوء إلى مكتب تطوير الجسور)، شريطة استيفاء قواعد وزن/تباعد المحاور. المصدر: دليل تصاريح النقل الصادر عن MD SHA (الوزن، 'أكثر من 60 طناً')."},"10":{"q":"بموجب جدول رسوم التصاريح الصادر عن SHA في ماريلاند، ما هي الرسوم الأساسية لتصريح النقل عندما يبلغ وزن الحمولة المجمَّعة 90,000 رطل (45 طناً) أو أقل؟","options":["10.00 دولارات","30.00 دولاراً","50.00 دولاراً","100.00 دولار"],"explanation":"يحدد دليل SHA رسوماً أساسية قدرها 30.00 دولاراً لتصريح النقل عندما يبلغ وزن الحمولة الزائدة عن الأبعاد/المجمَّعة أقل من 90,000 رطل؛ وتضيف الحمولات التي تزيد على 45 طناً (90,000 رطل) مبلغ 5.00 دولارات عن كل طن إضافي. المصدر: دليل تصاريح النقل الصادر عن MD SHA (معلومات عامة؛ رسوم التصاريح)."},"11":{"q":"بالنسبة للحمولة المصرَّح بها التي تتجاوز 45 طناً (90,000 رطل)، كم تضيف SHA في ماريلاند إلى رسوم التصريح عن كل طن إضافي؟","options":["2.00 دولار لكل طن","5.00 دولارات لكل طن","10.00 دولارات لكل طن","25.00 دولاراً لكل طن"],"explanation":"ينص الدليل على أنه بالنسبة للحمولات التي تزيد على 45 طناً (90,000 رطل)، يُفرض مبلغ إضافي قدره 5.00 دولارات عن كل طن إضافي (مثال: 50 طناً = 55.00 دولاراً). المصدر: دليل تصاريح النقل الصادر عن MD SHA (معلومات عامة؛ جدول رسوم التصاريح)."},"12":{"q":"بموجب قواعد ماريلاند العامة لساعات التحرك، متى لا يجوز تحريك حمولة مصرَّح بها زائدة عن الحجم/الوزن؟","options":["فقط بين منتصف الليل والساعة 6:00 صباحاً في أيام الأسبوع","أي يوم سبت بعد الساعة 12:00 ظهراً وطوال يوم الأحد","فقط في أول يوم اثنين من كل شهر","فقط خلال ساعات الذروة المعلنة في بالتيمور"],"explanation":"وفقاً لدليل SHA وللباب 11 من مدونة لوائح ماريلاند (COMAR)، لا يجوز تحريك أي حمولة مصرَّح بها في أي يوم سبت بعد الساعة 12:00 ظهراً، أو في أي يوم أحد، أو خلال فترات العطلات المدرجة. والقاعدة عدا ذلك هي التحرك في وضح النهار (من نصف ساعة بعد الشروق إلى نصف ساعة قبل الغروب). المصدر: دليل تصاريح النقل الصادر عن MD SHA (ساعات التحرك)؛ COMAR 11.04."},"13":{"q":"عند أي عرض تتطلب الحمولة المصرَّح بها (عدا المنزل المتنقل/المعياري) لأول مرة مركبة مرافِقة خاصة واحدة في ماريلاند؟","options":["أكثر من 10 أقدام عرضاً","أكثر من 12 قدماً عرضاً","أكثر من 13 قدماً عرضاً","أكثر من 14 قدماً عرضاً"],"explanation":"يتطلب دليل SHA مرافِقاً خاصاً واحداً للحمولات التي يزيد عرضها على 13 قدماً (تحتاج الحمولات في نطاق 13'1\"–13'11\" إلى مرافِق خاص واحد)، مع اشتراط مرافِقين خاصين اثنين عند عرض 14 قدماً أو أكثر. المصدر: دليل تصاريح النقل الصادر عن MD SHA (العرض؛ المرافِقون – الشروط العامة)."},"14":{"q":"في ماريلاند، كم مركبة مرافِقة خاصة تتطلبها حمولة مصرَّح بها عرضها 14 قدماً أو أكثر؟","options":["لا يُشترط أي مرافِق","مرافِق خاص واحد","مرافِقان خاصان","أربعة مرافِقين خاصين"],"explanation":"يحدد دليل SHA أن جميع الحمولات التي يبلغ عرضها 14 قدماً أو أكثر تتطلب مرافِقين خاصين اثنين للتحرك داخل ماريلاند وعبرها. المصدر: دليل تصاريح النقل الصادر عن MD SHA (العرض؛ المرافِقون – الشروط العامة)."},"15":{"q":"أي بُعد أو وزن يجعل الحمولة المصرَّح بها في ماريلاند 'حمولة فائقة' (Super Load) على الطرق السريعة بين الولايات؟","options":["أكثر من 90,000 رطل إجمالاً أو 11 قدماً عرضاً","تجاوز 150,000 رطل (75 طناً) أو 27,000 رطل على أي محور","تجاوز 80,000 رطل أو 12 قدماً ارتفاعاً","أي حمولة تتطلب مرافِقاً خاصاً واحداً"],"explanation":"يعرّف دليل SHA الحمولات الفائقة (Super Loads)، من بين أمور أخرى، بأنها تلك التي تتجاوز 150,000 رطل (75 طناً) أو تتجاوز 27,000 رطل على أي محور على الطرق السريعة بين الولايات (أو تتجاوز 120,000 رطل / 60 طناً أو 27,000 رطل لكل محور على طرق ماريلاند السريعة التابعة للولاية)، أو 120 قدماً طولاً، أو 16 قدماً عرضاً، أو 16 قدماً ارتفاعاً. المصدر: دليل تصاريح النقل الصادر عن MD SHA (المرافِقون – الشروط العامة، الحمولات الفائقة)."},"16":{"q":"على طرق ماريلاند السريعة التابعة للولاية (غير الطرق بين الولايات)، تجاوز أي وزن إجمالي يصنّف الحمولة المصرَّح بها بوصفها 'حمولة فائقة' مفرطة؟","options":["80,000 رطل (40 طناً)","100,000 رطل (50 طناً)","120,000 رطل (60 طناً)","150,000 رطل (75 طناً)"],"explanation":"يصنّف دليل SHA الحمولة بوصفها حمولة فائقة على طرق ماريلاند السريعة التابعة للولاية عندما تتجاوز 120,000 رطل (60 طناً) أو تتجاوز 27,000 رطل على أي محور. أما عتبة 150,000 رطل (75 طناً) فتنطبق على الطرق السريعة بين الولايات. المصدر: دليل تصاريح النقل الصادر عن MD SHA (الحمولات الفائقة)."},"17":{"q":"باستثناء الطرق السريعة بين الولايات، ما هو سماح حمل المحور الذي يتيحه قانون ماريلاند لمركبة زراعية تنقل منتجات زراعية من الحقل خلال فترات الحصاد المدرجة؟","options":["سماح حمل محور بنسبة 5%","سماح حمل محور بنسبة 10%","سماح حمل محور بنسبة 15%","لا يُسمح بأي سماح في أي وقت"],"explanation":"تتيح المادة 24-109 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-109) للمركبات الزراعية (خارج الطرق بين الولايات) سماح محور بنسبة 5% عادةً، يُزاد إلى سماح حمل محور بنسبة 15% خلال فترات الحصاد المحددة (مثل القمح من 1 يونيو إلى 15 أغسطس، والذرة من 1 يوليو إلى 1 ديسمبر)، مع سماح وزن إجمالي بنسبة 5% ضمن نطاق 100 ميل من الحقل. المصدر: Md. Transp. § 24-109 (التباين الزراعي في وقت الحصاد)."},"18":{"q":"باستثناء الطرق السريعة بين الولايات، ما هو سماح حمل المحور المسموح به لتركيبة تنقل منتجات الغابات من غابة (نصف مقطورة 45 قدماً أو أقل) في الفترة من 1 يونيو حتى 30 سبتمبر؟","options":["سماح حمل محور بنسبة 5%","سماح حمل محور بنسبة 10%","سماح حمل محور بنسبة 15%","سماح حمل محور بنسبة 20%"],"explanation":"تتيح المادة 24-109 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-109) لتركيبة منتجات الغابات (نصف مقطورة 45 قدماً أو أقل، محمّلة خارج الطريق، وليست على الطرق بين الولايات) سماح محور بنسبة 5%، يُزاد إلى 15% من 1 يونيو حتى 30 سبتمبر. المصدر: Md. Transp. § 24-109 (تباين منتجات الغابات)."},"19":{"q":"تتيح ماريلاند (تبعاً للقانون الفيدرالي) للمركبة الثقيلة سماح وزن إضافياً صغيراً لتعويض وزن أي جهاز موفّر للوقود، دون انتهاك حدود الوزن الإجمالي/المحور/صيغة الجسور؟","options":["نظام النفخ التلقائي للإطارات، حتى 1,000 رطل إضافي","وحدة طاقة مساعدة / تقنية تقليل التشغيل الخامل، حتى 550 رطلاً إضافياً","وحدة تبريد، حتى 2,000 رطل إضافي","إطار مفرد عريض القاعدة، حتى 250 رطلاً إضافياً"],"explanation":"تسمح المادة 24-109 من قانون النقل في ماريلاند (Maryland Transportation Article § 24-109) بما يصل إلى 550 رطلاً إضافياً إجمالاً في الوزن الإجمالي أو وزن المحور أو التاندم أو صيغة الجسور لمراعاة وحدة الطاقة المساعدة أو وحدة تقنية تقليل التشغيل الخامل، بما يتوافق مع القانون الفيدرالي. المصدر: Md. Transp. § 24-109 (سماح تقليل التشغيل الخامل)؛ 23 CFR 658.17."},"20":{"q":"في ماريلاند، أي فئة من CDL مطلوبة لتشغيل مركبة مركّبة بتقدير وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطل أو أكثر، حيث يكون للوحدة المقطورة تقدير وزن إجمالي للمركبة (GVWR) يتجاوز 10,000 رطل؟","options":["الفئة A","الفئة B","الفئة C","الفئة D"],"explanation":"تعرّف ماريلاند رخصة CDL من الفئة A بأنها مركبة مركّبة ذات جرار/وحدة قوة ومقطورة (مقطورات) لها تقدير وزن إجمالي للتركيبة (GCWR) يبلغ 26,001 رطل أو أكثر، مع وحدة مقطورة بتقدير وزن إجمالي (GVWR) يتجاوز 10,000 رطل. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود؛ الدليل DL-151."},"21":{"q":"بموجب قواعد Maryland MVA، أي فئة من CDL تأذن بقيادة أي مركبة مفردة بتقدير وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطل أو أكثر (تقطر وحدة لا تتجاوز 10,000 رطل)؟","options":["الفئة A","الفئة B","الفئة C","الفئة M"],"explanation":"تغطي رخصة CDL من الفئة B في ماريلاند المركبات المفردة بتقدير وزن إجمالي للمركبة (GVWR) يبلغ 26,001 رطل أو أكثر، أو مثل هذه المركبة وهي تقطر وحدة لا يتجاوز تقدير وزنها الإجمالي (GVWR) 10,000 رطل. وتشمل الأمثلة الشاحنات الصندوقية المستقيمة ومعظم الحافلات. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود."},"22":{"q":"مركبة في ماريلاند مقدَّرة بأقل من 26,001 رطل لكنها مصممة لنقل 16 راكباً أو أكثر (بمن فيهم السائق)، أو تنقل مواد خطرة تتطلب لافتات. أي فئة من CDL تنطبق؟","options":["الفئة A","الفئة B","الفئة C","الفئة E"],"explanation":"تغطي رخصة CDL من الفئة C في ماريلاند المركبات التجارية الأصغر التي لا تستوفي معايير الوزن للفئة A أو B لكنها مصممة لنقل 16 راكباً أو أكثر (بمن فيهم السائق) أو تنقل مواد خطرة تتطلب لافتات. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود؛ الدليل DL-151."},"23":{"q":"في ماريلاند، أي رمز تظهير مطلوب لتشغيل مركبة مصممة لنقل 16 راكباً أو أكثر، مثل الحافلة؟","options":["التظهير N","التظهير P","التظهير T","التظهير H"],"explanation":"تتطلب ماريلاند تظهير P (الركاب) لتشغيل المركبات التي تنقل 16 راكباً أو أكثر. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود."},"24":{"q":"لقيادة حافلة مدرسية في ماريلاند، أي مجموعة تظهيرات تتطلبها MVA؟","options":["تظهير S فقط","تظهير P فقط","كل من تظهير P (الركاب) وتظهير S (الحافلة المدرسية)","كل من تظهير S (الحافلة المدرسية) وتظهير H (المواد الخطرة)"],"explanation":"تتطلب ماريلاند كلاً من تظهير P (الركاب) وتظهير S (الحافلة المدرسية) لتشغيل حافلة مدرسية. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود."},"25":{"q":"أي تظهير CDL في ماريلاند مطلوب لتشغيل مركبة تنقل سوائل أو غازات في خزان، مثل صهريج وقود أو ماء؟","options":["التظهير H","التظهير N","التظهير T","التظهير P"],"explanation":"تستخدم ماريلاند تظهير N (المركبة الصهريجية) للمركبات التي تنقل سوائل أو غازات في خزانات، مثل صهاريج الوقود أو الماء. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود."},"26":{"q":"في ماريلاند، ماذا يجمع تظهير 'X' على رخصة CDL؟","options":["الركاب (P) والحافلة المدرسية (S)","المركبة الصهريجية (N) والمواد الخطرة (H)","المقطورات المزدوجة/الثلاثية (T) والصهريج (N)","المواد الخطرة (H) والركاب (P)"],"explanation":"تظهير X في ماريلاند هو دمج لتظهير N (المركبة الصهريجية) وتظهير H (المواد الخطرة)، ويأذن بنقل المواد الخطرة في المركبات الصهريجية. المصدر: Maryland MVA، تصنيفات CDL والتظهيرات والقيود."},"27":{"q":"ما هو الحد الأدنى للعمر للحصول على رخصة CDL في ماريلاند مقيَّدة بالقيادة التجارية داخل الولاية (داخل ماريلاند فقط)؟","options":["16 عاماً","18 عاماً","21 عاماً","25 عاماً"],"explanation":"تتيح ماريلاند الحصول على رخصة CDL في سن 18 للقيادة داخل الولاية (ضمن ماريلاند)، بينما تتطلب القيادة بين الولايات سن 21. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها؛ الدليل DL-151."},"28":{"q":"وفقاً لـ Maryland MVA، ما هو الحد الأدنى للعمر المطلوب لقيادة مركبة تجارية في التجارة بين الولايات (عبر حدود الولايات)؟","options":["18 عاماً","19 عاماً","21 عاماً","23 عاماً"],"explanation":"تتطلب ماريلاند أن يكون عمر السائقين 21 عاماً على الأقل لتشغيل مركبة CDL بين الولايات (عبر حدود الولايات)، أو لنقل مواد خطرة تتطلب لافتات، أو لنقل ركاب بين الولايات. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها."},"29":{"q":"حامل رخصة CDL في ماريلاند يبلغ من العمر 19 عاماً ممنوع قانونياً من أي مما يلي؟","options":["قيادة شاحنة مستقيمة داخل ماريلاند","قيادة مركبة تجارية عبر حدود الولايات","حمل تظهير الركاب (P) للاستخدام داخل الولاية","قيادة مركبة من الفئة B داخل ماريلاند"],"explanation":"لا يجوز لسائق في ماريلاند يتراوح عمره بين 18 و21 عاماً قيادة مركبة تجارية خارج ماريلاند (بين الولايات)، ولا قيادة مركبة تتطلب لافتات المواد الخطرة، ولا تشغيل تركيبات المقطورات المزدوجة/الثلاثية. المصدر: Maryland MVA / الدليل DL-151."},"30":{"q":"بموجب القاعدة الفيدرالية المطبَّقة في ماريلاند، كم يجب أن يحمل المتقدم تصريح المتعلّم التجاري (CLP) قبل أن يُسمح له بإجراء اختبار مهارات CDL (اختبار الطريق)؟","options":["14 يوماً على الأقل","10 أيام على الأقل","7 أيام على الأقل","30 يوماً على الأقل"],"explanation":"تطبّق ماريلاند القاعدة الفيدرالية التي تشترط حمل تصريح المتعلّم التجاري (CLP) لمدة 14 يوماً على الأقل قبل إمكان إجراء اختبار مهارات CDL (اختبار الطريق). المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها؛ 49 CFR 383.25."},"31":{"q":"قبل إصدار تصريح المتعلّم التجاري (CLP) في ماريلاند، يجب أن يكون المتقدم حاملاً بالفعل أي مستند اعتماد؟","options":["رخصة قيادة سارية في ماريلاند (لغير الدراجات النارية)","رخصة دراجة نارية من ماريلاند","بطاقة TWIC الفيدرالية","رخصة CDL من ولاية أخرى"],"explanation":"تتطلب ماريلاند أن يكون المتقدمون لتصريح المتعلّم التجاري (CLP) حاملين بالفعل رخصة قيادة سارية في ماريلاند (وليست رخصة للدراجات النارية فقط) وأن يجتازوا اختباري الرؤية والمعرفة. المصدر: Maryland MVA / الدليل DL-151."},"32":{"q":"أي مجموعة من المستندات تتطلبها Maryland MVA من المتقدم عند التقديم للحصول على رخصة CDL؟","options":["رخصة قيادة سارية وصورة فوتوغرافية فقط","إثبات الهوية والعمر ورقم الضمان الاجتماعي والإقامة في ماريلاند","جواز سفر وخطاب من صاحب العمل فقط","إثبات الهوية وبطاقة تسجيل المركبة"],"explanation":"تتطلب Maryland MVA إثبات الهوية والعمر ورقم الضمان الاجتماعي والإقامة في ماريلاند (ويُثبَت الوجود القانوني من خلال مستندات الهوية هذه). المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها."},"33":{"q":"أين يجب إكمال تدريب السائقين المبتدئين (ELDT) لمتقدم يطلب لأول مرة رخصة CDL من الفئة A أو B في ماريلاند؟","options":["أي مدرسة قيادة خاصة يختارها المتقدم","مزوِّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA","فقط في مكتب فرع تابع لـ Maryland MVA","برنامج معتمد من إدارة التعليم في ولاية ماريلاند"],"explanation":"تتطلب ماريلاند إكمال تدريب السائقين المبتدئين (ELDT) للمتقدمين لأول مرة للفئة A/B (وللتظهيرات S وP وH لأول مرة) من خلال مزوِّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل اختبار المهارات أو اختبار معرفة المواد الخطرة. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها؛ 49 CFR Part 380."},"34":{"q":"لأي مما يلي تتطلب ماريلاند تدريب السائقين المبتدئين (ELDT) قبل الاختبار؟","options":["تجديد رخصة CDL قائمة من الفئة A","إضافة قيد ناقل الحركة الأوتوماتيكي","الحصول على رخصة CDL من الفئة A أو B لأول مرة، أو إضافة S أو P أو H لأول مرة","تحديث عنوان السكن على رخصة CDL"],"explanation":"تُلزِم ماريلاند بتدريب السائقين المبتدئين (ELDT) لرخص CDL من الفئة A أو B لأول مرة، ولأول مرة عند إضافة تظهيرات الحافلة المدرسية (S) أو الركاب (P) أو المواد الخطرة (H). وهو غير مطلوب لعمليات التجديد أو التغييرات الإدارية. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها؛ 49 CFR Part 380."},"35":{"q":"أي مما يلي إحدى فئات الإقرار الذاتي الطبي الأربع التي يجب على حامل رخصة CDL في ماريلاند الاختيار من بينها؟","options":["غير المستثنى بين الولايات (NI)","التجاري المقيَّد (RC)","المؤقت بين الولايات (PI)","المواد الخطرة المحدودة (LH)"],"explanation":"فئات الإقرار الذاتي الأربع في ماريلاند هي: غير المستثنى بين الولايات (NI)، والمستثنى بين الولايات (EI)، وغير المستثنى داخل الولاية (NA)، والمستثنى داخل الولاية (EA). المصدر: Maryland MVA، متطلبات الاعتماد الطبي لرخصة CDL."},"36":{"q":"حامل رخصة CDL في ماريلاند يقود عبر حدود الولايات ويجب عليه الامتثال لجميع متطلبات تأهيل السائق الفيدرالية، ينبغي أن يقرّ ذاتياً بأنه ضمن أي فئة؟","options":["المستثنى داخل الولاية (EA)","المستثنى بين الولايات (EI)","غير المستثنى بين الولايات (NI)","غير المستثنى داخل الولاية (NA)"],"explanation":"تنطبق فئة غير المستثنى بين الولايات (NI) على حامل رخصة CDL الذي يقود عبر حدود الولايات ويستوفي جميع متطلبات التأهيل الفيدرالية، بما في ذلك شهادة طبية سارية من DOT. المصدر: Maryland MVA، متطلبات الاعتماد الطبي لرخصة CDL."},"37":{"q":"في ماريلاند، قبل إمكان إجراء اختبار معرفة تظهير المواد الخطرة (H) وإصدار التظهير، ماذا يجب على المتقدم اجتيازه؟","options":["تقييم تهديد أمني من TSA مع فحص خلفية قائم على البصمات","فحص انبعاثات المركبات بالولاية","استعلام ما قبل التوظيف من مركز تبادل بيانات المخدرات والكحول فقط","تدقيق سجل القيادة من شرطة ولاية ماريلاند فقط"],"explanation":"تتطلب ماريلاند من المتقدمين للمواد الخطرة اجتياز تقييم تهديد أمني من TSA، يتضمن فحص سجل خلفية قائماً على البصمات (يُعالَج عبر DPSCS)، إضافةً إلى اجتياز اختبار معرفة المواد الخطرة. المصدر: Maryland MVA، تظهير المواد الخطرة لرخصة CDL؛ 49 CFR Part 1572."},"38":{"q":"بعد الحصول على موافقة TSA، خلال أي إطار زمني يجب على المتقدم في ماريلاند الحصول على تظهير المواد الخطرة؟","options":["خلال 30 يوماً","خلال 90 يوماً","خلال ستة أشهر","خلال سنتين"],"explanation":"تتطلب ماريلاند من المتقدم الحصول على تظهير المواد الخطرة خلال ستة أشهر من تاريخ خطاب موافقة TSA. المصدر: Maryland MVA، تظهير المواد الخطرة لرخصة CDL."},"39":{"q":"كم مرة يحتاج حامل رخصة CDL في ماريلاند الحامل لتظهير الحافلة المدرسية (S) عادةً إلى تجديد شهادة الفاحص الطبي للحفاظ على سريان ذلك التظهير؟","options":["كل 6 أشهر","سنوياً (كل عام)","كل سنتين","كل 5 سنوات"],"explanation":"في حين أن معظم شهادات الفاحص الطبي سارية حتى سنتين، يحتاج حاملو تظهير الحافلة المدرسية (S) في ماريلاند عموماً إلى اعتماد طبي سنوي للحفاظ على ذلك التصنيف. المصدر: Maryland MVA، متطلبات الاعتماد الطبي لرخصة CDL."},"40":{"q":"في ماريلاند، ما هو الحد الأقصى لتركيز الكحول في الدم/النفَس (BAC) الذي يجوز عنده قانونياً للشخص تشغيل مركبة تجارية آلية (CMV)؟","options":["0.04","0.08","0.02","0.10"],"explanation":"يُجرَّد سائق المركبة التجارية الآلية (CMV) في ماريلاند من الأهلية للقيادة بتركيز كحول في الدم (BAC) يبلغ 0.04 أو أكثر — أي نصف حد 0.08 المقرر للسائقين غير التجاريين. المصدر: المادة 16-812(a) والمادة 11-127.1 من قانون النقل في ماريلاند؛ دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"41":{"q":"بموجب قانون الموافقة الضمنية في ماريلاند، ماذا يحدث إذا طُلب من حامل رخصة CDL قانونياً إجراء اختبار كيميائي للكحول فرفض؟","options":["تُجرَّد رخصة CDL من الأهلية لمدة سنة واحدة على الأقل (يُعامَل الرفض الأول معاملة المخالفة الكبرى)","يُغرَّم السائق لكنه يحتفظ برخصة CDL","تُعلَّق رخصة CDL لمدة 60 يوماً","لا يحدث شيء حتى صدور إدانة"],"explanation":"تطبّق ماريلاند الموافقة الضمنية: رفض اختبار كيميائي مطلوب قانونياً يجرّد رخصة CDL من الأهلية لمدة سنة واحدة عن المخالفة الأولى، شأنه شأن المخالفات الكبرى الأخرى. المصدر: المادة 16-205.1 والمادة 16-812(b) من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"42":{"q":"ما هي مدة التجريد من أهلية CDL في ماريلاند عن مخالفة كبرى أولى (مثل القيادة تحت تأثير الكحول، أو تركيز كحول في الدم 0.04 أو أكثر في مركبة CMV، أو رفض الاختبار) عند عدم نقل مواد خطرة تحمل لافتات؟","options":["سنة واحدة","60 يوماً","3 سنوات","6 أشهر"],"explanation":"تجرّد المخالفة الكبرى الأولى رخصة CDL من الأهلية لمدة سنة واحدة (3 سنوات إذا وقعت أثناء نقل مواد خطرة تحمل لافتات). المصدر: المادة 16-812 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"43":{"q":"إذا ارتكب سائق رخصة CDL في ماريلاند مخالفة كبرى أولى (مثل القيادة تحت تأثير الكحول أو تركيز كحول في الدم 0.04 أو أكثر) أثناء نقل مواد خطرة تتطلب لافتات، فما هي مدة التجريد من الأهلية؟","options":["3 سنوات","سنة واحدة","5 سنوات","مدى الحياة"],"explanation":"تُزاد مدة التجريد المعيارية للمخالفة الأولى البالغة سنة واحدة إلى 3 سنوات عندما يكون السائق ينقل مواد خطرة تحمل لافتات في حينها. المصدر: المادة 16-812 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"44":{"q":"ما هو التجريد من أهلية CDL في ماريلاند عن مخالفة كبرى ثانية (قيادة ثانية تحت تأثير الكحول، أو تركيز كحول في الدم 0.04 أو أكثر، أو رفض، إلخ) ارتُكبت في حادثة منفصلة؟","options":["تجريد مدى الحياة","5 سنوات","3 سنوات","سنتان"],"explanation":"تؤدي المخالفة الكبرى الثانية إلى تجريد من أهلية CDL مدى الحياة، وإن أمكن إعادة الترخيص بعد 10 سنوات في الحالات المؤهَّلة. المصدر: المادة 16-812 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"45":{"q":"استخدام مركبة CMV لارتكاب جناية تتعلق بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها يؤدي إلى أي عقوبة على رخصة CDL في ماريلاند؟","options":["تجريد مدى الحياة دون إمكانية إعادة الترخيص بعد 10 سنوات","تجريد لمدة سنة واحدة","تجريد لمدة 3 سنوات","تجريد مدى الحياة، لكن مع الأهلية لإعادة الترخيص بعد 10 سنوات"],"explanation":"الجناية المتعلقة بتصنيع مادة خاضعة للرقابة أو توزيعها أو صرفها باستخدام مركبة CMV هي تجريد مدى الحياة غير مؤهَّل لإعادة الترخيص بعد 10 سنوات. المصدر: 49 CFR 383.51 الجدول 1؛ المادة 16-812 من قانون النقل في ماريلاند."},"46":{"q":"كم عدد المخالفات المرورية الجسيمة خلال فترة 3 سنوات التي تستوجب تجريداً من أهلية CDL لمدة 60 يوماً في ماريلاند؟","options":["مخالفتان جسيمتان","3 مخالفات جسيمة","4 مخالفات جسيمة","مخالفة جسيمة واحدة"],"explanation":"مخالفتان مروريتان جسيمتان خلال 3 سنوات (بأي مجموعة، في مركبة CMV) تؤديان إلى تجريد لمدة 60 يوماً. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"47":{"q":"ثلاث مخالفات مرورية جسيمة خلال فترة 3 سنوات تؤدي إلى أي مدة تجريد من أهلية CDL في ماريلاند؟","options":["120 يوماً","60 يوماً","180 يوماً","سنة واحدة"],"explanation":"ثلاث مخالفات مرورية جسيمة خلال 3 سنوات تجرّد رخصة CDL من الأهلية لمدة 120 يوماً؛ ويُضاف هذا إلى أي تجريد سابق مدته 60 يوماً. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"48":{"q":"كم ميلاً في الساعة فوق الحد المعلن يجب أن تبلغه مخالفة السرعة لتُحتسب 'مخالفة مرورية جسيمة' لأغراض CDL في ماريلاند؟","options":["15 ميلاً في الساعة أو أكثر فوق الحد","10 أميال في الساعة أو أكثر فوق الحد","20 ميلاً في الساعة أو أكثر فوق الحد","25 ميلاً في الساعة أو أكثر فوق الحد"],"explanation":"تجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر فوق حد السرعة المعلن هو مخالفة مرورية جسيمة تُحتسب ضمن تجريد مخالفتين خلال 3 سنوات (60 يوماً) وثلاث مخالفات خلال 3 سنوات (120 يوماً). المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"49":{"q":"أي مما يلي يُصنَّف 'مخالفة مرورية جسيمة' لحامل رخصة CDL في ماريلاند؟","options":["القيادة المتهورة","الوقوف في ممر الإطفاء","مصباح خلفي محترق","ملصق تسجيل منتهي الصلاحية"],"explanation":"تشمل المخالفات المرورية الجسيمة القيادة المتهورة، وتجاوز السرعة بمقدار 15 ميلاً في الساعة أو أكثر، وتغيير المسارات بشكل غير سليم/متقلب، والاقتراب الشديد من المركبة الأمامية، والمراسلة النصية، واستخدام الهاتف المحمول باليد. ولا تُعدّ مسائل المعدات/الوقوف الاعتيادية مخالفات جسيمة. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"50":{"q":"في ماريلاند، قيادة مركبة CMV أثناء المراسلة النصية بما يخالف القانون تُعامَل بوصفها أي نوع من المخالفات لأغراض التجريد من أهلية CDL؟","options":["مخالفة مرورية جسيمة","مخالفة كبرى","مخالفة أمر إيقاف عن الخدمة","مخالفة معبر سكة حديد"],"explanation":"المراسلة النصية أثناء قيادة مركبة CMV مخالفة مرورية جسيمة تُحتسب ضمن تجريد 60 يوماً (مخالفتان خلال 3 سنوات) و120 يوماً (ثلاث مخالفات خلال 3 سنوات). وتحظر ماريلاند المراسلة النصية بموجب قانون ذي إنفاذ أساسي. المصدر: المادة 21-1124.1 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"51":{"q":"بموجب قانون ماريلاند، السائق البالغ لمركبة CMV الذي يستخدم هاتفاً محمولاً باليد أثناء حركة المركبة يرتكب أي نوع من مخالفات CDL؟","options":["مخالفة مرورية جسيمة","مخالفة بسيطة غير واجبة الإبلاغ","مخالفة كبرى بتجريد لمدة سنة واحدة","مخالفة أمر إيقاف عن الخدمة"],"explanation":"استخدام هاتف محمول باليد أثناء قيادة مركبة CMV مخالفة مرورية جسيمة تُحتسب ضمن عتبات تجريد 60/120 يوماً. وحظر ماريلاند لاستخدام الهاتف المحمول باليد مخالفة ذات إنفاذ أساسي. المصدر: المادة 21-1124.2 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 2."},"52":{"q":"ما هو الحد الأدنى للتجريد من أهلية CDL في ماريلاند عن مخالفة معبر سكة حديد-طريق سريع أولى؟","options":["لا تقل عن 60 يوماً","لا تقل عن 30 يوماً","لا تقل عن 120 يوماً","لا تقل عن سنة واحدة"],"explanation":"تجرّد مخالفة معبر سكة حديد-طريق سريع أولى رخصة CDL من الأهلية لمدة لا تقل عن 60 يوماً. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 3."},"53":{"q":"مخالفة معبر سكة حديد-طريق سريع ثانية خلال فترة 3 سنوات تؤدي إلى أي حد أدنى للتجريد من أهلية CDL في ماريلاند؟","options":["لا تقل عن 120 يوماً","لا تقل عن 60 يوماً","لا تقل عن سنة واحدة","لا تقل عن 180 يوماً"],"explanation":"مخالفة معبر سكة حديد ثانية خلال 3 سنوات تجرّد رخصة CDL من الأهلية لمدة لا تقل عن 120 يوماً. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 3."},"54":{"q":"مخالفة معبر سكة حديد-طريق سريع ثالثة خلال فترة 3 سنوات تؤدي إلى أي حد أدنى للتجريد من أهلية CDL في ماريلاند؟","options":["لا تقل عن سنة واحدة","لا تقل عن 120 يوماً","لا تقل عن 180 يوماً","مدى الحياة"],"explanation":"مخالفة معبر سكة حديد ثالثة (أو لاحقة) خلال 3 سنوات تجرّد رخصة CDL من الأهلية لمدة لا تقل عن سنة واحدة. المصدر: دليل CDL في ماريلاند؛ 49 CFR 383.51 الجدول 3."},"55":{"q":"ما هو نطاق التجريد من أهلية CDL في ماريلاند عن إدانة أولى بمخالفة أمر الإيقاف عن الخدمة أثناء قيادة مركبة CMV لا تحمل مواد خطرة؟","options":["180 يوماً حتى سنة واحدة","60 إلى 120 يوماً","1 إلى 3 سنوات","30 إلى 90 يوماً"],"explanation":"تجرّد مخالفة أمر إيقاف عن الخدمة أولى (لا تتعلق بمواد خطرة، وأقل من 16 راكباً) رخصة CDL من الأهلية لمدة لا تقل عن 180 يوماً ولا تزيد على سنة واحدة. المصدر: المادة 16-813 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 4."},"56":{"q":"مخالفة أمر إيقاف عن الخدمة ثانية خلال أي فترة 10 سنوات (لا تتعلق بمواد خطرة) تؤدي إلى أي نطاق للتجريد من أهلية CDL في ماريلاند؟","options":["2 إلى 5 سنوات","180 يوماً إلى سنة واحدة","1 إلى 3 سنوات","مدى الحياة"],"explanation":"مخالفة أمر إيقاف عن الخدمة ثانية خلال 10 سنوات تجرّد رخصة CDL من الأهلية لمدة لا تقل عن سنتين ولا تزيد على 5 سنوات. المصدر: المادة 16-813 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 4."},"57":{"q":"مخالفة أمر إيقاف عن الخدمة أولى أثناء نقل مواد خطرة تحمل لافتات أو أثناء تشغيل مركبة مصممة لـ 16 راكباً أو أكثر تحمل أي نطاق للتجريد من أهلية CDL في ماريلاند؟","options":["180 يوماً حتى سنتين","180 يوماً حتى سنة واحدة","2 إلى 5 سنوات","3 إلى 5 سنوات"],"explanation":"مخالفة أمر إيقاف عن الخدمة أولى تتعلق بمواد خطرة تحمل لافتات أو بمركبة تسع 16 راكباً أو أكثر تجرّد رخصة CDL من الأهلية لمدة لا تقل عن 180 يوماً ولا تزيد على سنتين. المصدر: المادة 16-813 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 4."},"58":{"q":"متى يجوز لـ Maryland MVA بدء تجريد من أهلية CDL يتعلق بإيقاف تجاري لتركيز كحول مرتفع؟","options":["بناءً على مخالفة/إجراء إداري بحد ذاته لتركيز كحول مرتفع في مركبة CMV، حتى قبل الإدانة","فقط بعد إدانة جنائية في المحكمة","فقط بعد مخالفة ثانية","فقط إذا تسبب السائق في تصادم"],"explanation":"يجوز لماريلاند تجريد رخصة CDL من الأهلية بناءً على مخالفة أو أمر إداري بحد ذاته لتركيز كحول مرتفع أثناء قيادة مركبة تجارية، حتى قبل أي إدانة قضائية. المصدر: صفحة MDOT MVA لتجريد CDL وإعادة الترخيص؛ المادة 16-205.1 والمادة 16-812 من قانون النقل في ماريلاند."},"59":{"q":"بعد تجريد من أهلية CDL مدى الحياة، يجوز لسائق في ماريلاند عموماً التقدم لإعادة الترخيص بعد كم سنة، شريطة استيفاء متطلبات الأهلية؟","options":["10 سنوات","5 سنوات","3 سنوات","أبداً — التجريد مدى الحياة دائم في جميع الحالات"],"explanation":"يمكن تخفيض تجريد CDL مدى الحياة إلى حد أدنى قدره 10 سنوات إذا استوفى السائق متطلبات إعادة الترخيص — باستثناء مخالفات مثل الاتجار بالمخدرات أو الاتجار بالبشر بواسطة مركبة CMV، التي لا تتيح إعادة الترخيص. المصدر: المادة 16-812 من قانون النقل في ماريلاند؛ 49 CFR 383.51 الجدول 1."},"60":{"q":"بموجب قانون \"أفسح الطريق\" (Move Over) في ولاية ماريلاند، عندما يقترب سائق يحمل رخصة CDL من مركبة طوارئ متوقفة أو شاحنة قطر أو مركبة خدمة تعرض أضواء تحذيرية، ما هو الإجراء الأول الذي يفرضه القانون؟","options":["الانتقال إلى مسار غير ملاصق مباشرةً للمركبة المتوقفة، إذا كان ذلك آمناً وقانونياً","التوقف التام إلى أن يأذن له ضابط بالمتابعة","إطلاق بوق المركبة باستمرار أثناء تجاوز المركبة المتوقفة","تخفيض السرعة إلى 20 mph تماماً أقل من الحد المعلن والبقاء في المسار"],"explanation":"تتطلب المادة 21-405.1 من قانون النقل في ماريلاند (قانون \"أفسح الطريق\") من السائق تغيير المسار إلى مسار غير ملاصق مباشرةً للمركبة المتوقفة عندما يكون ذلك آمناً وقانونياً. وفقط إذا كان تغيير المسار غير آمن أو مستحيل، فيجب على السائق عندئذٍ التباطؤ إلى سرعة معقولة وحكيمة. المصدر: Md. Code, Transportation 21-405.1؛ إرشادات Maryland MVA/MSP."},"61":{"q":"إذا لم يتمكن سائق يحمل رخصة CDL في ماريلاند من تغيير المسار بأمان عند تجاوز مركبة طوارئ أو خدمة متوقفة بأضوائها مضاءة، فماذا يجب أن يفعل بدلاً من ذلك؟","options":["التباطؤ إلى سرعة معقولة وحكيمة تناسب الظروف القائمة","التوقف التام على الكتف إلى أن يتم إخلاء موقع الحادث","الحفاظ على الحد الأقصى المعلن للسرعة والتجاوز دون تغيير السرعة","الانعطاف إلى الجزيرة الوسطى والانتظار حتى يخلو المسار من حركة المرور"],"explanation":"بموجب المادة 21-405.1 من قانون النقل في ماريلاند، إذا كان الانتقال غير آمن أو غير ممكن، فيجب على السائق التباطؤ إلى سرعة معقولة وحكيمة تكون آمنة للظروف. لا يحدد قانون ماريلاند رقماً ثابتاً واحداً؛ بل يتطلب سرعة معقولة تناسب الظروف. المصدر: Md. Code, Transportation 21-405.1."},"62":{"q":"اعتباراً من توسيع جرى في 1 أكتوبر 2022، يسري قانون \"أفسح الطريق\" في ماريلاند على أيٍّ مما يلي عند توقفه على جانب الطريق؟","options":["أي مركبة تعرض أضواء الخطر أو مخاريط تحذيرية أو شعلات طريق، بما في ذلك سيارات الركاب العادية","فقط مركبات الشرطة والإطفاء المميزة التي تستخدم الأضواء الوامضة","فقط شاحنات القطر ومركبات صيانة الطرق السريعة","فقط المركبات التجارية التي تزيد عن 26,001 pounds"],"explanation":"اعتباراً من 1 أكتوبر 2022، وسّعت ماريلاند المادة 21-405.1 بحيث يسري واجب \"أفسح الطريق\" على أي مركبة متوقفة تعرض أضواء الخطر أو شعلات الطريق أو المخاريط التحذيرية، وليس فقط مركبات الطوارئ أو الخدمة. المصدر: Md. Code, Transportation 21-405.1 (تعديل 2022)؛ Maryland MVA."},"63":{"q":"عندما تتوقف حافلة مدرسية في ماريلاند بأضوائها الحمراء الوامضة وذراع التوقف ممدودة على طريق غير مقسّم من مسارين، ماذا يجب على سائق يحمل رخصة CDL يقترب من أيٍّ من الاتجاهين أن يفعل؟","options":["التوقف والبقاء متوقفاً إلى أن تتوقف الأضواء عن الوميض وتتحرك الحافلة أو تشير بالمتابعة","التباطؤ إلى 15 mph والتجاوز من اليسار بحذر","التوقف فقط إذا كان يسير في الاتجاه نفسه للحافلة","المتابعة إذا لم يكن هناك أطفال ظاهرون قرب الحافلة"],"explanation":"على طريق ثنائي الاتجاه غير مقسّم في ماريلاند، يجب على حركة المرور في كلا الاتجاهين التوقف للحافلة المدرسية ذات الأضواء الحمراء الوامضة وذراع التوقف الممدودة، والبقاء متوقفة إلى أن تنطفئ الإشارات. المصدر: Md. Code, Transportation 21-706؛ Maryland MVA/MSP."},"64":{"q":"بموجب استثناء الطريق السريع المقسّم في ماريلاند، متى لا يُطلب من السائقين المسافرين في الاتجاه المعاكس لحافلة مدرسية متوقفة أن يتوقفوا؟","options":["عندما تفصل بين اتجاهي السير جزيرة وسطى أو حاجز مادي مثل العشب أو التراب أو فاصل خرساني","عندما يكون للطريق أربعة مسارات أو أكثر، بغض النظر عن وجود أي جزيرة وسطى","عندما يفصل بين اتجاهي السير خط أصفر مزدوج في المنتصف","عندما تكون الحافلة على بُعد أكثر من 100 feet في المسارات المعاكسة"],"explanation":"تعفي ماريلاند حركة المرور المعاكسة من التوقف فقط عندما تفصل بين الطريقين جزيرة وسطى مادية أو حاجز أو شريط غير معبّد. الخطوط المرسومة لا تُنشئ طريقاً سريعاً مقسّماً، لذا فإن وجود خط أصفر مزدوج وحده لا يُفعّل الاستثناء. المصدر: Md. Code, Transportation 21-706؛ إرشادات Maryland MVA."},"65":{"q":"على طريق سريع مقسّم في ماريلاند بجزيرة وسطى مادية، مَن الذي يجب عليه التوقف رغم ذلك عندما تومض حافلة مدرسية على الجانب المعاكس بأضوائها الحمراء؟","options":["السائقون المسافرون في الاتجاه نفسه للحافلة، خلفها","يجب على جميع السائقين على كلا الطريقين التوقف","لا يُطلب من أي سائقين التوقف على أي طريق سريع مقسّم","فقط السائقون في المسار الملاصق مباشرةً للجزيرة الوسطى"],"explanation":"حتى على طريق سريع مقسّم، يجب على حركة المرور التي تتبع الحافلة في الاتجاه نفسه أن تتوقف. ويُعفى فقط السير المعاكس المفصول بالجزيرة الوسطى المادية. المصدر: Md. Code, Transportation 21-706."},"66":{"q":"ما هو الحد الأقصى المطلق للسرعة الذي يجوز وضعه على أي طريق سريع في ماريلاند، بما في ذلك الطرق السريعة بين الولايات والطرق السريعة السريعة؟","options":["70 mph","65 mph","75 mph","55 mph"],"explanation":"يحدّد قانون ماريلاند الحد الأقصى للسرعة بـ 70 mph، والذي يجوز وضعه فقط على بعض الطرق السريعة بين الولايات والطرق السريعة السريعة؛ ولا يجوز لأي طريق سريع في ماريلاند أن يعلن أكثر من 70 mph. المصدر: Md. Code, Transportation 21-801.1؛ MDOT SHA."},"67":{"q":"كيف تحدد ماريلاند الحد الأقصى للسرعة للشاحنات وغيرها من المركبات التجارية مقارنةً بسيارات الركاب على الطريق السريع نفسه؟","options":["تتبع الشاحنات الحد الأقصى المعلن نفسه كباقي المركبات؛ وليس لدى ماريلاند حد سرعة منفصل أدنى للشاحنات على مستوى الولاية","تُحدَّد سرعة الشاحنات بـ 55 mph على مستوى الولاية بغض النظر عن الحد المعلن","تُحدَّد سرعة الشاحنات بـ 10 mph أقل من الحد المعلن على جميع الطرق السريعة","تُحدَّد سرعة الشاحنات بـ 65 mph بينما يجوز للسيارات السير بسرعة 70 mph على كل طريق بين الولايات"],"explanation":"على عكس بعض الولايات، لا تحدد ماريلاند حد سرعة منفصلاً أدنى للشاحنات على مستوى الولاية. تلتزم المركبات التجارية بنفس الحدود المعلنة كباقي حركة المرور (حتى سقف الـ 70 mph). المصدر: Md. Code, Transportation 21-801.1؛ إرشادات حدود السرعة من MDOT SHA."},"68":{"q":"أي المركبات التجارية يجب أن تتوقف قبل عبور سكك الحديد عند مستوى السطح بموجب القواعد التي تطبقها ماريلاند على سائقي CDL؟","options":["الحافلات التي تقل ركاباً والمركبات التي تنقل مواد خطرة تحمل لافتات تحذيرية","جميع المركبات التجارية التي تزيد عن 10,000 pounds","فقط المركبات التي تجر مقطورات مزدوجة أو ثلاثية","فقط مركبات الصهاريج الفارغة التي سبق أن نقلت مواد قابلة للاشتعال"],"explanation":"تتبع ماريلاند القاعدة الفيدرالية (49 CFR 392.10) المعتمدة في دليل CDL الخاص بها: يجب على الحافلات التي تقل ركاباً والمركبات التي تنقل مواد خطرة تحمل لافتات أن تتوقف عند معابر السطح. ومعظم الشاحنات الأخرى غير ملزمة بالتوقف ما لم توجّه بذلك لافتات أو إشارات. المصدر: دليل Maryland CDL؛ 49 CFR 392.10."},"69":{"q":"عندما يُطلب من شاحنة مواد خطرة تحمل لافتات أو حافلة ركاب التوقف عند معبر سكة حديد في ماريلاند، ضمن أي مسافة من أقرب قضيب يجب أن تتوقف؟","options":["ليس أقرب من 15 feet وليس أبعد من 50 feet من أقرب قضيب","ليس أقرب من 5 feet وليس أبعد من 25 feet من أقرب قضيب","ليس أقرب من 25 feet وليس أبعد من 75 feet من أقرب قضيب","ليس أقرب من 10 feet وليس أبعد من 100 feet من أقرب قضيب"],"explanation":"يجب على المركبات التجارية الملزمة بالتوقف أن تتوقف ضمن 50 feet من أقرب قضيب، ولكن ليس أقرب من 15 feet منه، ثم تنظر وتستمع قبل المتابعة. المصدر: دليل Maryland CDL؛ 49 CFR 392.10."},"70":{"q":"بعد التوقف عند معبر سكة حديد، لا يجوز لسائق حافلة أو سائق شاحنة مواد خطرة تحمل لافتات في ماريلاند المتابعة إلا بعد فعل ماذا؟","options":["النظر والاستماع في كلا الاتجاهين بحثاً عن قطار قادم والتأكد من إمكانية تجاوز المعبر دون توقف","تبديل التروس مرة واحدة على الأقل أثناء عبور السكك للحفاظ على الزخم","الانتظار إلزامياً 30 ثانية بغض النظر عمّا إذا كان هناك قطار قادم","إطلاق البوق ثلاث مرات قبل دخول المعبر"],"explanation":"بعد التوقف ضمن المنطقة من 15 إلى 50 feet، يجب على السائق النظر والاستماع في كلا الاتجاهين بحثاً عن قطار، ويجب ألا يبدأ العبور ما لم يكن هناك متسع لتجاوز السكك بالكامل دون توقف. وينبغي على السائقين عدم تبديل التروس أثناء وجودهم على السكك. المصدر: دليل Maryland CDL؛ 49 CFR 392.10."},"71":{"q":"عندما يتعين على سائق يحمل رخصة CDL في ماريلاند إيقاف شاحنة على الجزء المخصص للسير أو على كتف الطريق السريع، خلال كم دقيقة يجب وضع أجهزة التحذير (المثلثات العاكسة)؟","options":["خلال 10 minutes من التوقف","خلال 5 minutes من التوقف","خلال 15 minutes من التوقف","خلال 30 minutes من التوقف"],"explanation":"يجب على سائق مركبة تجارية متوقفة وضع أجهزة التحذير خلال 10 minutes. هذا المعيار الفيدرالي يُدرَّس في دليل Maryland CDL ويسري في ماريلاند. المصدر: دليل Maryland CDL؛ 49 CFR 392.22."},"72":{"q":"على طريق ثنائي الاتجاه من مسارين، أين يجب على سائق يحمل رخصة CDL في ماريلاند وضع مثلثات التحذير الثلاثة المطلوبة لشاحنة متوقفة؟","options":["نحو 10 feet خلف المركبة على جانب حركة المرور، ونحو 100 feet خلفها، ونحو 100 feet أمام المركبة","المثلثات الثلاثة جميعها على بُعد 200 feet خلف المركبة في صف واحد","نحو 50 feet و150 feet و250 feet خلف المركبة فقط","واحد على غطاء المحرك واثنان على السقف لزيادة الوضوح إلى أقصى حد"],"explanation":"على طريق ثنائي الاتجاه، ضَع مثلثاً واحداً على بُعد نحو 10 feet خلف المركبة على جانب حركة المرور، وواحداً على بُعد نحو 100 feet إلى الخلف، وواحداً على بُعد نحو 100 feet إلى الأمام، بحيث يجري تحذير حركة المرور من كلا الاتجاهين. المصدر: دليل Maryland CDL؛ 49 CFR 392.22."},"73":{"q":"على طريق سريع أحادي الاتجاه أو مقسّم، كيف يجب على سائق يحمل رخصة CDL في ماريلاند أن يباعد بين مثلثات التحذير الثلاثة خلف شاحنة متوقفة؟","options":["على بُعد نحو 10 feet و100 feet و200 feet باتجاه حركة المرور القادمة","على بُعد نحو 10 feet و50 feet و100 feet باتجاه حركة المرور القادمة","على بُعد نحو 25 feet و75 feet و150 feet باتجاه حركة المرور القادمة","على بُعد نحو 50 feet و100 feet و500 feet باتجاه حركة المرور القادمة"],"explanation":"على طريق سريع أحادي الاتجاه أو مقسّم، تُوضع المثلثات الثلاثة باتجاه حركة المرور القادمة على بُعد نحو 10 و100 و200 feet من المركبة. المصدر: دليل Maryland CDL؛ 49 CFR 392.22."},"74":{"q":"يتطلب قانون الالتزام بجانب اليمين في ماريلاند من المركبة البطيئة استخدام المسار الأيمن. أي مركبة تسير بأي مقدار أقل من الحد الأقصى للسرعة يجب أن تلتزم باليمين (إلا للتجاوز أو الانعطاف يساراً)؟","options":["10 mph أو أكثر أقل من الحد الأقصى المطبق للسرعة","5 mph أو أكثر أقل من الحد الأقصى المطبق للسرعة","15 mph أو أكثر أقل من الحد الأقصى المطبق للسرعة","20 mph أو أكثر أقل من الحد الأقصى المطبق للسرعة"],"explanation":"تتطلب المادة 21-301 من قانون النقل في ماريلاند من أي مركبة تسير بسرعة 10 mph أو أكثر أقل من الحد الأقصى (أو أبطأ من حركة المرور المعتادة عندما تستلزم الظروف ذلك) أن تلتزم بالمسار الأيمن، إلا عند التجاوز أو الاستعداد للانعطاف يساراً. المصدر: Md. Code, Transportation 21-301."},"75":{"q":"على طريق في ماريلاند به مساران أو أكثر في الاتجاه نفسه، ما الذي يحكم أي مسار يجب أن تستخدمه الشاحنة أو الجرّار الشاحن أو المقطورة أو الحافلة؟","options":["توجيهات أي جهاز للتحكم في حركة المرور يتطلب قيادة المركبة في مسار معيّن","تفضيل السائق، لأن لافتات المسارات لا تنطبق على المركبات التجارية","قاعدة ثابتة تقضي بأن جميع الشاحنات يجب أن تستخدم المسار الأقصى يساراً فقط","أي مسار به أقل عدد من سيارات الركاب في ذلك الوقت"],"explanation":"يتطلب قانون ماريلاند (المادة 21-301 من قانون النقل وقواعد استخدام المسارات ذات الصلة) من الشاحنات والجرّارات الشاحنة والمقطورات والحافلات الالتزام بأجهزة التحكم في حركة المرور التي تخصص مسارات معينة لها. المصدر: Md. Code, Transportation 21-301؛ 21-309."},"76":{"q":"لماذا تُمنع الشاحنات التجارية عموماً من طريق بالتيمور-واشنطن السريع (Baltimore-Washington Parkway) (قسم National Park Service من MD 295)؟","options":["إنه طريق سريع فيدرالي يحظر المركبات التجارية؛ يجب على الشاحنات استخدام I-95 أو طرق شاحنات أخرى ما لم تحمل تصريحاً خاصاً","الرصيف ضيق جداً بحيث لا يتسع لأي مركبة أعرض من سيارة ركاب","إنه طريق برسوم لا يقبل أجهزة الإرسال التجارية","يسمح للشاحنات فقط بين منتصف الليل والساعة 5 صباحاً"],"explanation":"يحظر طريق بالتيمور-واشنطن السريع، الذي تديره National Park Service، المركبات التجارية؛ وتُوجَّه الشاحنات للخروج بلافتات ويجب أن تستخدم I-95 أو طرق شاحنات أخرى مخصصة. يُسمح عموماً بالمركبات الترفيهية والحافلات، لكن لا يُسمح بالشاحنات التجارية دون تصريح. المصدر: لوائح الطرق السريعة لـ National Park Service؛ إرشادات طرق الشاحنات في ماريلاند."},"77":{"q":"أي فئات من الشحنات محظورة من نفق فورت ماكهنري (Fort McHenry Tunnel) (I-95) ونفق ميناء بالتيمور (Baltimore Harbor Tunnel) (I-895) في ماريلاند؟","options":["المتفجرات والغازولين السائب والسوائل القابلة للاشتعال والبروبان المعبأ فوق الحدود المسموح بها، من بين مواد خطرة أخرى","حمولات الأغذية المبردة والحيوانات الحية","أي حمولة يزيد وزنها الإجمالي عن 40,000 pounds","جميع الحمولات المنقولة في مقطورات مزدوجة أو ثلاثية، بغض النظر عن محتوياتها"],"explanation":"تحظر MDTA المتفجرات والغازولين السائب/السوائل القابلة للاشتعال وبعض المواد المشعة والبروبان المعبأ فوق الحد المسموح به (أكثر من 10 lb لكل عبوة) من نفقي فورت ماكهنري وميناء بالتيمور. المصدر: قائمة المواد الخطرة المحظورة لـ MDTA؛ mdta.maryland.gov."},"78":{"q":"سائق يحمل رخصة CDL في ماريلاند ينقل مواد خطرة تحمل لافتات ومحظورة من أنفاق بالتيمور، أي طريق ينبغي أن يسلكه عبر منطقة بالتيمور؟","options":["القسم الغربي من I-695 (الطريق الدائري الخارجي) حول معابر الميناء","مباشرةً عبر نفق فورت ماكهنري على I-95 خلال ساعات خارج الذروة","نفق ميناء بالتيمور على I-895 مع تشغيل أضواء الخطر","أي شارع في المدينة عبر وسط بالتيمور يتجنب الرسوم"],"explanation":"يجب على حمولات المواد الخطرة الممنوعة من الأنفاق الالتفاف حول الميناء باستخدام الجزء الغربي من I-695. ويزداد أهمية هذا المسار أكثر منذ انهيار جسر Key Bridge (معبر I-695 الجنوبي الشرقي) في عام 2024. المصدر: إرشادات قيود/تصاريح الأنفاق لـ MDTA؛ mdta.maryland.gov."},"79":{"q":"على المنحدرات الجبلية الحادة لـ I-68 في غرب ماريلاند (قرب Sideling Hill وBig Savage Mountain)، ما ميزة السلامة المتوفرة للشاحنات التي تفقد القدرة على الكبح على منحدر طويل؟","options":["منحدرات هروب الشاحنات الجامحة (منحدرات الهروب) التي تستخدم منحدراً صاعداً ومادة كابحة لإيقاف المركبة","أنفاق إلزامية تجبر الشاحنات على التباطؤ قبل النزول","مسارات رسوم قابلة للعكس تُفتح فقط للشاحنات المعطلة","شرائط رصيف مُسخَّنة تزيد من احتكاك الإطارات على المنحدر"],"explanation":"يحتوي I-68 عبر غرب ماريلاند على منحدرات حادة وطويلة؛ وتتوفر منحدرات هروب الشاحنات الجامحة (منحدرات هروب كابحة من الحصى/الرمل على منحدر صاعد) لكي تتمكن الشاحنات التي تعطّلت أو ارتفعت حرارة مكابحها من التوقف بأمان. ينبغي على السائقين النزول بترس منخفض واستخدام تقنية الكبح الصحيحة. المصدر: MDOT SHA؛ قسم القيادة الجبلية في دليل Maryland CDL."},"80":{"q":"أي وكالة في ماريلاند تُصدر رخص القيادة التجارية (CDLs)؟","options":["إدارة مركبات السيارات (MVA) التابعة لـ MDOT","قسم المركبات التجارية في شرطة ولاية ماريلاند","الإدارة الفيدرالية لسلامة شركات النقل بالشاحنات (FMCSA)","وزارة العمل في ماريلاند"],"explanation":"تُصدر رخص CDL في ماريلاند من قِبل إدارة مركبات السيارات (MVA) التابعة لـ MDOT. وتضع FMCSA المعايير الفيدرالية لرخص CDL لكنها لا تُصدر الرخصة نفسها. المصدر: Maryland MVA، صفحات رخصة القيادة التجارية."},"81":{"q":"قبل تحديد موعد اختبار المهارات (اختبار الطريق) لرخصة CDL في ماريلاند، كم من الوقت يجب أن تكون قد حملت تصريح المتعلم التجاري (CLP)؟","options":["14 days على الأقل","7 days على الأقل","30 days على الأقل","60 days على الأقل"],"explanation":"تتبع ماريلاند القاعدة الفيدرالية: لا يكون حامل CLP مؤهلاً لإجراء اختبار مهارات CDL إلا بعد مرور 14 days على الأقل من إصدار CLP. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها."},"82":{"q":"ما التدريب الذي يجب إكماله قبل أن يتمكن مقدّم الطلب في ماريلاند من إجراء اختبار مهارات CDL لأول رخصة من الفئة A أو الفئة B؟","options":["تدريب السائقين المبتدئين (ELDT)","دورة قيادة دفاعية معتمدة من الولاية","ندوة المواد الخطرة من FMCSA","توجيه صفّي من MVA مدته 40 ساعة"],"explanation":"لن تسمح لك ماريلاند بإجراء اختبار المهارات حتى تُكمل تدريب السائقين المبتدئين (ELDT) المطلوب فيدرالياً، وهو مطلوب لأول رخصة CDL من الفئة A أو B ولأول مصادقات P أو S أو H. المصدر: Maryland MVA / قاعدة ELDT من FMCSA."},"83":{"q":"يتألف اختبار مهارات CDL في ماريلاند من ثلاثة أجزاء يجب اجتيازها. ما هي؟","options":["فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية بالمركبة، والقيادة على الطريق","اختبار المعرفة التحريري، وفحص النظر، والقيادة على الطريق","اختبار المكابح الهوائية، واختبار الرجوع للخلف، والقيادة الليلية","فحص ما قبل الرحلة، والتعامل مع المواد الخطرة، والقيادة على الطريق"],"explanation":"يتألف اختبار مهارات CDL في ماريلاند من فحص المركبة قبل الرحلة، ومهارات التحكم الأساسية بالمركبة، واختبار القيادة على الطريق، ويجب إكمال الأجزاء الثلاثة جميعها بنجاح. المصدر: Maryland MVA، اختبار مهارات CDL."},"84":{"q":"بموجب التصديق الذاتي لرخصة CDL في ماريلاند، كم عدد فئات عمليات القيادة التجارية التي يمكن لمقدّم الطلب أن يعلنها؟","options":["أربع","اثنتان","ثلاث","خمس"],"explanation":"يصدّق حاملو رخصة CDL في ماريلاند ذاتياً ضمن إحدى أربع فئات: بين الولايات غير مستثنى (NI)، بين الولايات مستثنى (EI)، داخل الولاية غير مستثنى (NA)، وداخل الولاية مستثنى (EA). المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"85":{"q":"سائق في ماريلاند يصدّق على نفسه ضمن فئة \"بين الولايات غير مستثنى (NI)\". ماذا يعني ذلك؟","options":["إنهم يقودون عبر حدود الولايات ويجب أن يستوفوا جميع متطلبات التأهيل الطبي الفيدرالية","إنهم يقودون داخل ماريلاند فقط ويُعفون من القواعد الطبية الفيدرالية","إنهم يقودون عبر حدود الولايات فقط لأنشطة مستثناة محددة","إنهم يقودون داخل ماريلاند فقط باستخدام إعفاء طبي معتمد من MVA"],"explanation":"تعني فئة \"بين الولايات غير مستثنى (NI)\" أن السائق يشغّل مركبة تجارية عبر حدود الولايات ويلتزم بجميع متطلبات التأهيل (بما في ذلك الطبية) الفيدرالية. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"86":{"q":"كيف تصل شهادة الفاحص الطبي من DOT لحامل رخصة CDL في ماريلاند إلى MVA عادةً؟","options":["يقدّمها الفاحص الطبي إلكترونياً إلى السجل الوطني لـ FMCSA وتتلقاها MVA تلقائياً","يجب على السائق إرسال الشهادة الورقية بالبريد إلى مقر MVA خلال 10 days","يرسل صاحب عمل السائق الشهادة بالفاكس إلى MVA نيابةً عن السائق","تُحمَّل الشهادة فقط عندما يجدّد السائق رخصة CDL شخصياً"],"explanation":"يرسل الفاحص الطبي المعتمد معلومات الشهادة إلكترونياً إلى السجل الوطني لـ FMCSA، وتتلقى MVA التصديق الطبي تلقائياً؛ ولا يحتاج السائق إلى إرساله بالبريد أو تقديمه. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"87":{"q":"ماذا يحدث لامتيازات القيادة التجارية لسائق في ماريلاند إذا انتهت صلاحية تصديقه الطبي من DOT؟","options":["تُخفَّض رخصة CDL الخاصة به ويصبح غير مؤهل لتشغيل مركبة تجارية","لا يتغير شيء لمدة 90 days طالما استمر بالقيادة داخل الولاية","تُعلَّق رخصة القيادة الكاملة، بما في ذلك الفئة الأساسية، فوراً","تُصدر MVA إعفاءً طبياً مؤقتاً تلقائياً"],"explanation":"إذا انتهت صلاحية التصديق الطبي، يصبح السائق غير مؤهل قانونياً لتشغيل مركبة تجارية وتُخفَّض امتيازات القيادة التجارية. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"88":{"q":"أي مجموعة من المستندات يجب أن يقدّمها مقدّم طلب رخصة CDL في ماريلاند إلى MVA؟","options":["إثبات الهوية والعمر ورقم الضمان الاجتماعي والإقامة في ماريلاند","فقط جواز سفر ساري المفعول وفاتورة خدمات","إثبات الهوية وخطاب موثّق من صاحب العمل فقط","شهادة ميلاد وإثبات تأمين على المركبة فقط"],"explanation":"يجب على مقدّمي طلبات رخصة CDL في ماريلاند تقديم إثبات الهوية والعمر ورقم الضمان الاجتماعي والإقامة في ماريلاند. المصدر: Maryland MVA، الحصول على رخصة CDL أو تجديدها."},"89":{"q":"التصديق الذاتي على نوع القيادة مطلوب في ماريلاند في جميع الحالات التالية باستثناء أيٍّ منها؟","options":["في كل مرة تجدّد فيها تسجيل مركبتك السنوي","عندما تحصل على رخصة CDL جديدة","عندما تجدّد رخصة CDL أو ترفع فئتها","عندما تنتقل بين القيادة بين الولايات والقيادة داخل الولاية"],"explanation":"التصديق الذاتي مطلوب عند الحصول على رخصة CDL أو تجديدها أو نقلها أو رفع فئتها، أو تغيير الحالة الطبية، أو الانتقال بين القيادة بين الولايات والقيادة داخل الولاية — وليس لتسجيل المركبة الروتيني. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"90":{"q":"أي فئة تصف حامل رخصة CDL في ماريلاند الذي يقود مركبة تجارية داخل ماريلاند فقط ويحمل إعفاءً طبياً معتمداً لرخصة CDL من MVA؟","options":["داخل الولاية غير مستثنى (NA)","بين الولايات غير مستثنى (NI)","بين الولايات مستثنى (EI)","داخل الولاية مستثنى (EA)"],"explanation":"تنطبق فئة \"داخل الولاية غير مستثنى (NA)\" على سائق مؤهل للتشغيل داخل ماريلاند فقط ويحمل إعفاءً طبياً معتمداً لرخصة CDL من MVA. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"91":{"q":"ما هو أول اختبار معرفة يجب أن يجتازه كل مقدّم طلب رخصة CDL في ماريلاند، بغض النظر عن المصادقات؟","options":["اختبار المعرفة العامة","اختبار المواد الخطرة","اختبار المكابح الهوائية","اختبار المركبات المركّبة"],"explanation":"يجب على جميع مقدّمي طلبات رخصة CDL في ماريلاند أولاً اجتياز اختبار المعرفة العامة لرخصة CDL؛ وتُؤخذ اختبارات المصادقات المحددة (P, S, N, H, T) إضافةً إلى ذلك حسب الحاجة. المصدر: Maryland MVA / دليل CDL (DL-151)."},"92":{"q":"أين يُجري مقدّم الطلب في ماريلاند اختبارات معرفة CDL (التحريرية)؟","options":["إلكترونياً في مكاتب MVA في جميع أنحاء ماريلاند","فقط عبر امتحان ورقي يُرسل بالبريد إلى مقر MVA","في أي مركز اختبار فيدرالي تابع لـ FMCSA","عبر الإنترنت من المنزل عبر أي موقع طرف ثالث معتمد"],"explanation":"تُجرى اختبارات معرفة CDL إلكترونياً في مكاتب MVA في جميع أنحاء ماريلاند. المصدر: Maryland MVA، اختبارات المعرفة / الاستعداد لاختبار رخصة القيادة."},"93":{"q":"ما هي دورة التجديد المعتادة (مدة الصلاحية) لرخصة قيادة قياسية في ماريلاند ولرخصة CDL؟","options":["8 years","4 years","5 years","10 years"],"explanation":"تُصدر/تُجدَّد رخص القيادة في ماريلاند، بما في ذلك رخص CDL، عادةً لمدة 8 years. المصدر: Maryland MVA، تجديد رخصة أو بطاقة هوية."},"94":{"q":"في اختبار مهارات CDL في ماريلاند، بأي ترتيب تُجرى المكونات الثلاثة عموماً؟","options":["فحص ما قبل الرحلة، ثم مهارات التحكم الأساسية، ثم القيادة على الطريق","القيادة على الطريق، ثم فحص ما قبل الرحلة، ثم مهارات التحكم الأساسية","مهارات التحكم الأساسية، ثم القيادة على الطريق، ثم فحص ما قبل الرحلة","القيادة على الطريق، ثم مهارات التحكم الأساسية، ثم فحص ما قبل الرحلة"],"explanation":"تُجري ماريلاند اختبار المهارات بالتسلسل: فحص المركبة قبل الرحلة أولاً، ثم مهارات التحكم الأساسية بالمركبة، ثم اختبار القيادة على الطريق. المصدر: Maryland MVA، اختبار مهارات CDL."},"95":{"q":"إذا ترك حامل رخصة CDL في ماريلاند تصديقه الطبي ينتهي ومرّت أكثر من سنة واحدة، فماذا يجب عليه فعله لاستعادة رخصة CDL؟","options":["إعادة إجراء جميع اختبارات معرفة ومهارات CDL","ببساطة تقديم شهادة طبية جديدة دون أي اختبار","دفع رسم إعادة تفعيل دون إجراء أي اختبارات","انتظار انقضاء تعليق إلزامي مدته 90 days فقط"],"explanation":"إذا خُفّضت رخصة CDL بسبب انتهاء صلاحية الشهادة الطبية ومرّت أكثر من سنة واحدة، فيجب على السائق إعادة إجراء جميع اختبارات معرفة ومهارات CDL لاستعادة الرخصة. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"96":{"q":"أي فئة تناسب حامل رخصة CDL في ماريلاند الذي يعبر حدود الولايات فقط لنقل أطفال المدارس أو المرضى أو المصابين أو الجثث؟","options":["بين الولايات مستثنى (EI)","بين الولايات غير مستثنى (NI)","داخل الولاية غير مستثنى (NA)","داخل الولاية مستثنى (EA)"],"explanation":"تشمل فئة \"بين الولايات مستثنى (EI)\" السائقين الذين يشغّلون مركباتهم عبر حدود الولايات فقط لأنشطة مستثناة محددة مثل نقل أطفال المدارس أو الطاقم أو المرضى أو المصابين أو الجثث. المصدر: Maryland MVA، متطلبات التصديق الطبي لرخصة CDL."},"97":{"q":"أي سيناريو لا يُفعّل بحد ذاته متطلب ELDT الفيدرالي قبل اختبار مهارات في ماريلاند؟","options":["تجديد رخصة CDL قائمة من الفئة A بالمصادقات نفسها","التقدم لأول رخصة CDL من الفئة A","الترقية من الفئة B إلى الفئة A لرخصة CDL","الحصول على أول مصادقة ركاب (P) أو حافلة مدرسية (S)"],"explanation":"ELDT مطلوب لأول رخصة CDL من الفئة A أو B، وللترقية من الفئة B إلى الفئة A، ولأول مصادقة P أو S أو H — لكن التجديد البسيط لرخصة CDL قائمة لا يُفعّل بحد ذاته ELDT. المصدر: Maryland MVA / قاعدة ELDT من FMCSA."},"98":{"q":"كيف يُحدَّد عادةً موعد اختبار مهارات CDL (اختبار الطريق) في ماريلاند؟","options":["بحجز موعد عبر حساب myMVA الخاص بمقدّم الطلب","بالدخول إلى أي فرع لـ MVA دون موعد","بالاتصال بخط الجدولة الوطني لـ FMCSA","تلقائياً في اليوم نفسه الذي تُصدر فيه CLP"],"explanation":"يحدد مقدّمو الطلبات موعد اختبار مهارات CDL بحجز موعد عبر حساب myMVA الخاص بهم؛ ويُجري الاختبار من قِبل MVA بعد استيفاء فترة حجز CLP و ELDT. المصدر: Maryland MVA، اختبار مهارات CDL."}}};
